-- Poems batch 460
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-13','杏溪十首：石潭','姚合','唐','御定全唐诗','yuding','','[]','曉向潭上行，夕就潭邊宿。清冷無波瀾，潎潎魚相逐。',36,'御定全唐詩/json/499.json','["曉向潭上行，夕就潭邊宿。清冷無波瀾，潎潎魚相逐。", "釣翁坐不起，見我往來熟。"]'),
('yuding-14','杏溪十首：溪路','姚合','唐','御定全唐诗','yuding','','[]','此路何瀟灑，永無公卿跡。日日多往來，藜杖與桑屐。',36,'御定全唐詩/json/499.json','["此路何瀟灑，永無公卿跡。日日多往來，藜杖與桑屐。", "路邊何所有，磊磊青淥石。"]'),
('yuding-15','杏溪十首：望江峰','姚合','唐','御定全唐诗','yuding','','[]','念昔有此峰，在彼江陵先。舉世未能知，愚亦望同賢。',36,'御定全唐詩/json/499.json','["念昔有此峰，在彼江陵先。舉世未能知，愚亦望同賢。", "我來心益悶，欲上天公箋。"]'),
('yuding-16','杏溪十首：杏水','姚合','唐','御定全唐诗','yuding','','[]','不與江水接，自出林中央。穿花複遠水，一山聞杏香。',36,'御定全唐詩/json/499.json','["不與江水接，自出林中央。穿花複遠水，一山聞杏香。", "我來持茗甌，日屢此來嘗。"]'),
('yuding-17','杏溪十首：渚上竹','姚合','唐','御定全唐诗','yuding','','[]','葉葉新春筠，下複清淺流。微風屢此來，決決複修修。',36,'御定全唐詩/json/499.json','["葉葉新春筠，下複清淺流。微風屢此來，決決複修修。", "詩人月下吟，月墮吟不休。"]'),
('yuding-18','杏溪十首：楓林堰','姚合','唐','御定全唐诗','yuding','','[]','森森楓樹林，護此石門堰。杏堤數裏餘，楓影覆亦遍。',36,'御定全唐詩/json/499.json','["森森楓樹林，護此石門堰。杏堤數裏餘，楓影覆亦遍。", "鸕鷀與釣童，質異同所願。"]'),
('yuding-19','杏溪十首：石瀨','姚合','唐','御定全唐诗','yuding','','[]','散漫複潺湲，半砂半和石。清風波亦無，歷歷魚可搦。',36,'御定全唐詩/json/499.json','["散漫複潺湲，半砂半和石。清風波亦無，歷歷魚可搦。", "我來亦屢久，歸路常日夕。"]'),
('yuding-20','陝下厲玄侍禦宅五題：濯纓溪','姚合','唐','御定全唐诗','yuding','','[]','舊山寧要去，此有濯纓泉。曉景松枝覆，秋光月色連。',48,'御定全唐詩/json/499.json','["舊山寧要去，此有濯纓泉。曉景松枝覆，秋光月色連。", "行尋屐齒盡，坐對角巾偏。寂寂幽棲處，無妨請俸錢。"]'),
('yuding-21','陝下厲玄侍禦宅五題：垂釣亭','姚合','唐','御定全唐诗','yuding','','[]','由釣起茅亭，柴扉複竹楹。波清見絲影，坐久識魚情。',48,'御定全唐詩/json/499.json','["由釣起茅亭，柴扉複竹楹。波清見絲影，坐久識魚情。", "白鳥依窗宿，青蒲傍砌生。欲同漁父舍，須自減逢迎。"]'),
('yuding-22','陝下厲玄侍禦宅五題：吟詩島','姚合','唐','御定全唐诗','yuding','','[]','幽島蘚層層，詩人日日登。坐危石是榻，吟冷唾成冰。',48,'御定全唐詩/json/499.json','["幽島蘚層層，詩人日日登。坐危石是榻，吟冷唾成冰。", "靜對唯秋水，同來但老僧。竹枝題字處，小篆複誰能。"]'),
('yuding-23','陝下厲玄侍禦宅五題：竹裏徑','姚合','唐','御定全唐诗','yuding','','[]','微徑嬋娟裏，唯聞靜者知。跡深苔長處，步狹筍生時。',48,'御定全唐詩/json/499.json','["微徑嬋娟裏，唯聞靜者知。跡深苔長處，步狹筍生時。", "高是連幽樹，窮應到曲池。紗巾靈壽杖，行樂複相宜。"]'),
('yuding-24','陝下厲玄侍禦宅五題：泛觴泉','姚合','唐','御定全唐诗','yuding','','[]','不上酒家樓，池邊日獻酬。杯來轉巴字，客坐繞方流。',48,'御定全唐詩/json/499.json','["不上酒家樓，池邊日獻酬。杯來轉巴字，客坐繞方流。", "酹滴苔紋斷，泉連石岸秋。若能山下置，歲晚願同遊。"]'),
('yuding-25','題僧院引泉','姚合','唐','御定全唐诗','yuding','','[]','泉眼高千尺，山僧取得歸。架空橫竹引，鑿石透渠飛。',48,'御定全唐詩/json/499.json','["泉眼高千尺，山僧取得歸。架空橫竹引，鑿石透渠飛。", "洗藥溪流濁，澆花雨力微。朝昏長繞看，護惜似持衣。"]'),
('yuding-26','題家園新池','姚合','唐','御定全唐诗','yuding','','[]','數日自穿池，引泉來近陂。尋渠通咽處，繞岸待清時。',48,'御定全唐詩/json/499.json','["數日自穿池，引泉來近陂。尋渠通咽處，繞岸待清時。", "深好求魚養，閑堪與鶴期。幽聲聽難盡，入夜睡常遲。"]'),
('yuding-27','詠盆池','姚合','唐','御定全唐诗','yuding','','[]','浮萍重疊水團圓，客繞千遭屐齒痕。',32,'御定全唐詩/json/499.json','["浮萍重疊水團圓，客繞千遭屐齒痕。", "莫驚池裏尋常滿，一井清泉是上源。"]'),
('yuding-28','買太湖石','姚合','唐','御定全唐诗','yuding','','[]','我嘗遊太湖，愛石青嵯峨。波瀾取不得，自後長咨嗟。',156,'御定全唐詩/json/499.json','["我嘗遊太湖，愛石青嵯峨。波瀾取不得，自後長咨嗟。", "奇哉賣石翁，不傍豪貴家。負石聽苦吟，雖貧亦來過。", "貴我辨識精，取價複不多。比之昔所見，珍怪頗更加。", "背面淙注痕，孔隙若琢磨。水稱至柔物，湖乃生壯波。", "或雲此天生，嵌空亦非他。氣質偶不合，如地生江河。", "置之書房前，曉霧常紛羅。碧光入四鄰，牆壁難蔽遮。", "客來謂我宅，忽若岩之阿。"]'),
('yuding-29','天竺寺殿前立石','姚合','唐','御定全唐诗','yuding','','[]','補天殘片女媧拋，撲落禪門壓地坳。霹靂劃深龍舊攫，',40,'御定全唐詩/json/499.json','["補天殘片女媧拋，撲落禪門壓地坳。霹靂劃深龍舊攫，", "秋至莫言長矻立，春來自有薜蘿交。"]'),
('yuding-30','杭州觀潮','姚合','唐','御定全唐诗','yuding','','[]','樓有章亭號，濤來自古今。勢連滄海闊，色比白雲深。',120,'御定全唐詩/json/499.json','["樓有章亭號，濤來自古今。勢連滄海闊，色比白雲深。", "怒雪驅寒氣，狂雷散大音。浪高風更起，波急石難沈。", "鳥懼多遙過，龍驚不敢吟。坳如開玉穴，危似走瓊岑。", "但褫千人魄，那知伍相心。岸摧連古道，洲漲踣叢林。", "跳沫山皆濕，當江日半陰。天然與禹鑿，此理遣誰尋。"]'),
('yuding-31','題李頻新居','姚合','唐','御定全唐诗','yuding','','[]','賃居求賤處，深僻任人嫌。蓋地花如繡，當門竹勝簾。',48,'御定全唐詩/json/499.json','["賃居求賤處，深僻任人嫌。蓋地花如繡，當門竹勝簾。", "勸僧嘗藥酒，教僕辨書簽。庭際山宜小，休令著石添。"]'),
('yuding-32','寄題縱上人院','姚合','唐','御定全唐诗','yuding','','[]','營營是與非，前樂後還悲。今世已如此，他生願似師。',48,'御定全唐詩/json/499.json','["營營是與非，前樂後還悲。今世已如此，他生願似師。", "禪房空旦暮，畫壁半陳隋。繞徑蒼苔跡，幽人來是誰。"]'),
('yuding-33','題山寺','姚合','唐','御定全唐诗','yuding','','[]','千重山崦裏，樓閣影參差。未暇尋僧院，先看置寺碑。',72,'御定全唐詩/json/499.json','["千重山崦裏，樓閣影參差。未暇尋僧院，先看置寺碑。", "竹深行漸暗，石穩坐多時。古塔蟲蛇善，陰廊鳥雀癡。", "雲開上界近，泉落下方遲。為愛青桐葉，因題滿樹詩。"]'),
('yuding-34','題貞女祠','姚合','唐','御定全唐诗','yuding','','[]','此女骨為土，貞名不可移。精靈閟何處，蘋藻奠空祠。',48,'御定全唐詩/json/499.json','["此女骨為土，貞名不可移。精靈閟何處，蘋藻奠空祠。", "水石生異狀，杉松無病枝。我來方謝雨，延滯失歸期。"]'),
('yuding-35','題刑部馬員外修行裏南街新居','姚合','唐','御定全唐诗','yuding','','[]','帝裏誰無宅，青山只屬君。閑窗連竹色，幽砌上苔文。',48,'御定全唐詩/json/499.json','["帝裏誰無宅，青山只屬君。閑窗連竹色，幽砌上苔文。", "遠近高低樹，東西南北雲。朝朝常獨見，免被四鄰分。"]'),
('yuding-36','題郭侍郎親仁裏幽居','姚合','唐','御定全唐诗','yuding','','[]','入門塵外思，苔徑藥苗間。洞裏應生玉，庭前自有山。',48,'御定全唐詩/json/499.json','["入門塵外思，苔徑藥苗間。洞裏應生玉，庭前自有山。", "帝城唯此靜，朝客更誰閑。野鶴松中語，時時去複還。"]'),
('yuding-37','題宣義池亭','姚合','唐','御定全唐诗','yuding','','[]','春入池亭好，風光暖更鮮。尋芳行不困，逐勝坐還遷。',96,'御定全唐詩/json/499.json','["春入池亭好，風光暖更鮮。尋芳行不困，逐勝坐還遷。", "細草亂如發，幽禽鳴似弦。苔文翻古篆，石色學秋天。", "花落能漂酒，萍開解避船。暫來還愈疾，久住合成仙。", "迸筍支階起，垂藤壓樹偏。此生應借看，自計買無錢。"]'),
('yuding-38','題薛十二池亭','姚合','唐','御定全唐诗','yuding','','[]','每日樹邊消一日，繞池行過又須行。異花多是非時有，',40,'御定全唐詩/json/499.json','["每日樹邊消一日，繞池行過又須行。異花多是非時有，", "浮萍著岸風吹歇，水面無塵晚更清。"]'),
('yuding-39','題大理崔少卿駙馬林亭','姚合','唐','御定全唐诗','yuding','','[]','每來歸意懶，都尉似山人。台榭棲雙鷺，松篁隔四鄰。',48,'御定全唐詩/json/499.json','["每來歸意懶，都尉似山人。台榭棲雙鷺，松篁隔四鄰。", "迸泉清勝雨，深洞暖如春。更看題詩處，前軒粉壁新。"]'),
('yuding-40','題杭州南亭','姚合','唐','御定全唐诗','yuding','','[]','舊隱即雲林，思歸日日深。如今來此地，無複有前心。',48,'御定全唐詩/json/499.json','["舊隱即雲林，思歸日日深。如今來此地，無複有前心。", "古石生靈草，長松棲異禽。暮潮簷下過，濺浪濕衣襟。"]'),
('yuding-41','題鄭駙馬林亭','姚合','唐','御定全唐诗','yuding','','[]','東園連宅起，勝事與心期。幽洞自生藥，新篁迸入池。',72,'御定全唐詩/json/499.json','["東園連宅起，勝事與心期。幽洞自生藥，新篁迸入池。", "密林行不盡，芳草坐難移。石翠疑無質，鶯歌似有詞。", "莎台高出樹，蘚壁淨題詩。我獨多來賞，九衢人不知。"]'),
('yuding-42','題厲玄侍禦所居','姚合','唐','御定全唐诗','yuding','','[]','幽棲一畝宮，清峭似山峰。鄰里不通徑，俸錢唯買松。',48,'御定全唐詩/json/499.json','["幽棲一畝宮，清峭似山峰。鄰里不通徑，俸錢唯買松。", "野人時寄宿，穀鳥自相逢。朝路床前是，誰知曉起慵。"]'),
('yuding-43','題田將軍宅','姚合','唐','御定全唐诗','yuding','','[]','焚香書院最風流，莎草緣牆綠蘚秋。近砌別穿澆藥井，',40,'御定全唐詩/json/499.json','["焚香書院最風流，莎草緣牆綠蘚秋。近砌別穿澆藥井，", "好是暗移城裏宅，清涼渾得似江頭。"]'),
('yuding-44','題崔駙馬宅','姚合','唐','御定全唐诗','yuding','','[]','心在林泉身在城，鳳凰樓下得閒名。洞中見鑿尋仙路，',40,'御定全唐詩/json/499.json','["心在林泉身在城，鳳凰樓下得閒名。洞中見鑿尋仙路，", "詩人多說離君宅，不得青苔地上行。"]'),
('yuding-45','題河上亭','姚合','唐','御定全唐诗','yuding','','[]','亭亭河上亭，魚躑水禽鳴。九曲何時盡，千峰今日清。',72,'御定全唐詩/json/499.json','["亭亭河上亭，魚躑水禽鳴。九曲何時盡，千峰今日清。", "晨光秋更遠，暑氣夏常輕。杯裏移檣影，琴中有浪聲。", "岸莎連砌靜，漁火入窗明。來此多沈醉，神高無宿酲。"]'),
('yuding-46','題長安薛員外水閣','姚合','唐','御定全唐诗','yuding','','[]','亭亭新閣成，風景益鮮明。石盡太湖色，水多湘渚聲。',72,'御定全唐詩/json/499.json','["亭亭新閣成，風景益鮮明。石盡太湖色，水多湘渚聲。", "翠筠和粉長，零露逐荷傾。時倚高窗望，幽尋小徑行。", "林疏看鳥語，池近識魚情。政暇招閑客，唯將酒送迎。"]'),
('yuding-47','題梁國公主池亭','姚合','唐','御定全唐诗','yuding','','[]','平陽池館枕秦川，門鎖南山一帶煙。素奈花開西子面，',40,'御定全唐詩/json/499.json','["平陽池館枕秦川，門鎖南山一帶煙。素奈花開西子面，", "寂寞空餘歌舞地，玉簫驚起鳳歸天。"]'),
('yuding-48','寄題尉遲少卿郊居','姚合','唐','御定全唐诗','yuding','','[]','卿仕在關東，林居思不窮。朝衣掛壁上，廄馬放田中。',96,'御定全唐詩/json/499.json','["卿仕在關東，林居思不窮。朝衣掛壁上，廄馬放田中。", "隅坐唯禪子，隨行只藥童。砌莎留宿露，庭竹出清風。", "濃翠生苔點，辛香發桂叢。蓮池伊水入，石徑遠山通。", "愚者心還靜，高人跡自同。無能相近住，終日羨鄰翁。"]'),
('yuding-49','題永城驛','姚合','唐','御定全唐诗','yuding','','[]','秋賦春還計盡違，自知身是拙求知。惟思曠海無休日，',40,'御定全唐詩/json/499.json','["秋賦春還計盡違，自知身是拙求知。惟思曠海無休日，", "從來此恨皆前達，敢負吾君作楚詞。"]'),
('yuding-0','過張邯鄲莊','姚合','唐','御定全唐诗','yuding','','[]','客行長似病，煩熱束四肢。到君讀書堂，忽若逢良醫。',120,'御定全唐詩/json/500.json','["客行長似病，煩熱束四肢。到君讀書堂，忽若逢良醫。", "堂前水交流，堂下樹交枝。兩門延風涼，洗我昏濁肌。", "與子還往熟，坐臥恣所宜。時時相獻酬，文字當酒卮。", "野飯具藜藿，永日亦不饑。苟餐非其所，鱠炙為蒺藜。", "時清士人閑，耕作唯文詞。豈獨鄉里薦，當取四海知。"]'),
('yuding-1','過楊處士幽居','姚合','唐','御定全唐诗','yuding','','[]','引水穿風竹，幽聲勝遠溪。裁衣延野客，翦翅養山雞。',48,'御定全唐詩/json/500.json','["引水穿風竹，幽聲勝遠溪。裁衣延野客，翦翅養山雞。", "酒熟聽琴酌，詩成削樹題。惟愁春氣暖，松下雪和泥。"]'),
('yuding-2','過李處士山居','姚合','唐','御定全唐诗','yuding','','[]','閒居晝掩扉，門柳蔭蔬畦。因病方收藥，尋僧始度溪。',48,'御定全唐詩/json/500.json','["閒居晝掩扉，門柳蔭蔬畦。因病方收藥，尋僧始度溪。", "少逢人到戶，時有燕銜泥。蕭灑身無事，名高孰與齊。"]'),
('yuding-3','過無可僧院','姚合','唐','御定全唐诗','yuding','','[]','憶師眠複起，永夜思迢迢。月下門方掩，林中寺更遙。',48,'御定全唐詩/json/500.json','["憶師眠複起，永夜思迢迢。月下門方掩，林中寺更遙。", "鐘聲空下界，池色在清宵。終擬修禪觀，窗間卷欲燒。"]'),
('yuding-4','過稠上人院','姚合','唐','御定全唐诗','yuding','','[]','清羸一飯師，閑院亦披衣。應詔常翻譯，修心出是非。',48,'御定全唐詩/json/500.json','["清羸一飯師，閑院亦披衣。應詔常翻譯，修心出是非。", "雪中疏磬度，林際晚風歸。蔬食常來此，人間護淨稀。"]'),
('yuding-5','過不疑上人院','姚合','唐','御定全唐诗','yuding','','[]','九經通大義，內典自應精。簾冷連松影，苔深減履聲。',48,'御定全唐詩/json/500.json','["九經通大義，內典自應精。簾冷連松影，苔深減履聲。", "相逢幸此日，相失恐來生。覺路何門去，師須引我行。"]'),
('yuding-6','過曇花寶上人院','姚合','唐','御定全唐诗','yuding','','[]','九陌最幽寺，吾師院複深。煙霜同覆屋，松竹雜成林。',48,'御定全唐詩/json/500.json','["九陌最幽寺，吾師院複深。煙霜同覆屋，松竹雜成林。", "鳥語境彌寂，客來機自沈。早知能到此，應不戴朝簪。"]'),
('yuding-7','過杜氏江亭','姚合','唐','御定全唐诗','yuding','','[]','上國千餘裏，逢春且勝遊。暫聞新鳥戲，似解旅人愁。',48,'御定全唐詩/json/500.json','["上國千餘裏，逢春且勝遊。暫聞新鳥戲，似解旅人愁。", "野色吞山盡，江煙襯水流。村醪須一醉，無恨滯行舟。"]'),
('yuding-8','過張雲峰院宿','姚合','唐','御定全唐诗','yuding','','[]','不吃胡麻飯，杯中自得仙。隔籬招好客，掃室置芳筵。',72,'御定全唐詩/json/500.json','["不吃胡麻飯，杯中自得仙。隔籬招好客，掃室置芳筵。", "家醞香醪嫩，時新異果鮮。夜深唯畏曉，坐穩豈思眠。", "棋罷嫌無敵，詩成貴在前。明朝題壁上，誰得眾人傳。"]'),
('yuding-9','過欽上人院','姚合','唐','御定全唐诗','yuding','','[]','有相無相身，唯師說始真。修篁半庭影，清磬幾僧鄰。',48,'御定全唐詩/json/500.json','["有相無相身，唯師說始真。修篁半庭影，清磬幾僧鄰。", "古壁丹青落，虛簷鳥雀馴。伊餘求了義，羸馬往來頻。"]'),
('yuding-10','過無可上人院','姚合','唐','御定全唐诗','yuding','','[]','寥寥聽不盡，孤磬與疏鐘。煩惱師長別，清涼我暫逢。',48,'御定全唐詩/json/500.json','["寥寥聽不盡，孤磬與疏鐘。煩惱師長別，清涼我暫逢。", "蟻行經古蘚，鶴毳落深松。自想歸時路，塵埃複幾重。"]'),
('yuding-11','過城南僧院','姚合','唐','御定全唐诗','yuding','','[]','寺對遠山起，幽居仍是師。斜陽通暗隙，殘雪落疏籬。',48,'御定全唐詩/json/500.json','["寺對遠山起，幽居仍是師。斜陽通暗隙，殘雪落疏籬。", "松靜鶴棲定，廊虛鐘盡遲。朝朝趨府吏，來此是相宜。"]'),
('yuding-12','過靈泉寺','姚合','唐','御定全唐诗','yuding','','[]','偶尋靈跡去，幽徑入氳氛。轉壑驚飛鳥，穿山踏亂雲。',48,'御定全唐詩/json/500.json','["偶尋靈跡去，幽徑入氳氛。轉壑驚飛鳥，穿山踏亂雲。", "水從岩下落，溪向寺前分。釋子遊何處，空堂日漸曛。"]'),
('yuding-13','過天津橋晴望','姚合','唐','御定全唐诗','yuding','','[]','閑立津橋上，寒光動遠林。皇宮對嵩頂，清洛貫城心。',48,'御定全唐詩/json/500.json','["閑立津橋上，寒光動遠林。皇宮對嵩頂，清洛貫城心。", "雪路初晴出，人家向晚深。自從王在鎬，天寶至如今。"]'),
('yuding-14','春日遊慈恩寺','姚合','唐','御定全唐诗','yuding','','[]','年長歸何處，青山未有家。賞春無酒飲，多看寺中花。',24,'御定全唐詩/json/500.json','["年長歸何處，青山未有家。賞春無酒飲，多看寺中花。"]'),
('yuding-15','游天臺上方','姚合','唐','御定全唐诗','yuding','','[]','曉上上方高處立，路人羨我此時身。',32,'御定全唐詩/json/500.json','["曉上上方高處立，路人羨我此時身。", "白雲向我頭上過，我更羨他雲路人。"]'),
('yuding-16','游終南山','姚合','唐','御定全唐诗','yuding','','[]','策杖度溪橋，雲深步數勞。青猿吟嶺際，白鶴坐松梢。',48,'御定全唐詩/json/500.json','["策杖度溪橋，雲深步數勞。青猿吟嶺際，白鶴坐松梢。", "天外浮煙遠，山根野水交。自緣名利系，好此結蓬茆。"]'),
('yuding-17','游杏溪蘭若','姚合','唐','御定全唐诗','yuding','','[]','踏得度溪灣，晨遊暮不還。月明松影路，春滿杏花山。',48,'御定全唐詩/json/500.json','["踏得度溪灣，晨遊暮不還。月明松影路，春滿杏花山。", "戲狖跳林末，高僧住石間。未肯離腰組，來此複何顏。"]'),
('yuding-18','游謝公亭','姚合','唐','御定全唐诗','yuding','','[]','行行方避夢，又到謝亭來。舉世皆如此，伊餘何處回。',48,'御定全唐詩/json/500.json','["行行方避夢，又到謝亭來。舉世皆如此，伊餘何處回。", "竹鮮多透石，泉潔亦無苔。坐與僧同語，誰能顧酒杯。"]'),
('yuding-19','游陽河岸','姚合','唐','御定全唐诗','yuding','','[]','終日遊山困，今朝始傍河。尋芳愁路盡，逢景畏人多。',48,'御定全唐詩/json/500.json','["終日遊山困，今朝始傍河。尋芳愁路盡，逢景畏人多。", "鳥語催沽酒，魚來似聽歌。醉時眠石上，肢體自婆娑。"]'),
('yuding-20','遊河橋曉望','姚合','唐','御定全唐诗','yuding','','[]','閑上津橋立，天涯一望間。秋風波上岸，旭日氣連山。',48,'御定全唐詩/json/500.json','["閑上津橋立，天涯一望間。秋風波上岸，旭日氣連山。", "偶聖今方變，朝宗豈複還。昆侖在蕃界，作將亦何顏。"]'),
('yuding-21','秋夜月中登天壇','姚合','唐','御定全唐诗','yuding','','[]','秋蟾流異彩，齋潔上壇行。天近星辰大，山深世界清。',48,'御定全唐詩/json/500.json','["秋蟾流異彩，齋潔上壇行。天近星辰大，山深世界清。", "仙飆石上起，海日夜中明。何計長來此，閑眠過一生。"]'),
('yuding-22','游昊天玄都觀','姚合','唐','御定全唐诗','yuding','','[]','性同相見易，紫府共閑行。陰徑紅桃落，秋壇白石生。',72,'御定全唐詩/json/500.json','["性同相見易，紫府共閑行。陰徑紅桃落，秋壇白石生。", "蘚文連竹色，鶴語應松聲。風定藥香細，樹聲泉氣清。", "垂簷靈草影，繞壁古山名。圍外坊無禁，歸時踏月明。"]'),
('yuding-23','同裴起居厲侍禦放朝游曲江','姚合','唐','御定全唐诗','yuding','','[]','暑月放朝頻，青槐路絕塵。雨晴江色出，風動草香新。',48,'御定全唐詩/json/500.json','["暑月放朝頻，青槐路絕塵。雨晴江色出，風動草香新。", "獨立分幽島，同行得靜人。此歡宜稍滯，此去與誰親。"]'),
('yuding-24','曉望華清宮','姚合','唐','御定全唐诗','yuding','','[]','曉看樓殿更鮮明，遙隔朱欄見鹿行。',32,'御定全唐詩/json/500.json','["曉看樓殿更鮮明，遙隔朱欄見鹿行。", "武帝自知身不死，教修玉殿號長生。"]'),
('yuding-25','夏日登樓晚望','姚合','唐','御定全唐诗','yuding','','[]','避暑高樓上，平蕪望不窮。鳥窮山色去，人歇樹陰中。',48,'御定全唐詩/json/500.json','["避暑高樓上，平蕪望不窮。鳥窮山色去，人歇樹陰中。", "數帶長河水，千條弱柳風。暗思多少事，懶話與芝翁。"]'),
('yuding-26','霽後登樓','姚合','唐','御定全唐诗','yuding','','[]','高樓初霽後，遠望思無窮。雨洗青山淨，春蒸大野融。',48,'御定全唐詩/json/500.json','["高樓初霽後，遠望思無窮。雨洗青山淨，春蒸大野融。", "碧池舒暖景，弱柳嚲和風。為有登臨興，獨吟落照中。"]'),
('yuding-27','早夏郡樓宴集','姚合','唐','御定全唐诗','yuding','','[]','官散有閒情，登樓步稍輕。窗雲帶雨氣，林鳥雜人聲。',48,'御定全唐詩/json/500.json','["官散有閒情，登樓步稍輕。窗雲帶雨氣，林鳥雜人聲。", "曉日襟前度，微風酒上生。城中會難得，掃壁各書名。"]'),
('yuding-28','夜宴太僕田卿宅','姚合','唐','御定全唐诗','yuding','','[]','故人九寺長，邀我此同歡。永夜開筵靜，中年飲酒難。',48,'御定全唐詩/json/500.json','["故人九寺長，邀我此同歡。永夜開筵靜，中年飲酒難。", "微風侵燭影，疊漏過林端。臘後分朝日，天明幾刻殘。"]'),
('yuding-29','春日同會衛尉崔少卿宅','姚合','唐','御定全唐诗','yuding','','[]','詩家會詩客，池閣曉初晴。鳥盡山中語，琴多譜外聲。',48,'御定全唐詩/json/500.json','["詩家會詩客，池閣曉初晴。鳥盡山中語，琴多譜外聲。", "映花相勸酒，入洞各題名。疏野常如此，誰人信在城。"]'),
('yuding-30','軍城夜會','姚合','唐','御定全唐诗','yuding','','[]','軍城夜禁樂，飲酒每題詩。坐穩吟難盡，寒多醉較遲。',48,'御定全唐詩/json/500.json','["軍城夜禁樂，飲酒每題詩。坐穩吟難盡，寒多醉較遲。", "遠鐘驚漏壓，微月被燈欺。此會誠堪惜，天明是別離。"]'),
('yuding-31','晦日宴劉值錄事宅','姚合','唐','御定全唐诗','yuding','','[]','花落鶯飛深院靜，滿堂賓客盡詩人。',32,'御定全唐詩/json/500.json','["花落鶯飛深院靜，滿堂賓客盡詩人。", "城中杯酒家家有，唯是君家酒送春。"]'),
('yuding-32','宴光祿田卿宅','姚合','唐','御定全唐诗','yuding','','[]','竹裏開華館，珍羞次第嘗。春風酒影動，晴日樂聲長。',48,'御定全唐詩/json/500.json','["竹裏開華館，珍羞次第嘗。春風酒影動，晴日樂聲長。", "久坐難辭醉，衰年亦暫狂。殷勤還繼燭，永夕夢相妨。"]'),
('yuding-33','會將作崔監東園','姚合','唐','御定全唐诗','yuding','','[]','牆北走紅塵，牆東接白雲。山光衣上見，藥氣酒中聞。',48,'御定全唐詩/json/500.json','["牆北走紅塵，牆東接白雲。山光衣上見，藥氣酒中聞。", "此會誠堪惜，窮秋日又曛。人間唯有醉，醉後複何雲。"]'),
('yuding-34','同諸公會太府韓卿宅','姚合','唐','御定全唐诗','yuding','','[]','九寺名卿才思雄，邀歡筆下與杯中。六街鼓絕塵埃息，',40,'御定全唐詩/json/500.json','["九寺名卿才思雄，邀歡筆下與杯中。六街鼓絕塵埃息，", "即聽雞唱天門曉，吏事相牽西複東。"]'),
('yuding-35','乞酒','姚合','唐','御定全唐诗','yuding','','[]','聞君有美酒，與我正相宜。溢甕清如水，黏杯半似脂。',48,'御定全唐詩/json/500.json','["聞君有美酒，與我正相宜。溢甕清如水，黏杯半似脂。", "豈唯消舊病，且要引新詩。況此便便腹，無非是滿卮。"]'),
('yuding-36','寄衛拾遺乞酒','姚合','唐','御定全唐诗','yuding','','[]','老人罷卮酒，不醉已經年。自飲君家酒，一杯三日眠。',48,'御定全唐詩/json/500.json','["老人罷卮酒，不醉已經年。自飲君家酒，一杯三日眠。", "味輕花上露，色似洞中泉。莫厭時時寄，須知法未傳。"]'),
('yuding-37','乞新茶','姚合','唐','御定全唐诗','yuding','','[]','嫩綠微黃碧澗春，采時聞道斷葷辛。',32,'御定全唐詩/json/500.json','["嫩綠微黃碧澗春，采時聞道斷葷辛。", "不將錢買將詩乞，借問山翁有幾人。"]'),
('yuding-38','西掖寓直春曉聞殘漏','姚合','唐','御定全唐诗','yuding','','[]','直廬仙掖近，春氣曙猶寒。隱隱銀河在，丁丁玉漏殘。',72,'御定全唐詩/json/500.json','["直廬仙掖近，春氣曙猶寒。隱隱銀河在，丁丁玉漏殘。", "微風飄更切，萬籟雜應難。鳳閣明初啟，雞人唱漸闌。", "靜宜來禁裏，清是下雲端。我識朝天路，從容自整冠。"]'),
('yuding-39','杭州郡齋南亭','姚合','唐','御定全唐诗','yuding','','[]','符印懸腰下，東山不得歸。獨行南北近，漸老往還稀。',48,'御定全唐詩/json/500.json','["符印懸腰下，東山不得歸。獨行南北近，漸老往還稀。", "迸筍侵窗長，驚蟬出樹飛。田田池上葉，長是使君衣。"]'),
('yuding-40','郡中西園','姚合','唐','御定全唐诗','yuding','','[]','西園春欲盡，芳草徑難分。靜語唯幽鳥，閑眠獨使君。',48,'御定全唐詩/json/500.json','["西園春欲盡，芳草徑難分。靜語唯幽鳥，閑眠獨使君。", "密林生雨氣，古石帶潮文。雖去清秋遠，朝朝見白雲。"]'),
('yuding-41','杭州官舍偶書','姚合','唐','御定全唐诗','yuding','','[]','錢塘刺史謾題詩，貧褊無恩懦少威。春盡酒杯花影在，',40,'御定全唐詩/json/500.json','["錢塘刺史謾題詩，貧褊無恩懦少威。春盡酒杯花影在，", "無術理人人自理，朝朝漸覺簿書稀。"]'),
('yuding-42','省直書事','姚合','唐','御定全唐诗','yuding','','[]','默默滄江老，官分右掖榮。立朝班近殿，奏直上知名。',120,'御定全唐詩/json/500.json','["默默滄江老，官分右掖榮。立朝班近殿，奏直上知名。", "曉霧和香氣，晴樓下樂聲。蜀箋金屑膩，月兔筆毫精。", "禁樹霏煙覆，宮牆瑞草生。露盤秋更出，玉漏晝還清。", "碧蘚無塵染，寒蟬似鳥鳴。竹深雲自宿，天近日先明。", "孱懦難封詔，疏愚但擲觥。素餐終日足，寧免眾人輕。"]'),
('yuding-43','杭州官舍即事','姚合','唐','御定全唐诗','yuding','','[]','臨江府署清，閑臥複閑行。苔蘚疏塵色，梧桐出雨聲。',48,'御定全唐詩/json/500.json','["臨江府署清，閑臥複閑行。苔蘚疏塵色，梧桐出雨聲。", "漸除身外事，暗作道家名。更喜仙山近，庭前藥自生。"]'),
('yuding-44','假日書事呈院中司徒','姚合','唐','御定全唐诗','yuding','','[]','十日公府靜，巾櫛起清晨。寒蟬近衰柳，古木似高人。',48,'御定全唐詩/json/500.json','["十日公府靜，巾櫛起清晨。寒蟬近衰柳，古木似高人。", "學佛寧憂老，為儒自喜貧。海山歸未得，芝朮夢中春。"]'),
('yuding-45','書縣丞舊廳','姚合','唐','御定全唐诗','yuding','','[]','宮殿半山上，人家向下居。古廳眠易魘，老吏語多虛。',48,'御定全唐詩/json/500.json','["宮殿半山上，人家向下居。古廳眠易魘，老吏語多虛。", "雨水澆荒竹，溪沙擁廢渠。聖朝收外府，皆是九天除。"]'),
('yuding-46','縣中秋宿','姚合','唐','御定全唐诗','yuding','','[]','鼓絕門方掩，蕭條作吏心。露垂庭際草，螢照竹間禽。',48,'御定全唐詩/json/500.json','["鼓絕門方掩，蕭條作吏心。露垂庭際草，螢照竹間禽。", "棋罷嫌無月，眠遲聽盡砧。還知未離此，時複更相尋。"]'),
('yuding-47','夏夜宿江驛','姚合','唐','御定全唐诗','yuding','','[]','竹屋臨江岸，清宵興自長。夜深傾北斗，葉落映橫塘。',48,'御定全唐詩/json/500.json','["竹屋臨江岸，清宵興自長。夜深傾北斗，葉落映橫塘。", "渚鬧漁歌響，風和角粽香。卻愁南去棹，早晚到瀟湘。"]'),
('yuding-48','陝城即事','姚合','唐','御定全唐诗','yuding','','[]','左右分京闕，黃河與宅連。何功來此地，竊位已經年。',48,'御定全唐詩/json/500.json','["左右分京闕，黃河與宅連。何功來此地，竊位已經年。", "天下才彌小，關中鎮最先。隴山望可見，惆悵是窮邊。"]'),
('yuding-0','和東都令狐留守相公','姚合','唐','御定全唐诗','yuding','','[]','除官東守洛陽宮，恩比藩方任更雄。拜表出時傳七刻，',40,'御定全唐詩/json/501.json','["除官東守洛陽宮，恩比藩方任更雄。拜表出時傳七刻，", "三十六峰詩酒思，朝朝閑望與誰同。"]'),
('yuding-1','和高諫議蒙兼賓客時入翰苑','姚合','唐','御定全唐诗','yuding','','[]','兼秩恩歸第一流，時尋仙路向瀛洲。鐘聲迢遞銀河曉，',40,'御定全唐詩/json/501.json','["兼秩恩歸第一流，時尋仙路向瀛洲。鐘聲迢遞銀河曉，", "從來共結歸山侶，今日多應獨自休。"]'),
('yuding-2','和盧給事酬裴員外','姚合','唐','御定全唐诗','yuding','','[]','南山雪色徹皇州，鐘鼓聲交曉氣浮。鴛鷺簪裾上龍尾，',40,'御定全唐詩/json/501.json','["南山雪色徹皇州，鐘鼓聲交曉氣浮。鴛鷺簪裾上龍尾，", "贈答詩成才思敵，病夫欲和幾朝愁。"]'),
('yuding-3','和裴結端公早朝','姚合','唐','御定全唐诗','yuding','','[]','魚鑰千門啟，雞人唱曉傳。冕旒臨玉殿，丞相入爐煙。',72,'御定全唐詩/json/501.json','["魚鑰千門啟，雞人唱曉傳。冕旒臨玉殿，丞相入爐煙。", "列位同居左，分行忝在前。仰聞天語近，俯拜佩聲連。", "彩仗祥光動，彤庭霽色鮮。威儀誰可紀，柱史有新篇。"]'),
('yuding-4','和門下李相餞西蜀相公','姚合','唐','御定全唐诗','yuding','','[]','聖朝同舜日，作相有夔龍。理化知無外，烝黎盡可封。',216,'御定全唐詩/json/501.json','["聖朝同舜日，作相有夔龍。理化知無外，烝黎盡可封。", "燮和皆達識，出入並登庸。武騎增餘勇，儒冠貴所從。", "贈詩全六義，出鎮越千峰。連日陳天樂，芳筵疊酒鐘。", "烏台情已洽，鳳閣分彌濃。棧轉旌搖水，崖高馬蹋松。", "恩深施遠俗，化美見前蹤。江曉流巴字，山晴聳劍峰。", "雙油擁上宰，四海羨臨邛。先路聲華遠，離京詔旨重。", "歲除今向盡，春色即相逢。嫩葉抽赬蕊，新苔長翠茸。", "冰銷魚潎潎，林暖鳥噰噰。泉落聞難盡，花開看不供。", "青城方眷戀，黃閣竟從容。計日歸台席，還聽長樂鐘。"]'),
('yuding-5','和座主相公西亭秋日即事','姚合','唐','御定全唐诗','yuding','','[]','西亭秋望好，寧要更垂簾。夫子牆還峻，酂侯宅過謙。',96,'御定全唐詩/json/501.json','["西亭秋望好，寧要更垂簾。夫子牆還峻，酂侯宅過謙。", "微風紅葉下，新雨綠苔黏。窗外松初長，欄中藥旋添。", "海圖裝玉軸，書目記牙籤。竹色晴連地，山光遠入簷。", "酒濃杯稍重，詩冷語多尖。屬和才雖淺，題高免客嫌。"]'),
('yuding-6','和秘書崔少監春日遊青龍寺僧院','姚合','唐','御定全唐诗','yuding','','[]','官清書府足閒時，曉起攀花折柳枝。九陌城中尋不盡，',40,'御定全唐詩/json/501.json','["官清書府足閒時，曉起攀花折柳枝。九陌城中尋不盡，", "見說往來多靜者，未知前日更逢誰。"]'),
('yuding-7','和李紳助教不赴看花','姚合','唐','御定全唐诗','yuding','','[]','笑辭聘禮深坊住，門館長閑似退居。太學官資清品秩，',40,'御定全唐詩/json/501.json','["笑辭聘禮深坊住，門館長閑似退居。太學官資清品秩，", "且看牡丹吟麗句，不知此外複何如。"]'),
('yuding-8','和李十二舍人冬至日','姚合','唐','御定全唐诗','yuding','','[]','獻壽人皆慶，南山複北堂。從今千萬日，此日又初長。',24,'御定全唐詩/json/501.json','["獻壽人皆慶，南山複北堂。從今千萬日，此日又初長。"]'),
('yuding-9','和裴令公新成綠野堂即事','姚合','唐','御定全唐诗','yuding','','[]','結構立嘉名，軒窗四面明。丘牆高莫比，蕭宅僻還清。',120,'御定全唐詩/json/501.json','["結構立嘉名，軒窗四面明。丘牆高莫比，蕭宅僻還清。", "池際龜潛戲，庭前藥旋生。樹深簷稍邃，石峭徑難平。", "道曠襟情遠，神閑視聽精。古今功獨出，大小隱俱成。", "曙雨新苔色，秋風長桂聲。攜詩就竹寫，取酒對花傾。", "古寺招僧飯，方塘看鶴行。人間無此貴，半仗暮歸城。"]'),
('yuding-10','和厲玄侍禦題戶部李相公廬山西林草堂','姚合','唐','御定全唐诗','yuding','','[]','茅屋臨江起，登庸複應期。遙知歸去日，自致太平時。',48,'御定全唐詩/json/501.json','["茅屋臨江起，登庸複應期。遙知歸去日，自致太平時。", "幽藥禪僧護，高窗宿鳥窺。行人盡歌詠，唯子獨能詩。"]'),
('yuding-11','和鄭相演楊尚書蜀中唱和詩','姚合','唐','御定全唐诗','yuding','','[]','天福坤維厚，忠賢擁節旄。江同渭濱遠，山似傅岩高。',96,'御定全唐詩/json/501.json','["天福坤維厚，忠賢擁節旄。江同渭濱遠，山似傅岩高。", "元氣符才格，文星照筆毫。五言全麗則，六義出風騷。", "聖日麻雙下，洪爐柄共操。寵榮連雨露，先後比蕭曹。", "唱絕時難和，吟多客詎勞。四方雖紙貴，誰怕費錢刀。"]'),
('yuding-12','和戶部侍郎省中晚歸','姚合','唐','御定全唐诗','yuding','','[]','寒日南宮晚，閑吟半醉歸。位高行路靜，詩好和人稀。',48,'御定全唐詩/json/501.json','["寒日南宮晚，閑吟半醉歸。位高行路靜，詩好和人稀。", "古樹苔文匝，遙峰雪色微。寧知逢彩筆，寂寞有光輝。"]'),
('yuding-13','和元八郎中秋居','姚合','唐','御定全唐诗','yuding','','[]','聖代無為化，郎中似散仙。晚眠隨客醉，夜坐學僧禪。',48,'御定全唐詩/json/501.json','["聖代無為化，郎中似散仙。晚眠隨客醉，夜坐學僧禪。", "酒用林花釀，茶將野水煎。人生知此味，獨恨少因緣。"]'),
('yuding-14','和李十二舍人、裴四二舍人兩閣老酬白少傅見寄','姚合','唐','御定全唐诗','yuding','','[]','罷草王言星歲久，嵩高山色日相親。蕭條雨夜吟連曉，',48,'御定全唐詩/json/501.json','["罷草王言星歲久，嵩高山色日相親。蕭條雨夜吟連曉，", "林中長老呼居士，天下書生仰達人。酒挈數瓶杯亦闊，"]'),
('yuding-15','和劉禹錫主客冬初拜表懷上都故人','姚合','唐','御定全唐诗','yuding','','[]','九陌喧喧騎吏催，百官拜表禁城開。林疏曉日明紅葉，',40,'御定全唐詩/json/501.json','["九陌喧喧騎吏催，百官拜表禁城開。林疏曉日明紅葉，", "此時共想朝天客，謝食方從閣裏回。"]'),
('yuding-16','和太僕田卿酬殷堯藩侍禦見寄','姚合','唐','御定全唐诗','yuding','','[]','往還知分熟，酬贈思同新。嗜飲殷偏逸，閑吟卿亦貧。',72,'御定全唐詩/json/501.json','["往還知分熟，酬贈思同新。嗜飲殷偏逸，閑吟卿亦貧。", "古苔寒更翠，修竹靜無鄰。促席燈浮酒，聽鴻霜滿身。", "淺才唯是我，高論更何人。攜手宜相訪，窮行少路塵。"]'),
('yuding-17','和膳部李郎中秋夕','姚合','唐','御定全唐诗','yuding','','[]','淅淅複修修，涼風似水流。此生難免老，舉世大同愁。',48,'御定全唐詩/json/501.json','["淅淅複修修，涼風似水流。此生難免老，舉世大同愁。", "螢影明苔蘚，鴻聲傍鬥牛。猶分省署直，何日是歸休。"]'),
('yuding-18','和前吏部韓侍郎夜泛南溪','姚合','唐','御定全唐诗','yuding','','[]','辭得官來疾漸平，世間難有此高情。',32,'御定全唐詩/json/501.json','["辭得官來疾漸平，世間難有此高情。", "新秋月滿南溪裏，引客乘船處處行。"]'),
('yuding-19','和王郎中題華州李中丞廳','姚合','唐','御定全唐诗','yuding','','[]','蓮華峰下郡齋前，繞砌穿池貯瀑泉。',32,'御定全唐詩/json/501.json','["蓮華峰下郡齋前，繞砌穿池貯瀑泉。", "君到亦應閑不得，主人草聖複詩仙。"]'),
('yuding-20','和厲玄侍禦、無可上人會宿見寄','姚合','唐','御定全唐诗','yuding','','[]','九衢難會宿，況複是寒天。朝客清貧老，林僧默悟禪。',48,'御定全唐詩/json/501.json','["九衢難會宿，況複是寒天。朝客清貧老，林僧默悟禪。", "眠遲消漏水，吟苦墮寒涎。異日來尋我，滄江有釣船。"]'),
('yuding-21','和令狐六員外直夜即事寄上相公','姚合','唐','御定全唐诗','yuding','','[]','霜台同處軒窗接，粉署先登語笑疏。皓月滿簾聽玉漏，',40,'御定全唐詩/json/501.json','["霜台同處軒窗接，粉署先登語笑疏。皓月滿簾聽玉漏，", "榮貴人間難有比，相公離此十年餘。"]'),
('yuding-22','答孟侍禦早朝見寄','姚合','唐','御定全唐诗','yuding','','[]','河傾月向西，九陌鼓聲齊。塵靜霜華遠，煙生曙色低。',48,'御定全唐詩/json/501.json','["河傾月向西，九陌鼓聲齊。塵靜霜華遠，煙生曙色低。", "禁門人已度，宮樹鳥猶棲。疏懶勞相問，登山有舊梯。"]'),
('yuding-23','和友人新居園上','姚合','唐','御定全唐诗','yuding','','[]','新居多野思，不似在京城。牆上雲相壓，庭前竹亂生。',48,'御定全唐詩/json/501.json','["新居多野思，不似在京城。牆上雲相壓，庭前竹亂生。", "尋師望藥力，依譜上琴聲。好是中秋夜，無塵有月明。"]'),
('yuding-24','和裴令公游南莊憶白二十、韋七二賓客','姚合','唐','御定全唐诗','yuding','','[]','四郊初雨歇，高樹滴猶殘。池滿紅蓮濕，雲收綠野寬。',96,'御定全唐詩/json/501.json','["四郊初雨歇，高樹滴猶殘。池滿紅蓮濕，雲收綠野寬。", "花開半山曉，竹動數村寒。鬥雀翻衣袂，驚魚觸釣竿。", "樽前多野客，膝下盡郎官。劚石通泉脈，移松出藥欄。", "關東分務重，天下似公難。半醉思韋白，題詩染彩翰。"]'),
('yuding-25','和李舍人秋日臥疾言懷','姚合','唐','御定全唐诗','yuding','','[]','閑臥襟情遠，西風菊漸芳。虛窗通曉景，珍簟卷秋光。',96,'御定全唐詩/json/501.json','["閑臥襟情遠，西風菊漸芳。虛窗通曉景，珍簟卷秋光。", "果墜青莎徑，塵離綠蘚牆。藥奩開靜室，書閣出叢篁。", "對酒吟難盡，思山夢稍長。王言生彩筆，朝服惹爐香。", "松影幽連砌，蟲聲冷到床。詩成誰敢和，清思若懷霜。"]'),
('yuding-26','和李十二舍人直日放朝對雪','姚合','唐','御定全唐诗','yuding','','[]','今朝街鼓何人聽，朝客開門對雪眠。',32,'御定全唐詩/json/501.json','["今朝街鼓何人聽，朝客開門對雪眠。", "豈比直廬丹禁裏，九重天近色彌鮮。"]'),
('yuding-27','答李頻秀才','姚合','唐','御定全唐诗','yuding','','[]','一年離九陌，壁上掛朝袍。物外詩情遠，人間酒味高。',48,'御定全唐詩/json/501.json','["一年離九陌，壁上掛朝袍。物外詩情遠，人間酒味高。", "思歸知病長，失寢覺神勞。衰老無多思，因君把筆毫。"]'),
('yuding-28','答胡遇','姚合','唐','御定全唐诗','yuding','','[]','一會一分離，貧遊少定期。酒多為客穩，米貴入城遲。',48,'御定全唐詩/json/501.json','["一會一分離，貧遊少定期。酒多為客穩，米貴入城遲。", "晴日偷將睡，秋山乞與詩。縱然眉得展，不似見君時。"]'),
('yuding-29','答友人招游','姚合','唐','御定全唐诗','yuding','','[]','不來知盡怪，失意懶春遊。聞鳥寧驚夢，看花怕引愁。',48,'御定全唐詩/json/501.json','["不來知盡怪，失意懶春遊。聞鳥寧驚夢，看花怕引愁。", "賭棋招敵手，沽酒自扶頭。何似華筵上，推辭候到籌。"]'),
('yuding-30','答竇知言','姚合','唐','御定全唐诗','yuding','','[]','冬日易慘惡，暴風拔山根。塵沙落黃河，濁波如地翻。',192,'御定全唐詩/json/501.json','["冬日易慘惡，暴風拔山根。塵沙落黃河，濁波如地翻。", "飛鳥皆束翼，居人不開門。獨我赴省期，冒此馳轂轅。", "陝城城西邊，逢子亦且奔。所趨事一心，相見如弟昆。", "我慘得子舒，我寒得子溫。同行十日程，僮僕性亦敦。", "到京人事多，日無閑精魂。念子珍重我，吐辭發蒙昏。", "反復千萬意，一百六十言。格高思清冷，山低濟渾渾。", "嘗聞朋友惠，贈言始為恩。金玉日消費，好句長存存。", "倒篚別收貯，不與俗士論。每當清夜吟，使我如哀猿。"]'),
('yuding-31','酬田就','姚合','唐','御定全唐诗','yuding','','[]','閒居多僻靜，猶恐道相違。只是夜深坐，那堪春未歸。',48,'御定全唐詩/json/501.json','["閒居多僻靜，猶恐道相違。只是夜深坐，那堪春未歸。", "嫩苔粘野色，香絮撲人衣。縱有野僧到，終朝不話非。"]'),
('yuding-32','酬禮部李員外見寄','姚合','唐','御定全唐诗','yuding','','[]','本求仙郡是閒居，豈向郎官更有書。溪石誰思玉匠愛，',40,'御定全唐詩/json/501.json','["本求仙郡是閒居，豈向郎官更有書。溪石誰思玉匠愛，", "唯見君詩難便舍，寒宵吟到曉更初。"]'),
('yuding-33','酬令狐郎中見寄','姚合','唐','御定全唐诗','yuding','','[]','昨是兒童今是翁，人間日月急如風。',32,'御定全唐詩/json/501.json','["昨是兒童今是翁，人間日月急如風。", "常聞欲向滄江去，除我無人與子同。"]'),
('yuding-34','酬李廓精舍南台望月見寄','姚合','唐','御定全唐诗','yuding','','[]','看月空門裏，詩家境有餘。露寒僧梵出，林靜鳥巢疏。',48,'御定全唐詩/json/501.json','["看月空門裏，詩家境有餘。露寒僧梵出，林靜鳥巢疏。", "遠色當秋半，清光勝夜初。獨無臺上思，寂寞守吾廬。"]'),
('yuding-35','酬光祿田卿末伏見寄','姚合','唐','御定全唐诗','yuding','','[]','下伏秋期近，還知扇漸疏。驚飆墜鄰果，暴雨落江魚。',48,'御定全唐詩/json/501.json','["下伏秋期近，還知扇漸疏。驚飆墜鄰果，暴雨落江魚。", "貴寺雖同秩，閑曹只管書。朝朝廊下食，相庇在肴菹。"]'),
('yuding-36','酬薛奉禮見贈之作','姚合','唐','御定全唐诗','yuding','','[]','棲棲滄海一耕人，詔遣江邊作使君。山頂雨餘青到地，',40,'御定全唐詩/json/501.json','["棲棲滄海一耕人，詔遣江邊作使君。山頂雨餘青到地，", "珍重來章相借分，芳名未識已曾聞。"]'),
('yuding-37','酬盧汀諫議','姚合','唐','御定全唐诗','yuding','','[]','粟如流水帛如山，依念倉邊語笑間。篇什縱橫文案少，',40,'御定全唐詩/json/501.json','["粟如流水帛如山，依念倉邊語笑間。篇什縱橫文案少，", "遙賀來年二三月，彩衣先輩過春關。"]'),
('yuding-38','酬萬年張郎中見寄','姚合','唐','御定全唐诗','yuding','','[]','貢籍常同府，周行今一時。諫曹誠已忝，京邑豈相宜。',48,'御定全唐詩/json/501.json','["貢籍常同府，周行今一時。諫曹誠已忝，京邑豈相宜。", "黑髮年來盡，滄江歸去遲。何時得攜手，林下靜吟詩。"]'),
('yuding-39','酬光祿田卿六韻見寄','姚合','唐','御定全唐诗','yuding','','[]','以病辭朝謁，迂疏種藥翁。心彌念魚鳥，詔遣理兵戎。',72,'御定全唐詩/json/501.json','["以病辭朝謁，迂疏種藥翁。心彌念魚鳥，詔遣理兵戎。", "繞戶旌旗影，吹人鼓角風。雪晴嵩嶽頂，樹老陝城宮。", "蒞職才微薄，歸山路未通。名卿詩句峭，誚我在關東。"]'),
('yuding-40','酬楊汝士尚書喜人移居','姚合','唐','御定全唐诗','yuding','','[]','未得滄江外，衰殘讀藥書。聖朝優上秩，仁裏許閒居。',48,'御定全唐詩/json/501.json','["未得滄江外，衰殘讀藥書。聖朝優上秩，仁裏許閒居。", "樹對枝相接，泉同井不疏。酬章深自鄙，欲寄複躊躇。"]'),
('yuding-41','酬田卿書齋即事見寄','姚合','唐','御定全唐诗','yuding','','[]','幽齋琴思靜，晚下紫宸朝。舊隱同溪遠，周行隔品遙。',48,'御定全唐詩/json/501.json','["幽齋琴思靜，晚下紫宸朝。舊隱同溪遠，周行隔品遙。", "深槐蟬唧唧，疏竹雨蕭蕭。不是相尋懶，煩君舉酒瓢。"]'),
('yuding-42','酬張籍司業見寄','姚合','唐','御定全唐诗','yuding','','[]','日日在心中，青山青桂叢。高人多愛靜，歸路亦應同。',48,'御定全唐詩/json/501.json','["日日在心中，青山青桂叢。高人多愛靜，歸路亦應同。", "罷吏方無病，因僧得解空。新詩勞見問，吟對竹林風。"]'),
('yuding-43','謝汾州田大夫寄茸氈葡萄','姚合','唐','御定全唐诗','yuding','','[]','筐封紫葡萄，筒卷白茸毛。臥暖身應健，含消齒免勞。',48,'御定全唐詩/json/501.json','["筐封紫葡萄，筒卷白茸毛。臥暖身應健，含消齒免勞。", "衾衣疏不稱，梨栗鄙難高。曉起題詩報，寒澌滿筆毫。"]'),
('yuding-44','牧杭州謝李太尉德裕','姚合','唐','御定全唐诗','yuding','','[]','皇恩特許拜杭壇，欲謝旌旄去就難。',32,'御定全唐詩/json/501.json','["皇恩特許拜杭壇，欲謝旌旄去就難。", "偷擬白頭瞻畫戟，四神俱散發毛寒。"]'),
('yuding-45','杏園宴上謝座主','姚合','唐','御定全唐诗','yuding','','[]','得陪桃李植芳叢，別感生成太昊功。',32,'御定全唐詩/json/501.json','["得陪桃李植芳叢，別感生成太昊功。", "今日無言春雨後，似含冷涕謝東風。"]'),
('yuding-46','謝韜光上人','姚合','唐','御定全唐诗','yuding','','[]','上方清淨無因住，唯願他生得住持。',32,'御定全唐詩/json/501.json','["上方清淨無因住，唯願他生得住持。", "只恐無生複無我，不知何處更逢師。"]'),
('yuding-47','謝秦校書與無可上人見訪','姚合','唐','御定全唐诗','yuding','','[]','道同無宿約，三伏自從容。窗豁山侵座，扇搖風下松。',48,'御定全唐詩/json/501.json','["道同無宿約，三伏自從容。窗豁山侵座，扇搖風下松。", "客吟多繞竹，僧飯只憑鐘。向晚分歸路，莓苔行跡重。"]'),
('yuding-48','喜胡遇至','姚合','唐','御定全唐诗','yuding','','[]','窮居稀出入，門戶滿塵埃。病少閒人問，貧唯密友來。',72,'御定全唐詩/json/501.json','["窮居稀出入，門戶滿塵埃。病少閒人問，貧唯密友來。", "茅齋從掃破，藥酒遣生開。多事經時別，還愁不宿回。", "就林燒嫩筍，繞樹揀香梅。相對題新什，遲成舉罰杯。"]'),
('yuding-49','喜賈島至','姚合','唐','御定全唐诗','yuding','','[]','布囊懸蹇驢，千里到貧居。飲酒誰堪伴，留詩自與書。',48,'御定全唐詩/json/501.json','["布囊懸蹇驢，千里到貧居。飲酒誰堪伴，留詩自與書。", "愛眠知不醉，省語似相疏。軍吏衣裳窄，還應暗笑餘。"]'),
('yuding-50','喜喻鳧至','姚合','唐','御定全唐诗','yuding','','[]','欲出心還懶，閑吟繞寢床。道書蟲食盡，酒律客偷將。',48,'御定全唐詩/json/501.json','["欲出心還懶，閑吟繞寢床。道書蟲食盡，酒律客偷將。", "愁至為多病，貧來減得狂。見君何所似，如熱得清涼。"]'),
('yuding-51','喜雍陶秋夜訪宿','姚合','唐','御定全唐诗','yuding','','[]','曉立侍爐煙，夜歸蓬蓽眠。露華明菊上，螢影滅燈前。',48,'御定全唐詩/json/501.json','["曉立侍爐煙，夜歸蓬蓽眠。露華明菊上，螢影滅燈前。", "清漏和砧疊，棲禽與葉連。高人來此宿，為似在山顛。"]'),
('yuding-52','喜賈島雨中訪宿','姚合','唐','御定全唐诗','yuding','','[]','雨裏難逢客，閑吟不復眠。蟲聲秋並起，林色夜相連。',48,'御定全唐詩/json/501.json','["雨裏難逢客，閑吟不復眠。蟲聲秋並起，林色夜相連。", "愛酒此生裏，趨朝未老前。終須攜手去，滄海棹魚船。"]'),
('yuding-53','喜馬戴冬夜見過期無可上人不至','姚合','唐','御定全唐诗','yuding','','[]','客來初夜裏，藥酒自開封。老漸多歸思，貧惟長病容。',96,'御定全唐詩/json/501.json','["客來初夜裏，藥酒自開封。老漸多歸思，貧惟長病容。", "苦寒燈焰細，近曉鼓聲重。僧可還相舍，深居閉古松。", "內殿臣相命，開樽話舊時。夜鐘催鳥絕，積雪阻僧期。", "林靜寒聲遠，天陰曙色遲。今宵複何夕，鳴佩坐相隨。"]'),
('yuding-54','訪僧法通不遇','姚合','唐','御定全唐诗','yuding','','[]','訪師師不遇，禮佛佛無言。依舊將煩惱，黃昏入宅門。',24,'御定全唐詩/json/501.json','["訪師師不遇，禮佛佛無言。依舊將煩惱，黃昏入宅門。"]'),
('yuding-55','夜期友生不至','姚合','唐','御定全唐诗','yuding','','[]','忍寒停酒待君來，酒作淩澌火作灰。',32,'御定全唐詩/json/501.json','["忍寒停酒待君來，酒作淩澌火作灰。", "半夜出門重立望，月明先自下高臺。"]'),
('yuding-56','尋僧不遇','姚合','唐','御定全唐诗','yuding','','[]','入門愁自散，不假見僧翁。花落煎茶水，松生醒酒風。',48,'御定全唐詩/json/501.json','["入門愁自散，不假見僧翁。花落煎茶水，松生醒酒風。", "拂床尋古畫，拔刺看新叢。別有遊人見，多疑住此中。"]'),
('yuding-57','過友人山莊','姚合','唐','御定全唐诗','yuding','','[]','蕙帶纏腰複野蔬，一莊水竹數房書。',32,'御定全唐詩/json/501.json','["蕙帶纏腰複野蔬，一莊水竹數房書。", "舉頭忽見南山雪，便說休官相近居。"]'),
('yuding-58','奉和前司封蘇郎中喜嚴常侍蕭給事見訪驚斑鬢之什','姚合','唐','御定全唐诗','yuding','','[]','繞鬢滄浪有幾莖，珥貂相問夕郎驚。只應為酒微微變，',40,'御定全唐詩/json/501.json','["繞鬢滄浪有幾莖，珥貂相問夕郎驚。只應為酒微微變，", "即提彩筆裁天詔，誰得吟詩自在行。"]'),
('yuding-59','奉和門下相公雨中寄裴給事','姚合','唐','御定全唐诗','yuding','','[]','曉起閑看雨，垂簷自滴階。風清想林壑，雲濕似江淮。',72,'御定全唐詩/json/501.json','["曉起閑看雨，垂簷自滴階。風清想林壑，雲濕似江淮。", "石信浮漚重，泥從積蘚埋。氣消濃酒力，心助獨吟懷。", "颯颯通琴韻，蕭蕭靜竹齋。彩毫無限思，念與夕郎乖。"]'),
('yuding-60','答韓湘','姚合','唐','御定全唐诗','yuding','','[]','疏散無世用，為文乏天格。把筆日不休，忽忽有所得。',168,'御定全唐詩/json/501.json','["疏散無世用，為文乏天格。把筆日不休，忽忽有所得。", "所得良自慰，不求他人識。子獨訪我來，致詩過相飾。", "君子無浮言，此詩應亦直。但慮憂我深，鑒亦隨之惑。", "子在名場中，屢戰還屢北。我無數子明，端坐空歎息。", "昨聞過春關，名系吏部籍。三十登高科，前塗浩難測。", "詩人多峭冷，如水在胸臆。豈隨尋常人，五藏為酒食。", "期來作酬章，危坐吟到夕。難為間其辭，益貴我紙墨。"]'),
('yuding-61','奉和四松','姚合','唐','御定全唐诗','yuding','','[]','四松相對植，蒼翠映中台。擢幹淩空去，移根劚石開。',120,'御定全唐詩/json/501.json','["四松相對植，蒼翠映中台。擢幹淩空去，移根劚石開。", "陰陽氣潛煦，造化手親栽。日月滋佳色，煙霄長異材。", "清音勝在澗，寒影遍生苔。靜繞霜沾履，閑看酒滿杯。", "同榮朱戶際，永日白雲隈。密葉聞風度，高枝見鶴來。", "賞心難可盡，麗什妙難裁。此地無因到，迴圈幾百回。"]'),
('yuding-0','和李補闕曲江看蓮花','姚合','唐','御定全唐诗','yuding','','[]','露荷迎曙發，灼灼複田田。乍見神應駭，頻來眼尚顛。',240,'御定全唐詩/json/502.json','["露荷迎曙發，灼灼複田田。乍見神應駭，頻來眼尚顛。", "光凝珠有蒂，焰起火無煙。粉膩黃絲蕊，心重碧玉錢。", "日浮秋轉麗，雨灑晚彌鮮。醉豔酣千朵，愁紅思一川。", "綠莖扶萼正，翠菂滿房圓。淡暈還殊眾，繁英得自然。", "高名猶不厭，上客去爭先。景逸傾芳酒，懷濃習彩箋。", "海霞寧有態，蜀錦不成妍。客至應消病，僧來欲破禪。", "曉多臨水立，夜只傍堤眠。金似明沙渚，燈疑宿浦船。", "風驚叢乍密，魚戲影微偏。穠彩燒晴霧，殷姿纈碧泉。", "畫工投粉筆，宮女棄花鈿。鳥戀驚難起，蜂偷困不前。", "繞行香爛熳，折贈意纏綿。誰計江南曲，風流合管弦。"]'),
('yuding-1','和王郎中召看牡丹','姚合','唐','御定全唐诗','yuding','','[]','葩疊萼相重，燒欄複照空。妍姿朝景裏，醉豔晚煙中。',144,'御定全唐詩/json/502.json','["葩疊萼相重，燒欄複照空。妍姿朝景裏，醉豔晚煙中。", "乍怪霞臨砌，還疑燭出籠。繞行驚地赤，移坐覺衣紅。", "殷麗開繁朵，香濃發幾叢。裁綃樣豈似，染茜色寧同。", "嫩畏人看損，鮮愁日炙融。嬋娟涵宿露，爛熳抵春風。", "縱賞襟情合，閑吟景思通。客來歸盡懶，鶯戀語無窮。", "萬物珍那比，千金買不充。如今難更有，縱有在仙宮。"]'),
('yuding-2','詠南池嘉蓮','姚合','唐','御定全唐诗','yuding','','[]','芙蓉池裏葉田田，一本雙花出碧泉。濃淡共妍香各散，',40,'御定全唐詩/json/502.json','["芙蓉池裏葉田田，一本雙花出碧泉。濃淡共妍香各散，", "四野人聞皆盡喜，爭來入郭看嘉蓮。"]'),
('yuding-3','種葦','姚合','唐','御定全唐诗','yuding','','[]','欲種數莖葦，出門來往頻。近陂收本土，選地問幽人。',48,'御定全唐詩/json/502.json','["欲種數莖葦，出門來往頻。近陂收本土，選地問幽人。", "靜看唯思長，初移未覺勻。坐中尋竹客，將去更逡巡。"]'),
('yuding-4','采松花','姚合','唐','御定全唐诗','yuding','','[]','擬服松花無處學，嵩陽道士忽相教。',32,'御定全唐詩/json/502.json','["擬服松花無處學，嵩陽道士忽相教。", "今朝試上高枝采，不覺傾翻仙鶴巢。"]'),
('yuding-5','詠新菊','姚合','唐','御定全唐诗','yuding','','[]','黃金色未足，摘取且嘗新。若待重陽日，何曾異眾人。',24,'御定全唐詩/json/502.json','["黃金色未足，摘取且嘗新。若待重陽日，何曾異眾人。"]'),
('yuding-6','楊柳枝詞五首','姚合','唐','御定全唐诗','yuding','','[]','黃金絲掛粉牆頭，動似顛狂靜似愁。',160,'御定全唐詩/json/502.json','["黃金絲掛粉牆頭，動似顛狂靜似愁。", "遊客見時心自醉，無因得見謝家樓。", "葉葉如眉翠色濃，黃鶯偏戀語從容。", "橋邊陌上無人識，雨濕煙和思萬重。", "江上東西離別饒，舊條折盡折新條。", "亦知春色人將去，猶勝狂風取次飄。", "二月楊花觸處飛，悠悠漠漠自東西。", "謝家詠雪徒相比，吹落庭前便作泥。", "江亭楊柳折還垂，月照深黃幾樹絲。", "見說隋堤枯已盡，年年行客怪春遲。"]'),
('yuding-7','郡中冬夜聞蛩','姚合','唐','御定全唐诗','yuding','','[]','秋蛩聲尚在，切切起蒼苔。久是忘情者，今還有事來。',48,'御定全唐詩/json/502.json','["秋蛩聲尚在，切切起蒼苔。久是忘情者，今還有事來。", "微霜風稍靜，圓月霧初開。此思誰能遣，應須執酒杯。"]'),
('yuding-8','聞新蟬寄李餘','姚合','唐','御定全唐诗','yuding','','[]','往年六月蟬應到，每到聞時骨欲驚。',32,'御定全唐詩/json/502.json','["往年六月蟬應到，每到聞時骨欲驚。", "今日槐花還似發，卻愁聽盡更無聲。"]'),
('yuding-9','聞蟬寄賈島','姚合','唐','御定全唐诗','yuding','','[]','秋來吟更苦，半咽半隨風。禪客心應亂，愁人耳願聾。',48,'御定全唐詩/json/502.json','["秋來吟更苦，半咽半隨風。禪客心應亂，愁人耳願聾。", "雨晴煙樹裏，日晚古城中。遠思應難盡，誰當與我同。"]'),
('yuding-10','題鶴雛','姚合','唐','御定全唐诗','yuding','','[]','羽毛生未齊，嶛峭醜於雞。夜夜穿籠出，擣衣砧上棲。',24,'御定全唐詩/json/502.json','["羽毛生未齊，嶛峭醜於雞。夜夜穿籠出，擣衣砧上棲。"]'),
('yuding-11','詠鶯','姚合','唐','御定全唐诗','yuding','','[]','春來深谷雪方消，鶯別寒林傍翠條。到處為憐煙景好，',40,'御定全唐詩/json/502.json','["春來深谷雪方消，鶯別寒林傍翠條。到處為憐煙景好，", "少婦聽時思舊曲，玉樓從此動雲韶。"]'),
('yuding-12','老馬','姚合','唐','御定全唐诗','yuding','','[]','臥來扶不起，唯向主人嘶。惆悵東郊道，秋來雨作泥。',24,'御定全唐詩/json/502.json','["臥來扶不起，唯向主人嘶。惆悵東郊道，秋來雨作泥。"]'),
('yuding-13','詠鏡','姚合','唐','御定全唐诗','yuding','','[]','鑄為明鏡絕塵埃，翡翠窗前掛玉台。繡帶共尋龍口出，',40,'御定全唐詩/json/502.json','["鑄為明鏡絕塵埃，翡翠窗前掛玉台。繡帶共尋龍口出，", "好是照身宜謝女，嫦娥飛向玉宮來。"]'),
('yuding-14','詠破屏風','姚合','唐','御定全唐诗','yuding','','[]','時人嫌古畫，倚壁不曾收。露滴膠山斷，風吹絹海秋。',48,'御定全唐詩/json/502.json','["時人嫌古畫，倚壁不曾收。露滴膠山斷，風吹絹海秋。", "殘雪飛屋裏，片水落床頭。尚勝凡花鳥，君能補綴不。"]'),
('yuding-15','古碑','姚合','唐','御定全唐诗','yuding','','[]','荒田一片石，文字滿青苔。不是逢閑客，何人肯讀來。',24,'御定全唐詩/json/502.json','["荒田一片石，文字滿青苔。不是逢閑客，何人肯讀來。"]'),
('yuding-16','拾得古硯','姚合','唐','御定全唐诗','yuding','','[]','僻性愛古物，終歲求不獲。昨朝得古硯，黃河灘之側。',120,'御定全唐詩/json/502.json','["僻性愛古物，終歲求不獲。昨朝得古硯，黃河灘之側。", "念此黃河中，應有昔人宅。宅亦作流水，斯硯未變易。", "波瀾所激觸，背面生罅隙。質狀樸且醜，今人作不得。", "捧持且驚歎，不敢施筆墨。或恐先聖人，嘗用修六籍。", "置之潔淨室，一日三磨拭。大喜豪貴嫌，久長得保惜。"]'),
('yuding-17','裴大夫見過','姚合','唐','御定全唐诗','yuding','','[]','湖南譙國盡英髦，心事相期節義高。',32,'御定全唐詩/json/502.json','["湖南譙國盡英髦，心事相期節義高。", "解下佩刀無所惜，新聞天子付三刀。"]'),
('yuding-18','謝韜光上人贈百齡藤杖','姚合','唐','御定全唐诗','yuding','','[]','衰病近來行少力，光公乞我百齡藤。',32,'御定全唐詩/json/502.json','["衰病近來行少力，光公乞我百齡藤。", "閑來杖此向何處，過水緣山只訪僧。"]'),
('yuding-19','詠貴游','姚合','唐','御定全唐诗','yuding','','[]','貴游多愛向深春，到處香凝數裏塵。紅杏花開連錦障，',40,'御定全唐詩/json/502.json','["貴游多愛向深春，到處香凝數裏塵。紅杏花開連錦障，", "日暮垂鞭共歸去，西園賓客附龍鱗。"]'),
('yuding-20','窮邊詞二首','姚合','唐','御定全唐诗','yuding','','[]','將軍作鎮古汧洲，水膩山春節氣柔。',64,'御定全唐詩/json/502.json','["將軍作鎮古汧洲，水膩山春節氣柔。", "清夜滿城絲管散，行人不信是邊頭。", "箭利弓調四鎮兵，蕃人不敢近東行。", "沿邊千里渾無事，唯見平安火入城。"]'),
('yuding-21','劍器詞三首','姚合','唐','御定全唐诗','yuding','','[]','聖朝能用將，破敵速如神。掉劍龍纏臂，開旗火滿身。',144,'御定全唐詩/json/502.json','["聖朝能用將，破敵速如神。掉劍龍纏臂，開旗火滿身。", "積屍川沒岸，流血野無塵。今日當場舞，應知是戰人。", "晝渡黃河水，將軍險用師。雪光偏著甲，風力不禁旗。", "陣變龍蛇活，軍雄鼓角知。今朝重起舞，記得戰酣時。", "破虜行千里，三軍意氣粗。展旗遮日黑，驅馬飲河枯。", "鄰境求兵略，皇恩索陣圖。元和太平樂，自古恐應無。"]'),
('yuding-22','從軍樂二首','姚合','唐','御定全唐诗','yuding','','[]','每日尋兵籍，經年別酒徒。眼疼長不校，肺病且還無。',96,'御定全唐詩/json/502.json','["每日尋兵籍，經年別酒徒。眼疼長不校，肺病且還無。", "僮僕驚衣窄，親情覺語粗。幾時得歸去，依舊作山夫。", "朝朝十指痛，唯署點兵符。貧賤依前在，顛狂一半無。", "身慚山友棄，膽賴酒杯扶。誰道從軍樂，年來鑷白須。"]'),
('yuding-23','敬宗皇帝挽詞三首','姚合','唐','御定全唐诗','yuding','','[]','從諫停東幸，垂衣寶曆昌。漢昭登位少，周代蔔年長。',144,'御定全唐詩/json/502.json','["從諫停東幸，垂衣寶曆昌。漢昭登位少，周代蔔年長。", "彩仗三清路，麻衣萬國喪。玄宮今一閉，終古柏蒼蒼。", "晚色啟重扉，旌旗路漸移。荊山鼎成日，湘浦竹斑時。", "臣子終身感，山園七月期。金莖看尚在，承露複何為。", "紫陌起仙飆，川原共寂寥。靈輴萬國護，儀殿百神朝。", "漏滴秋風路，笳吟灞水橋。微臣空感咽，踴絕覺天遙。"]'),
('yuding-24','文宗皇帝挽詞三首','姚合','唐','御定全唐诗','yuding','','[]','垂拱開成化，愔愔雅樂全。千官方就日，四海忽無天。',144,'御定全唐詩/json/502.json','["垂拱開成化，愔愔雅樂全。千官方就日，四海忽無天。", "堯舜非傳子，殷周但蔔年。聖功青史外，刊石在陵前。", "代以無為理，車書萬國同。繼兄還付弟，授聖悉推公。", "雲霧疑無日，笳簫別起風。金莖難複見，寒露落空中。", "龍歸攀不得，髯在侍臣邊。徹奠新阡起，登山吉從全。", "關河佳氣散，夷夏哭聲連。寂寞玄宮閉，朝昏千萬年。"]'),
('yuding-25','莊恪太子挽詞二首','姚合','唐','御定全唐诗','yuding','','[]','曉漏啟嚴城，宮臣縞素行。靈儀先鹵簿，新諡在銘旌。',96,'御定全唐詩/json/502.json','["曉漏啟嚴城，宮臣縞素行。靈儀先鹵簿，新諡在銘旌。", "雲晦郊原色，風連霰雪聲。淒涼望苑路，春草即應生。", "寒日青宮閉，玄堂渭水濱。華夷箋乍絕，凶吉禮空新。", "薤露歌連哭，泉扉夜作晨。吹笙今一去，千古在逡巡。"]'),
('yuding-26','哭費拾遺征君','姚合','唐','御定全唐诗','yuding','','[]','服儒師道旨，糲食臥中林。誰識先生事，無身是本心。',48,'御定全唐詩/json/502.json','["服儒師道旨，糲食臥中林。誰識先生事，無身是本心。", "空山流水遠，故國白雲深。日夕誰來哭，唯應猿鳥吟。"]'),
('yuding-27','哭硯山孫道士','姚合','唐','御定全唐诗','yuding','','[]','修短皆由命，暗懷師出塵。豈知修道者，難免不亡身。',48,'御定全唐詩/json/502.json','["修短皆由命，暗懷師出塵。豈知修道者，難免不亡身。", "永秘黃庭訣，高懸漉酒巾。可憐白犬子，閑吠遠行人。"]'),
('yuding-28','哭賈島二首','姚合','唐','御定全唐诗','yuding','','[]','白日西邊沒，滄波東去流。名雖千古在，身已一生休。',96,'御定全唐詩/json/502.json','["白日西邊沒，滄波東去流。名雖千古在，身已一生休。", "豈料文章遠，那知瑞草秋。曾聞有書劍，應是別人收。", "杳杳黃泉下，嗟君向此行。有名傳後世，無子過今生。", "新墓松三尺，空階月二更。從今舊詩卷，人覓寫應爭。"]'),
('yuding-29','楊給事師皋哭亡愛姬英英竊聞詩人多賦因而繼和','姚合','唐','御定全唐诗','yuding','','[]','真珠為土玉為塵，未識遙聞鼻亦辛。天上還應收至寶，',40,'御定全唐詩/json/502.json','["真珠為土玉為塵，未識遙聞鼻亦辛。天上還應收至寶，", "見說忘情唯有酒，夕陽對酒更傷神。"]'),
('yuding-30','喜覽涇州盧侍禦詩卷','姚合','唐','御定全唐诗','yuding','','[]','新詩十九首，麗格出青冥。得處神應駭，成時力盡停。',48,'御定全唐詩/json/502.json','["新詩十九首，麗格出青冥。得處神應駭，成時力盡停。", "正愁聞更喜，沈醉見還醒。自是天才健，非關筆硯靈。"]'),
('yuding-31','喜覽裴中丞詩卷','姚合','唐','御定全唐诗','yuding','','[]','新詩盈道路，清韻似敲金。調格江山峻，功夫日月深。',48,'御定全唐詩/json/502.json','["新詩盈道路，清韻似敲金。調格江山峻，功夫日月深。", "蜀箋方入寫，越客始消吟。後輩難知處，朝朝枉用心。"]'),
('yuding-32','心懷霜','姚合','唐','御定全唐诗','yuding','','[]','欲識為詩苦，秋霜若在心。神清方耿耿，氣肅覺沉沉。',72,'御定全唐詩/json/502.json','["欲識為詩苦，秋霜若在心。神清方耿耿，氣肅覺沉沉。", "皓素中方委，嚴凝得更深。依稀輕夕渚，仿佛在寒林。", "思勁淒孤韻，聲酸激冷吟。還如飲冰士，勵節望知音。"]'),
('yuding-33','聽僧雲端講經','姚合','唐','御定全唐诗','yuding','','[]','無生深旨誠難解，唯是師言得正真。',32,'御定全唐詩/json/502.json','["無生深旨誠難解，唯是師言得正真。", "遠近持齋來諦聽，酒坊魚市盡無人。"]'),
('yuding-34','臘日獵','姚合','唐','御定全唐诗','yuding','','[]','健夫結束執旌旗，曉度長江自合圍。野外狐狸搜得盡，',40,'御定全唐詩/json/502.json','["健夫結束執旌旗，曉度長江自合圍。野外狐狸搜得盡，", "蠟節畋遊非為己，莫驚刺史夜深歸。"]'),
('yuding-35','聞魏州破賊','姚合','唐','御定全唐诗','yuding','','[]','生靈蘇息到元和，上將功成自執戈。煙霧掃開尊北嶽，',40,'御定全唐詩/json/502.json','["生靈蘇息到元和，上將功成自執戈。煙霧掃開尊北嶽，", "從此四方無一事，朝朝雨露是恩波。"]'),
('yuding-36','下第','姚合','唐','御定全唐诗','yuding','','[]','枉為鄉里舉，射鵠藝渾疏。歸路羞人問，春城賃舍居。',48,'御定全唐詩/json/502.json','["枉為鄉里舉，射鵠藝渾疏。歸路羞人問，春城賃舍居。", "閉門辭雜客，開篋讀生書。以此投知己，還因勝自餘。"]'),
('yuding-37','得舍弟書','姚合','唐','御定全唐诗','yuding','','[]','親戚多離散，三年獨在城。貧居深穩臥，晚學愛閑名。',48,'御定全唐詩/json/502.json','["親戚多離散，三年獨在城。貧居深穩臥，晚學愛閑名。", "小弟有書至，異鄉無地行。悲歡相並起，何處說心情。"]'),
('yuding-38','病僧','姚合','唐','御定全唐诗','yuding','','[]','三年病不出，苔蘚滿藤鞋。倚壁看經坐，聞鐘吃藥齋。',48,'御定全唐詩/json/502.json','["三年病不出，苔蘚滿藤鞋。倚壁看經坐，聞鐘吃藥齋。", "茶煙熏殺竹，簷雨滴穿階。無暇頻相訪，秋風寂寞懷。"]'),
('yuding-39','成名後留別從兄','姚合','唐','御定全唐诗','yuding','','[]','一辭山舍廢躬耕，無事悠悠住帝城。為客衣裳多不穩，',40,'御定全唐詩/json/502.json','["一辭山舍廢躬耕，無事悠悠住帝城。為客衣裳多不穩，", "卻出關東悲複喜，歸尋弟妹別仁兄。"]'),
('yuding-40','佛舍見鬍子有嘲','姚合','唐','御定全唐诗','yuding','','[]','明明複夜夜，鬍子即成翁。唯是真知性，不來生滅中。',24,'御定全唐詩/json/502.json','["明明複夜夜，鬍子即成翁。唯是真知性，不來生滅中。"]'),
('yuding-41','白鼻騧','姚合','唐','御定全唐诗','yuding','','[]','為底胡姬酒，長來白鼻騧。摘蓮拋水上，郎意在浮花。',24,'御定全唐詩/json/502.json','["為底胡姬酒，長來白鼻騧。摘蓮拋水上，郎意在浮花。"]'),
('yuding-42','崔少卿鶴','姚合','唐','御定全唐诗','yuding','','[]','入門石徑半高低，閑處無非是藥畦。',32,'御定全唐詩/json/502.json','["入門石徑半高低，閑處無非是藥畦。", "致得仙禽無去意，花間舞罷洞中棲。"]'),
('yuding-43','新昌裏','姚合','唐','御定全唐诗','yuding','','[]','舊客常樂坊，井泉濁而鹹。新屋新昌裏，井泉清而甘。',96,'御定全唐詩/json/502.json','["舊客常樂坊，井泉濁而鹹。新屋新昌裏，井泉清而甘。", "僮僕慣苦飲，食美翻憎嫌。朝朝忍饑行，戚戚如難堪。", "中下無正性，所習便淫耽。一染不可變，甚于茜與藍。", "近貧日益廉，近富日益貪。以此當自警，慎勿信邪讒。"]'),
('yuding-44','塞下曲','姚合','唐','御定全唐诗','yuding','','[]','磧露黃雲下，凝寒鼓不鳴。戰須移死地，軍諱殺降兵。',48,'御定全唐詩/json/502.json','["磧露黃雲下，凝寒鼓不鳴。戰須移死地，軍諱殺降兵。", "印馬秋遮虜，蒸沙夜築城。舊鄉歸不得，都尉負功名。"]'),
('yuding-45','從軍行','姚合','唐','御定全唐诗','yuding','','[]','濫得進士名，才用苦不長。性癖藝亦獨，十年作詩章。',144,'御定全唐詩/json/502.json','["濫得進士名，才用苦不長。性癖藝亦獨，十年作詩章。", "六義雖粗成，名字猶未揚。將軍俯招引，遣脫儒衣裳。", "常恐虛受恩，不慣把刀槍。又無遠籌略，坐使虜滅亡。", "昨來發兵師，各各赴戰場。顧我同老弱，不得隨戎行。", "丈夫生世間，職分貴所當。從軍不出門，豈異病在床。", "誰不戀其家，其家無風霜。鷹鶻念搏擊，豈貴食滿腸。"]'),
('yuding-46','杏園','姚合','唐','御定全唐诗','yuding','','[]','江頭數頃杏花開，車馬爭先盡此來。',32,'御定全唐詩/json/502.json','["江頭數頃杏花開，車馬爭先盡此來。", "欲待無人連夜看，黃昏樹樹滿塵埃。"]'),
('yuding-47','閒居','姚合','唐','御定全唐诗','yuding','','[]','日日門長閉，憐家亦懶過。頭風春飲苦，眼暈夜書多。',48,'御定全唐詩/json/502.json','["日日門長閉，憐家亦懶過。頭風春飲苦，眼暈夜書多。", "幽鳥偏棲竹，凡人笑種莎。近來難得酒，無計奈愁何。"]'),
('yuding-48','句','姚合','唐','御定全唐诗','yuding','','[]','天遙來雁小，江闊去帆孤。',76,'御定全唐詩/json/502.json','["天遙來雁小，江闊去帆孤。", "南陌遊人回首去，東林道者杖藜歸。", "萄藤洞庭頭，引葉漾盈搖。皎潔鉤高掛，玲瓏影落寮。", "陰煙壓幽屋，蒙密夢冥苗。清秋青且翠，冬到凍都凋。"]'),
('yuding-0','留辭杭州姚合郎中','周賀','唐','御定全唐诗','yuding','','[]','波濤千里隔，抱疾亦相尋。會宿逢高士，辭歸值積霖。',48,'御定全唐詩/json/503.json','["波濤千里隔，抱疾亦相尋。會宿逢高士，辭歸值積霖。", "叢桑山店迥，孤燭海船深。尚有重來約，知無省閣心。"]'),
('yuding-1','酬吳之問見贈','周賀','唐','御定全唐诗','yuding','','[]','已當鳴雁夜，多事不同居。故疾離城晚，秋霖見月疏。',48,'御定全唐詩/json/503.json','["已當鳴雁夜，多事不同居。故疾離城晚，秋霖見月疏。", "趁風開靜戶，帶葉卷殘書。蕩槳期南去，荒園久廢鋤。"]'),
('yuding-2','送分定歸靈夏','周賀','唐','御定全唐诗','yuding','','[]','南遊多老病，見說講經稀。塞寺幾僧在，關城空自歸。',48,'御定全唐詩/json/503.json','["南遊多老病，見說講經稀。塞寺幾僧在，關城空自歸。", "帶河衰草斷，映日旱沙飛。卻到禪齋後，邊軍識衲衣。"]'),
('yuding-3','與崔弇話別','周賀','唐','御定全唐诗','yuding','','[]','歸思緣平澤，幽齋夜話遲。人尋馮翊去，草向建康衰。',48,'御定全唐詩/json/503.json','["歸思緣平澤，幽齋夜話遲。人尋馮翊去，草向建康衰。", "雨雪生中路，干戈阻後期。幾年方見面，應是鑷蒼髭。"]'),
('yuding-4','題何氏池亭','周賀','唐','御定全唐诗','yuding','','[]','信是虛閑地，亭高亦有苔。繞池逢石坐，穿竹引山回。',48,'御定全唐詩/json/503.json','["信是虛閑地，亭高亦有苔。繞池逢石坐，穿竹引山回。", "果落纖萍散，龜行細草開。主人偏好事，終不厭頻來。"]'),
('yuding-5','送表兄東南游','周賀','唐','御定全唐诗','yuding','','[]','山水疊層層，吾兄涉又登。掛帆春背雁，尋磬夜逢僧。',48,'御定全唐詩/json/503.json','["山水疊層層，吾兄涉又登。掛帆春背雁，尋磬夜逢僧。", "雪溜懸衡岳，江雲蓋秣陵。評文永不忘，此說是中興。"]'),
('yuding-6','送康紹歸建業','周賀','唐','御定全唐诗','yuding','','[]','南朝秋色滿，君去意如何。帝業空城在，民田壞塚多。',48,'御定全唐詩/json/503.json','["南朝秋色滿，君去意如何。帝業空城在，民田壞塚多。", "月圓臺獨上，栗綻寺頻過。籬下西江闊，相思見白波。"]'),
('yuding-7','再過王輅原居納涼','周賀','唐','御定全唐诗','yuding','','[]','夏天多憶此，早晚得秋分。舊月來還見，新蟬坐忽聞。',48,'御定全唐詩/json/503.json','["夏天多憶此，早晚得秋分。舊月來還見，新蟬坐忽聞。", "扇風調病葉，溝水隔殘雲。別有微涼處，從容不似君。"]'),
('yuding-8','送耿山人歸湖南','周賀','唐','御定全唐诗','yuding','','[]','南行隨越僧，別業幾池菱。兩鬢已垂白，五湖歸掛罾。',48,'御定全唐詩/json/503.json','["南行隨越僧，別業幾池菱。兩鬢已垂白，五湖歸掛罾。", "夜濤鳴柵鎖，寒葦露船燈。去此應無事，卻來知不能。"]'),
('yuding-9','送省己上人歸太原','周賀','唐','御定全唐诗','yuding','','[]','惜別聽邊漏，窗燈落燼重。寒僧回絕塞，夕雪下窮冬。',48,'御定全唐詩/json/503.json','["惜別聽邊漏，窗燈落燼重。寒僧回絕塞，夕雪下窮冬。", "出定聞殘角，休兵見壞鋒。何年更來此，老卻倚階松。"]'),
('yuding-10','宿甄山南溪晝公院','周賀','唐','御定全唐诗','yuding','','[]','從作兩河客，別離經半年。卻來峰頂宿，知廢甄南禪。',48,'御定全唐詩/json/503.json','["從作兩河客，別離經半年。卻來峰頂宿，知廢甄南禪。", "餘霧沉斜月，孤燈照落泉。何當閒事盡，相伴老溪邊。"]'),
('yuding-11','相次尋舉客寄住人','周賀','唐','御定全唐诗','yuding','','[]','停橈因舊識，白髮向波濤。以我往來倦，知君耕稼勞。',48,'御定全唐詩/json/503.json','["停橈因舊識，白髮向波濤。以我往來倦，知君耕稼勞。", "渚田臨舍盡，阪路出簷高。游者還南去，終期伴爾曹。"]'),
('yuding-12','出關寄賈島','周賀','唐','御定全唐诗','yuding','','[]','舊鄉無子孫，誰共老青門。迢遞早秋路，別離深夜村。',48,'御定全唐詩/json/503.json','["舊鄉無子孫，誰共老青門。迢遞早秋路，別離深夜村。", "伊流偕行客，嶽響答啼猿。去後期招隱，何當複此言。"]'),
('yuding-13','暮冬長安旅舍','周賀','唐','御定全唐诗','yuding','','[]','湖外誰相識，思歸日日頻。遍尋新住客，少見故鄉人。',48,'御定全唐詩/json/503.json','["湖外誰相識，思歸日日頻。遍尋新住客，少見故鄉人。", "失計空知命，勞生恥為身。惟看洞庭樹，即是舊山春。"]'),
('yuding-14','贈胡僧','周賀','唐','御定全唐诗','yuding','','[]','瘦形無血色，草屨著行穿。閒話似持咒，不眠同坐禪。',48,'御定全唐詩/json/503.json','["瘦形無血色，草屨著行穿。閒話似持咒，不眠同坐禪。", "背經來漢地，袒膊過冬天。情性人難會，游方應信緣。"]'),
('yuding-15','贈李主簿','周賀','唐','御定全唐诗','yuding','','[]','稅時兼主印，每日得閒稀。對酒妨料吏，為官亦典衣。',48,'御定全唐詩/json/503.json','["稅時兼主印，每日得閒稀。對酒妨料吏，為官亦典衣。", "案遲吟坐待，宅近步行歸。見說論詩道，應愁判是非。"]'),
('yuding-16','同朱慶餘宿翊西上人房','周賀','唐','御定全唐诗','yuding','','[]','溪僧還共謁，相與坐寒天。屋雪淩高燭，山茶稱遠泉。',48,'御定全唐詩/json/503.json','["溪僧還共謁，相與坐寒天。屋雪淩高燭，山茶稱遠泉。", "夜清更徹寺，空闊雁沖煙。莫怪多時話，重來又來年。"]'),
('yuding-17','寄姚合郎中','周賀','唐','御定全唐诗','yuding','','[]','轉刺名山郡，連年別省曹。分題得客少，著價買書高。',48,'御定全唐詩/json/503.json','["轉刺名山郡，連年別省曹。分題得客少，著價買書高。", "晚柳蟬和角，寒城燭照濤。鄱溪臥疾久，未獲後乘騷。"]'),
('yuding-18','休糧僧','周賀','唐','御定全唐诗','yuding','','[]','一齋難過日，況是更休糧。養力時行道，聞鐘不上堂。',48,'御定全唐詩/json/503.json','["一齋難過日，況是更休糧。養力時行道，聞鐘不上堂。", "唯留溫藥火，未寫化金方。舊有山廚在，從僧請作房。"]'),
('yuding-19','懷西峰隱者','周賀','唐','御定全唐诗','yuding','','[]','灌木藏岑色，天寒望即愁。高齋何日去，遠瀑入城流。',48,'御定全唐詩/json/503.json','["灌木藏岑色，天寒望即愁。高齋何日去，遠瀑入城流。", "臘近溪書絕，燈殘夜雪稠。邇來相憶處，枕上苦吟休。"]'),
('yuding-20','贈柏岩禪師','周賀','唐','御定全唐诗','yuding','','[]','野寺絕依念，靈山會遍行。老來披衲重，病後讀經生。',48,'御定全唐詩/json/503.json','["野寺絕依念，靈山會遍行。老來披衲重，病後讀經生。", "乞食嫌村遠，尋溪愛路平。多年柏岩住，不記柏岩名。"]'),
('yuding-21','旅懷','周賀','唐','御定全唐诗','yuding','','[]','不覺月又盡，未歸還到春。雪通廬嶽夢，樹匝草堂身。',48,'御定全唐詩/json/503.json','["不覺月又盡，未歸還到春。雪通廬嶽夢，樹匝草堂身。", "澤雁和寒露，江槎帶遠薪。何年自此去，舊國複為鄰。"]'),
('yuding-22','緱氏韋明府廳','周賀','唐','御定全唐诗','yuding','','[]','貴邑清風滿，誰同上宰心。杉松出郭外，雨電下嵩陰。',48,'御定全唐詩/json/503.json','["貴邑清風滿，誰同上宰心。杉松出郭外，雨電下嵩陰。", "度雁方離壘，來僧始別岑。西池月才迥，會接一宵吟。"]'),
('yuding-23','送朱慶餘','周賀','唐','御定全唐诗','yuding','','[]','野客行無定，全家在浦東。寄眠僧閣靜，贈別橐金空。',48,'御定全唐詩/json/503.json','["野客行無定，全家在浦東。寄眠僧閣靜，贈別橐金空。", "舊裏千山隔，歸舟百計同。藥資如有分，相約老吳中。"]'),
('yuding-24','宿開元寺樓','周賀','唐','御定全唐诗','yuding','','[]','西峰殘日落，誰見寂寥心。孤枕客眠久，兩廊僧話深。',48,'御定全唐詩/json/503.json','["西峰殘日落，誰見寂寥心。孤枕客眠久，兩廊僧話深。", "寒扉關雨氣，風葉隱鐘音。此愛東樓望，仍期別夜尋。"]'),
('yuding-25','送僧還南嶽','周賀','唐','御定全唐诗','yuding','','[]','辭僧下水柵，因夢嶽鐘聲。遠路獨歸寺，幾時重到城。',48,'御定全唐詩/json/503.json','["辭僧下水柵，因夢嶽鐘聲。遠路獨歸寺，幾時重到城。", "風高寒葉落，雨絕夜堂清。自說深居後，鄰州亦不行。"]'),
('yuding-26','秋思','周賀','唐','御定全唐诗','yuding','','[]','楊柳已秋思，楚田仍刈禾。歸心病起切，敗葉夜來多。',48,'御定全唐詩/json/503.json','["楊柳已秋思，楚田仍刈禾。歸心病起切，敗葉夜來多。", "細雨城蟬噪，殘陽嶠客過。舊山餘業在，杳隔洞庭波。"]'),
('yuding-27','旅情','周賀','唐','御定全唐诗','yuding','','[]','黃葉下階頻，徐徐起病身。殘秋螢出盡，獨夜雁來新。',48,'御定全唐詩/json/503.json','["黃葉下階頻，徐徐起病身。殘秋螢出盡，獨夜雁來新。", "別業去千里，舊鄉空四鄰。孤舟尋幾度，又識岳陽人。"]'),
('yuding-28','送靈應禪師','周賀','唐','御定全唐诗','yuding','','[]','寒天仍遠去，離寺雪霏霏。古跡曾重到，生涯不暫歸。',48,'御定全唐詩/json/503.json','["寒天仍遠去，離寺雪霏霏。古跡曾重到，生涯不暫歸。", "坐禪山店暝，補衲夜燈微。巡禮何時住，相逢的是稀。"]'),
('yuding-29','送陸判官防秋','周賀','唐','御定全唐诗','yuding','','[]','匹馬無窮地，三年逐大軍。算程淮邑遠，起帳夕陽曛。',48,'御定全唐詩/json/503.json','["匹馬無窮地，三年逐大軍。算程淮邑遠，起帳夕陽曛。", "瀑浪行時漱，邊笳語次聞。要傳書劄去，應到磧東雲。"]'),
('yuding-30','山居秋思','周賀','唐','御定全唐诗','yuding','','[]','一從雲水住，曾不下西岑。落木孤猿在，秋庭積霧深。',48,'御定全唐詩/json/503.json','["一從雲水住，曾不下西岑。落木孤猿在，秋庭積霧深。", "泉流通井脈，蟲響出牆陰。夜靜溪聲徹，寒燈尚獨吟。"]'),
('yuding-31','贈皎然上人','周賀','唐','御定全唐诗','yuding','','[]','竹庭瓶水新，深稱北窗人。講罷見黃葉，詩成尋舊鄰。',48,'御定全唐詩/json/503.json','["竹庭瓶水新，深稱北窗人。講罷見黃葉，詩成尋舊鄰。", "錫陰迷坐石，池影露齋身。苦作南行約，勞生始問津。"]'),
('yuding-32','春日山居寄友人','周賀','唐','御定全唐诗','yuding','','[]','春居無俗喧，時立澗前村。路遠少來客，山深多過猿。',48,'御定全唐詩/json/503.json','["春居無俗喧，時立澗前村。路遠少來客，山深多過猿。", "帶岩松色老，臨水杏花繁。除憶文流外，何人更可言。"]'),
('yuding-33','留別南徐故人','周賀','唐','御定全唐诗','yuding','','[]','三年蒙見待，此夕是前程。未斷卻來約，且伸臨去情。',48,'御定全唐詩/json/503.json','["三年蒙見待，此夕是前程。未斷卻來約，且伸臨去情。", "潮回灘鳥下，月上客船明。他日南徐道，緣君又重行。"]'),
('yuding-34','送僧歸江南','周賀','唐','御定全唐诗','yuding','','[]','洗足北林去，遠途今已分。麻衣行嶽色，竹杖帶湘雲。',48,'御定全唐詩/json/503.json','["洗足北林去，遠途今已分。麻衣行嶽色，竹杖帶湘雲。", "饑鼠緣危壁，寒狸出壞墳。前峰一聲磬，此夕不同聞。"]'),
('yuding-35','早春越中留故人','周賀','唐','御定全唐诗','yuding','','[]','此行經歲近，唯約半年回。野渡人初過，前山雲未開。',48,'御定全唐詩/json/503.json','["此行經歲近，唯約半年回。野渡人初過，前山雲未開。", "雁群逢曉斷，林色映川來。清夜蘆中客，嚴家舊釣台。"]'),
('yuding-36','送友人','周賀','唐','御定全唐诗','yuding','','[]','彈琴多去情，浮楫背潮行。人望豐壖宿，蟲依蠹木鳴。',48,'御定全唐詩/json/503.json','["彈琴多去情，浮楫背潮行。人望豐壖宿，蟲依蠹木鳴。", "檣煙離浦色，蘆雨入船聲。如疾登雲路，憑君寄此生。"]'),
('yuding-37','春日重到王依村居','周賀','唐','御定全唐诗','yuding','','[]','野煙居舍在，曾約此重過。久雨初招客，新田未種禾。',48,'御定全唐詩/json/503.json','["野煙居舍在，曾約此重過。久雨初招客，新田未種禾。", "夜蟲鳴井浪，春鳥宿庭柯。莫為兒孫役，餘生能幾何。"]'),
('yuding-38','入靜隱寺途中作','周賀','唐','御定全唐诗','yuding','','[]','亂雲迷遠寺，入路認青松。鳥道緣巢影，僧鞋印雪蹤。',48,'御定全唐詩/json/503.json','["亂雲迷遠寺，入路認青松。鳥道緣巢影，僧鞋印雪蹤。", "草煙連野燒，溪霧隔霜鐘。更遇樵人問，猶言過數峰。"]'),
('yuding-39','送楊岳歸巴陵','周賀','唐','御定全唐诗','yuding','','[]','何處得鄉信，告行當雨天。人離京口日，潮送岳陽船。',48,'御定全唐詩/json/503.json','["何處得鄉信，告行當雨天。人離京口日，潮送岳陽船。", "孤鳥背林色，遠帆開浦煙。悲君唯此別，不肯話回年。"]'),
('yuding-40','贈朱慶餘校書','周賀','唐','御定全唐诗','yuding','','[]','風泉盡結冰，寒夢徹西陵。越信楚城得，遠懷中夜興。',48,'御定全唐詩/json/503.json','["風泉盡結冰，寒夢徹西陵。越信楚城得，遠懷中夜興。", "樹停沙島鶴，茶會石橋僧。寺閣邊官舍，行吟過幾層。"]'),
('yuding-41','逢播公','周賀','唐','御定全唐诗','yuding','','[]','帶病希相見，西城早晚來。衲衣風壞帛，香印雨沾灰。',48,'御定全唐詩/json/503.json','["帶病希相見，西城早晚來。衲衣風壞帛，香印雨沾灰。", "坐久鐘聲盡，談餘嶽影回。卻思同宿夜，高枕說天臺。"]'),
('yuding-42','尋北岡韓處士','周賀','唐','御定全唐诗','yuding','','[]','相過值早涼，松帚掃山床。坐石泉痕黑，登城蘚色黃。',48,'御定全唐詩/json/503.json','["相過值早涼，松帚掃山床。坐石泉痕黑，登城蘚色黃。", "逆風沈寺磬，初日曬鄰桑。幾處逢僧說，期來宿北岡。"]'),
('yuding-43','哭閑霄上人','周賀','唐','御定全唐诗','yuding','','[]','林徑西風急，松枝講鈔餘。凍髭亡夜剃，遺偈病時書。',48,'御定全唐詩/json/503.json','["林徑西風急，松枝講鈔餘。凍髭亡夜剃，遺偈病時書。", "地燥焚身後，堂空著影初。吊來頻落淚，曾憶到吾廬。"]'),
('yuding-44','城中秋作','周賀','唐','御定全唐诗','yuding','','[]','已落關東葉，空懸浙右心。寒燈隨故病，伏雨接秋霖。',48,'御定全唐詩/json/503.json','["已落關東葉，空懸浙右心。寒燈隨故病，伏雨接秋霖。", "客話曾誰和，蟲聲少我吟。蒹葭半波水，夜夜宿邊禽。"]'),
('yuding-45','玉芝觀王道士','周賀','唐','御定全唐诗','yuding','','[]','四面杉蘿合，空堂畫老仙。蠹根停雪水，曲角積茶煙。',48,'御定全唐詩/json/503.json','["四面杉蘿合，空堂畫老仙。蠹根停雪水，曲角積茶煙。", "道至心極盡，宵晴瑟韻全。暫來還又去，未得坐經年。"]'),
('yuding-46','出關後寄賈島','周賀','唐','御定全唐诗','yuding','','[]','故國知何處，西風已度關。歸人值落葉，遠路入寒山。',48,'御定全唐詩/json/503.json','["故國知何處，西風已度關。歸人值落葉，遠路入寒山。", "多難喜相識，久貧寧自閑。唯將往來信，遙慰別離顏。"]'),
('yuding-47','題晝公院','周賀','唐','御定全唐诗','yuding','','[]','叢木開風徑，過從白晝寒。舍深原草合，茶疾竹薪幹。',48,'御定全唐詩/json/503.json','["叢木開風徑，過從白晝寒。舍深原草合，茶疾竹薪幹。", "夕雨生眠興，禪心少話端。頻來覺無事，盡日坐相看。"]'),
('yuding-48','京口贈崔固','周賀','唐','御定全唐诗','yuding','','[]','積雨晴時近，西風葉滿泉。相逢嵩嶽客，共聽楚城蟬。',48,'御定全唐詩/json/503.json','["積雨晴時近，西風葉滿泉。相逢嵩嶽客，共聽楚城蟬。", "宿館橫秋島，歸帆漲遠田。別多還寂寞，不似剡中年。"]'),
('yuding-49','書實上人房','周賀','唐','御定全唐诗','yuding','','[]','絕頂言無伴，長懷剃發師。禪中燈落燼，講次柏生枝。',48,'御定全唐詩/json/503.json','["絕頂言無伴，長懷剃發師。禪中燈落燼，講次柏生枝。", "沙井泉澄疾，秋鐘韻盡遲。裏閭還受請，空有向南期。"]'),
('yuding-50','送張諲之睦州','周賀','唐','御定全唐诗','yuding','','[]','遙憶新安舊，扁舟往復還。淺深看水石，來往逐雲山。',48,'御定全唐詩/json/503.json','["遙憶新安舊，扁舟往復還。淺深看水石，來往逐雲山。", "到縣餘花在，過門五柳閑。東征隨子去，俱隱薜蘿間。"]'),
('yuding-51','贈王道士','周賀','唐','御定全唐诗','yuding','','[]','藥力資蒼鬢，應非舊日身。一為嵩嶽客，幾葬洛陽人。',48,'御定全唐詩/json/503.json','["藥力資蒼鬢，應非舊日身。一為嵩嶽客，幾葬洛陽人。", "石縫瓢探水，雲根斧斫薪。關西來往路，誰得水銀銀。"]'),
('yuding-52','冬日山居思鄉','周賀','唐','御定全唐诗','yuding','','[]','大野始嚴凝，雲天曉色澄。樹寒稀宿鳥，山迥少來僧。',48,'御定全唐詩/json/503.json','["大野始嚴凝，雲天曉色澄。樹寒稀宿鳥，山迥少來僧。", "背日收窗雪，開爐釋硯冰。忽然歸故國，孤想寓西陵。"]'),
('yuding-53','如空上人移居大雲寺','周賀','唐','御定全唐诗','yuding','','[]','竹溪人請住，何日向中峰。瓦舍山情少，齋身疾色濃。',48,'御定全唐詩/json/503.json','["竹溪人請住，何日向中峰。瓦舍山情少，齋身疾色濃。", "夏高移坐次，菊淺露行蹤。來往湓城下，三年兩度逢。"]'),
('yuding-54','送幻群法師','周賀','唐','御定全唐诗','yuding','','[]','北京一別後，吳楚幾聽砧。住久白髮出，講長枯葉深。',48,'御定全唐詩/json/503.json','["北京一別後，吳楚幾聽砧。住久白髮出，講長枯葉深。", "香連鄰舍像，磬徹遠巢禽。寂默應關道，何人見此心。"]'),
('yuding-55','春喜友人至山舍','周賀','唐','御定全唐诗','yuding','','[]','鳥鳴春日曉，喜見竹門開。路自高岩出，人騎大馬來。',48,'御定全唐詩/json/503.json','["鳥鳴春日曉，喜見竹門開。路自高岩出，人騎大馬來。", "折花林影斷，移石洞陰回。更欲留深語，重城暮色催。"]'),
('yuding-56','春日重至南徐舊居','周賀','唐','御定全唐诗','yuding','','[]','綠水陰空院，春深喜再來。獨眠從草長，留酒看花開。',48,'御定全唐詩/json/503.json','["綠水陰空院，春深喜再來。獨眠從草長，留酒看花開。", "過雨還山出，向風孤鳥回。忽思秋夕事，雲物卻悠哉。"]'),
('yuding-57','早秋過郭涯書堂','周賀','唐','御定全唐诗','yuding','','[]','暑消岡舍清，閑語有餘情。澗水生茶味，松風滅扇聲。',48,'御定全唐詩/json/503.json','["暑消岡舍清，閑語有餘情。澗水生茶味，松風滅扇聲。", "遠分臨海雨，靜覺掩山城。此地秋吟苦，時來繞菊行。"]'),
('yuding-58','長安送人','周賀','唐','御定全唐诗','yuding','','[]','上國多離別，年年渭水濱。空將未歸意，說向欲行人。',48,'御定全唐詩/json/503.json','["上國多離別，年年渭水濱。空將未歸意，說向欲行人。", "雁度池塘月，山連井邑春。臨岐惜分手，日暮一沾巾。"]'),
('yuding-59','寄甯海李明府','周賀','唐','御定全唐诗','yuding','','[]','山縣風光異，公門水石清。一官居外府，幾載別東京。',96,'御定全唐詩/json/503.json','["山縣風光異，公門水石清。一官居外府，幾載別東京。", "故疾梅天發，新詩雪夜成。家貧思減選，時靜憶歸耕。", "把疏尋書義，澄心得獄情。夢靈邀客解，劍古揀人呈。", "守月通宵坐，尋花迥路行。從來愛知道，何慮白髭生。"]'),
('yuding-60','投江州張郎中','周賀','唐','御定全唐诗','yuding','','[]','要地無閑日，仍容冒謁頻。借山年涉閏，寢郡月逾旬。',96,'御定全唐詩/json/503.json','["要地無閑日，仍容冒謁頻。借山年涉閏，寢郡月逾旬。", "驛徑曾沖雪，方泉省滌塵。隨行溪路細，接話草堂新。", "減藥痊餘癖，飛書苦問貧。噪蟬離宿殼，吟客寄秋身。", "煉句貽箱篋，懸圖見蜀岷。使君匡嶽近，終作社中人。"]'),
('yuding-61','晚題江館','周賀','唐','御定全唐诗','yuding','','[]','病寄曲江居帶城，傍門孤柳一蟬鳴。澄波月上見魚擲，',40,'御定全唐詩/json/503.json','["病寄曲江居帶城，傍門孤柳一蟬鳴。澄波月上見魚擲，", "故園盡賣休官去，潮水秋來空自平。"]'),
('yuding-62','秋晚歸廬山留別道友','周賀','唐','御定全唐诗','yuding','','[]','病起陵陽思翠微，秋風動後著行衣。月生石齒人同見，',40,'御定全唐詩/json/503.json','["病起陵陽思翠微，秋風動後著行衣。月生石齒人同見，", "不嫌舊隱相隨去，廬嶽臨天好息機。"]'),
('yuding-63','同徐處士秋懷少室舊居','周賀','唐','御定全唐诗','yuding','','[]','曾居少室黃河畔，秋夢長懸未得回。扶病半年離水石，',40,'御定全唐詩/json/503.json','["曾居少室黃河畔，秋夢長懸未得回。扶病半年離水石，", "燈下此心誰共說，傍松幽徑已多栽。"]'),
('yuding-64','贈神遘上人','周賀','唐','御定全唐诗','yuding','','[]','草履蒲團山意存，坐看庭木長桐孫。行齋罷講仍香氣，',40,'御定全唐詩/json/503.json','["草履蒲團山意存，坐看庭木長桐孫。行齋罷講仍香氣，", "道情淡薄閒愁盡，霜色何因入鬢根。"]'),
('yuding-65','贈道人','周賀','唐','御定全唐诗','yuding','','[]','布褐高眠石竇春，迸泉多濺黑紗巾。搖頭說易當朝客，',40,'御定全唐詩/json/503.json','["布褐高眠石竇春，迸泉多濺黑紗巾。搖頭說易當朝客，", "擬歸太華何時去，他日相尋乞藥銀。"]'),
('yuding-66','贈厲玄侍禦','周賀','唐','御定全唐诗','yuding','','[]','山松徑與瀑泉通，巾舄行吟想越中。塞雁去經華頂末，',40,'御定全唐詩/json/503.json','["山松徑與瀑泉通，巾舄行吟想越中。塞雁去經華頂末，", "抱疾因尋周柱史，杜陵寒葉落無窮。"]'),
('yuding-67','送韓評事','周賀','唐','御定全唐诗','yuding','','[]','門枕平湖秋景好，水煙松色遠相依。罷官餘俸租田種，',40,'御定全唐詩/json/503.json','["門枕平湖秋景好，水煙松色遠相依。罷官餘俸租田種，", "嵩陽舊隱多時別，閉目閑吟憶翠微。"]'),
('yuding-68','宿隱靜寺上人','周賀','唐','御定全唐诗','yuding','','[]','一宿五峰杯度寺，虛廊中夜磬聲分。疏林未落上方月，',40,'御定全唐詩/json/503.json','["一宿五峰杯度寺，虛廊中夜磬聲分。疏林未落上方月，", "暫來此地歇勞足，望斷故山滄海濆。"]'),
('yuding-69','寄新頭陀','周賀','唐','御定全唐诗','yuding','','[]','見說北京尋祖後，瓶盂自挈繞窮邊。相逢竹塢晦暝夜，',40,'御定全唐詩/json/503.json','["見說北京尋祖後，瓶盂自挈繞窮邊。相逢竹塢晦暝夜，", "青城不得師同住，坐想滄江憶浩然。"]'),
('yuding-70','湘漢旅懷翁傑','周賀','唐','御定全唐诗','yuding','','[]','一宿空江聽急流，仍同賈客坐歸舟。遠書來隔巴陵雨，',40,'御定全唐詩/json/503.json','["一宿空江聽急流，仍同賈客坐歸舟。遠書來隔巴陵雨，", "吾宗尚作無憀者，中夜閑吟生旅愁。"]'),
('yuding-71','寄韓司兵','周賀','唐','御定全唐诗','yuding','','[]','多病十年無舊識，滄州亂後只逢君。已知罷秩辭瀧水，',40,'御定全唐詩/json/503.json','["多病十年無舊識，滄州亂後只逢君。已知罷秩辭瀧水，", "若為此別終期老，書劄何因寄北軍。"]'),
('yuding-72','寺居寄楊侍禦','周賀','唐','御定全唐诗','yuding','','[]','雨過北林空晚涼，院閒人去掩斜陽。十年多病度落葉，',40,'御定全唐詩/json/503.json','["雨過北林空晚涼，院閒人去掩斜陽。十年多病度落葉，", "還知謝客名先重，肯為詩篇問楚狂。"]'),
('yuding-73','上陝府姚中丞','周賀','唐','御定全唐诗','yuding','','[]','此心長愛狎禽魚，仍候登封獨著書。領郡只嫌生藥少，',40,'御定全唐詩/json/503.json','["此心長愛狎禽魚，仍候登封獨著書。領郡只嫌生藥少，", "見說養真求退靜，溪南泉石許同居。"]'),
('yuding-74','贈僧','周賀','唐','御定全唐诗','yuding','','[]','藩府十年為律業，南朝本寺往來新。辭歸幾別深山客，',40,'御定全唐詩/json/503.json','["藩府十年為律業，南朝本寺往來新。辭歸幾別深山客，", "他年更息登壇計，應與雲泉作四鄰。"]'),
('yuding-75','送石協律歸吳','周賀','唐','御定全唐诗','yuding','','[]','僧窗夢後憶歸耕，水涉應多半月程。幕府罷來無藥價，',40,'御定全唐詩/json/503.json','["僧窗夢後憶歸耕，水涉應多半月程。幕府罷來無藥價，", "已讓辟書稱抱疾，滄洲便許白髭生。"]'),
('yuding-76','寄金陵僧','周賀','唐','御定全唐诗','yuding','','[]','水石致身閑自得，平雲竹閣少炎蒸。齋床幾減供禽食，',40,'御定全唐詩/json/503.json','["水石致身閑自得，平雲竹閣少炎蒸。齋床幾減供禽食，", "行登總到諸山寺，坐聽蟬聲滿四棱。"]'),
('yuding-77','送忍禪師歸廬岳','周賀','唐','御定全唐诗','yuding','','[]','浪匝湓城嶽壁青，白頭僧去掃禪扃。龕燈度雪補殘衲，',40,'御定全唐詩/json/503.json','["浪匝湓城嶽壁青，白頭僧去掃禪扃。龕燈度雪補殘衲，", "已知身事非吾道，甘臥荒齋竹滿庭。"]'),
('yuding-78','贈姚合郎中','周賀','唐','御定全唐诗','yuding','','[]','望重來為守土臣，清高還似武功貧。道從會解唯求靜，',40,'御定全唐詩/json/503.json','["望重來為守土臣，清高還似武功貧。道從會解唯求靜，", "兩衙向後長無事，門館多逢請益人。"]'),
('yuding-79','宿李主簿','周賀','唐','御定全唐诗','yuding','','[]','獨樹倚亭新月入，城牆四面鎖山多。',32,'御定全唐詩/json/503.json','["獨樹倚亭新月入，城牆四面鎖山多。", "去年今夜還來此，坐見西風嫋鵲窠。"]'),
('yuding-80','寄潘緯','周賀','唐','御定全唐诗','yuding','','[]','楊柳垂絲與地連，歸來一醉向溪邊。',32,'御定全唐詩/json/503.json','["楊柳垂絲與地連，歸來一醉向溪邊。", "相逢頭白莫惆悵，世上無人長少年。"]'),
('yuding-81','潯陽與孫郎中宴回','周賀','唐','御定全唐诗','yuding','','[]','別酒已酣春漏前，他人扶上北歸船。',32,'御定全唐詩/json/503.json','["別酒已酣春漏前，他人扶上北歸船。", "潯陽渡口月未上，漁火照江仍獨眠。"]'),
('yuding-82','送宗禪師','周賀','唐','御定全唐诗','yuding','','[]','衡陽到卻十三春，行腳同來有幾人。',32,'御定全唐詩/json/503.json','["衡陽到卻十三春，行腳同來有幾人。", "老大又思歸嶽裏，當時來漆祖師身。"]'),
('yuding-83','送僧','周賀','唐','御定全唐诗','yuding','','[]','草履初登南客船，銅瓶猶貯北山泉。',32,'御定全唐詩/json/503.json','["草履初登南客船，銅瓶猶貯北山泉。", "衡陽舊寺秋歸去，門鎖寒潭幾樹蟬。"]'),
('yuding-84','送蜀僧','周賀','唐','御定全唐诗','yuding','','[]','萬里獨行無弟子，惟齎筇竹與檀龕。',32,'御定全唐詩/json/503.json','["萬里獨行無弟子，惟齎筇竹與檀龕。", "看經更向吳中老，應是山川似劍南。"]'),
('yuding-85','過僧竹院','周賀','唐','御定全唐诗','yuding','','[]','一生愛竹自未有，每到此房歸不能。',32,'御定全唐詩/json/503.json','["一生愛竹自未有，每到此房歸不能。", "高人留宿話禪後，寂寞雨堂空夜燈。"]'),
('yuding-86','憶潯陽舊居兼感長孫郎中','周賀','唐','御定全唐诗','yuding','','[]','潯陽卻到是何日，此地今無舊使君。',32,'御定全唐詩/json/503.json','["潯陽卻到是何日，此地今無舊使君。", "長憶窮冬宿廬嶽，瀑泉冰折共僧聞。"]'),
('yuding-87','送郭秀才歸金陵','周賀','唐','御定全唐诗','yuding','','[]','夏後客堂黃葉多，又懷家國起悲歌。酒前欲別語難盡，',40,'御定全唐詩/json/503.json','["夏後客堂黃葉多，又懷家國起悲歌。酒前欲別語難盡，", "南徐舊業幾時到，門掩殘陽積翠蘿。"]'),
('yuding-88','宿李樞書齋','周賀','唐','御定全唐诗','yuding','','[]','小齋經暮雨，四面絕纖埃。眠客聞風覺，飛蟲入燭來。',48,'御定全唐詩/json/503.json','["小齋經暮雨，四面絕纖埃。眠客聞風覺，飛蟲入燭來。", "夜涼書讀遍，月正戶全開。住遠稀相見，留連宿始回。"]'),
('yuding-89','杪秋登江樓','周賀','唐','御定全唐诗','yuding','','[]','平楚起寒色，長沙猶未還。世情何處淡，湘水向人閑。',48,'御定全唐詩/json/503.json','["平楚起寒色，長沙猶未還。世情何處淡，湘水向人閑。", "空翠隱高鳥，夕陽歸遠山。孤雲萬餘裏，惆悵洞庭間。"]'),
('yuding-90','秋宿洞庭','周賀','唐','御定全唐诗','yuding','','[]','洞庭初葉下，旅客不勝愁。明月天涯夜，青山江上秋。',48,'御定全唐詩/json/503.json','["洞庭初葉下，旅客不勝愁。明月天涯夜，青山江上秋。", "一官成白首，萬里寄滄洲。只被浮名系，甯無愧海鷗。"]'),
('yuding-91','重陽','周賀','唐','御定全唐诗','yuding','','[]','雲木疏黃秋滿川，茱萸風裏一樽前。幾回為客逢佳節，',40,'御定全唐詩/json/503.json','["雲木疏黃秋滿川，茱萸風裏一樽前。幾回為客逢佳節，", "古來醉樂皆難得，留取窮通委上天。"]'),
('yuding-92','送李億東歸','周賀','唐','御定全唐诗','yuding','','[]','黃山遠隔秦樹，紫禁斜通渭城。別路青青柳發，',35,'御定全唐詩/json/503.json','["黃山遠隔秦樹，紫禁斜通渭城。別路青青柳發，", "灞上金樽未飲，宴歌已有餘聲。"]'),
('yuding-0','泊靈溪館','鄭巢','唐','御定全唐诗','yuding','','[]','孤吟疏雨絕，荒館亂峰前。曉鷺棲危石，秋萍滿敗船。',48,'御定全唐詩/json/504.json','["孤吟疏雨絕，荒館亂峰前。曉鷺棲危石，秋萍滿敗船。", "溜從華頂落，樹與赤城連。已有求閑意，相期在暮年。"]'),
('yuding-1','瀑布寺貞上人院','鄭巢','唐','御定全唐诗','yuding','','[]','林疏多暮蟬，師去宿山煙。古壁燈熏畫，秋琴雨潤弦。',48,'御定全唐詩/json/504.json','["林疏多暮蟬，師去宿山煙。古壁燈熏畫，秋琴雨潤弦。", "竹間窺遠鶴，岩上取寒泉。西嶽沙房在，歸期更幾年。"]'),
('yuding-2','寄貞法師','鄭巢','唐','御定全唐诗','yuding','','[]','巡禮知難盡，幽人見亦稀。幾年潭上過，何待雪中歸。',48,'御定全唐詩/json/504.json','["巡禮知難盡，幽人見亦稀。幾年潭上過，何待雪中歸。", "遠瀑穿經室，寒螿發定衣。無因尋道者，獨坐對松扉。"]'),
('yuding-3','送靈溪李侍郎','鄭巢','唐','御定全唐诗','yuding','','[]','貂裘離闕下，初佐漢元勳。河偃流澌疊，沙晴遠樹分。',48,'御定全唐詩/json/504.json','["貂裘離闕下，初佐漢元勳。河偃流澌疊，沙晴遠樹分。", "牛羊下暮靄，鼓角調寒雲。中夕蕭關宿，邊聲不可聞。"]'),
('yuding-4','送姚郎中罷郡游越','鄭巢','唐','御定全唐诗','yuding','','[]','逍遙方罷郡，高興接東甌。幾處行杉徑，何時宿石樓。',48,'御定全唐詩/json/504.json','["逍遙方罷郡，高興接東甌。幾處行杉徑，何時宿石樓。", "湘聲穿古竇，華影在空舟。惆悵雲門路，無因得從遊。"]'),
('yuding-5','送魏校書赴夏口從事','鄭巢','唐','御定全唐诗','yuding','','[]','西風吹遠蟬，驛路在雲邊。獨夢諸山外，高談大旆前。',48,'御定全唐詩/json/504.json','["西風吹遠蟬，驛路在雲邊。獨夢諸山外，高談大旆前。", "夜燈分楚塞，秋角滿湘船。郡邑多岩竇，何方便學仙。"]'),
('yuding-6','送衡州薛從事','鄭巢','唐','御定全唐诗','yuding','','[]','吟去望雙旌，滄洲晚氣清。遙分高嶽色，亂出遠蟬聲。',48,'御定全唐詩/json/504.json','["吟去望雙旌，滄洲晚氣清。遙分高嶽色，亂出遠蟬聲。", "楚霽雲連寺，湘寒浪浸城。孤猿不可聽，一聽白髭生。"]'),
('yuding-7','送邊使','鄭巢','唐','御定全唐诗','yuding','','[]','關河度幾重，邊色上離容。灞水方為別，沙場又入冬。',48,'御定全唐詩/json/504.json','["關河度幾重，邊色上離容。灞水方為別，沙場又入冬。", "曙雕回大旆，夕雪沒前峰。漢使多長策，須令遠國從。"]'),
('yuding-8','送人赴舉','鄭巢','唐','御定全唐诗','yuding','','[]','篇章動玉京，墜葉滿前程。舊國與僧別，秋江罷釣行。',48,'御定全唐詩/json/504.json','["篇章動玉京，墜葉滿前程。舊國與僧別，秋江罷釣行。", "馬過隋代寺，檣出楚山城。應近嵩陽宿，潛聞瀑布聲。"]'),
('yuding-9','送袁肇歸山陰','鄭巢','唐','御定全唐诗','yuding','','[]','論文意有違，寒雨灑行衣。南渡久誰語，後吟今獨歸。',48,'御定全唐詩/json/504.json','["論文意有違，寒雨灑行衣。南渡久誰語，後吟今獨歸。", "河帆因樹落，沙鳥背潮飛。若值雲門侶，多因宿翠微。"]'),
('yuding-10','送李式','鄭巢','唐','御定全唐诗','yuding','','[]','瀟湘路杳然，清興起秋前。去寺多隨磬，看山半在船。',48,'御定全唐詩/json/504.json','["瀟湘路杳然，清興起秋前。去寺多隨磬，看山半在船。", "綠雲天外鶴，紅樹雨中蟬。莫使游華頂，逍遙更過年。"]'),
('yuding-11','送韋弇','鄭巢','唐','御定全唐诗','yuding','','[]','掛席曙鐘初，家山半在吳。櫓聲過遠寺，江色潤秋蕪。',48,'御定全唐詩/json/504.json','["掛席曙鐘初，家山半在吳。櫓聲過遠寺，江色潤秋蕪。", "陂鶴巢城木，邊鴻宿岸蘆。知君當永夜，獨釣五湖隅。"]'),
('yuding-12','送人南游','鄭巢','唐','御定全唐诗','yuding','','[]','南京路悄然，欹石漱流泉。遠寺寒雲外，揚帆暑雨前。',48,'御定全唐詩/json/504.json','["南京路悄然，欹石漱流泉。遠寺寒雲外，揚帆暑雨前。", "雁行回曉岫，蜃色上湖田。更想清吟處，多同隱者眠。"]'),
('yuding-13','送省空上人歸南嶽','鄭巢','唐','御定全唐诗','yuding','','[]','又歸衡嶽寺，舊院樹冥冥。坐石縫寒衲，尋龕補壞經。',48,'御定全唐詩/json/504.json','["又歸衡嶽寺，舊院樹冥冥。坐石縫寒衲，尋龕補壞經。", "嶠雲籠曙磬，潭草落秋萍。誰伴高窗宿，禪衣掛桂馨。"]'),
('yuding-14','送象上人還山中','鄭巢','唐','御定全唐诗','yuding','','[]','竹錫與袈裟，靈山笑暗霞。泉痕生淨蘚，燒力落寒花。',48,'御定全唐詩/json/504.json','["竹錫與袈裟，靈山笑暗霞。泉痕生淨蘚，燒力落寒花。", "高戶閑聽雪，空窗靜搗茶。終期宿華頂，須會說三巴。"]'),
('yuding-15','送僧歸富春','鄭巢','唐','御定全唐诗','yuding','','[]','憶過僧禪處，遙山抱竹門。古房關蘚色，秋徑掃潮痕。',48,'御定全唐詩/json/504.json','["憶過僧禪處，遙山抱竹門。古房關蘚色，秋徑掃潮痕。", "石淨聞泉落，沙寒見鶴翻。終當從此望，更與道人言。"]'),
('yuding-16','送琇上人','鄭巢','唐','御定全唐诗','yuding','','[]','古殿焚香外，清羸坐石棱。茶煙開瓦雪，鶴跡上潭冰。',48,'御定全唐詩/json/504.json','["古殿焚香外，清羸坐石棱。茶煙開瓦雪，鶴跡上潭冰。", "孤磬侵雲動，靈山隔水登。白雲歸意遠，舊寺在廬陵。"]'),
('yuding-17','哭虛海上人','鄭巢','唐','御定全唐诗','yuding','','[]','一化西風外，禪流稍稍分。買碑行暮雨，斫石葬寒雲。',48,'御定全唐詩/json/504.json','["一化西風外，禪流稍稍分。買碑行暮雨，斫石葬寒雲。", "靜戶關松色，荒齋聚鳥群。朗吟聲不倦，高傳有遺文。"]'),
('yuding-18','和姚郎中題凝公院','鄭巢','唐','御定全唐诗','yuding','','[]','後房寒竹連，白晝坐冥然。片衲何山至，空堂幾夜禪。',48,'御定全唐詩/json/504.json','["後房寒竹連，白晝坐冥然。片衲何山至，空堂幾夜禪。", "葉侵經上字，冰結硯中泉。雪夕誰同話，懸燈古像前。"]'),
('yuding-19','贈丘先生','鄭巢','唐','御定全唐诗','yuding','','[]','雲泉心不爽，垂日坐柴關。硯取簷前雨，圖開異國山。',48,'御定全唐詩/json/504.json','["雲泉心不爽，垂日坐柴關。硯取簷前雨，圖開異國山。", "原僧招過宿，沙鳥伴長閑。地與中峰近，殘陽獨不還。"]'),
('yuding-20','贈蠻僧','鄭巢','唐','御定全唐诗','yuding','','[]','南海何年過，中林一磬微。病逢秋雨發，心逐暮潮歸。',48,'御定全唐詩/json/504.json','["南海何年過，中林一磬微。病逢秋雨發，心逐暮潮歸。", "久臥前山寺，猶逢故國衣。近來慵步履，石蘚滿柴扉。"]'),
('yuding-21','秋思','鄭巢','唐','御定全唐诗','yuding','','[]','寒蛩鳴不定，郭外水雲幽。南浦雁來日，北窗人臥秋。',48,'御定全唐詩/json/504.json','["寒蛩鳴不定，郭外水雲幽。南浦雁來日，北窗人臥秋。", "病身多在遠，生計少於愁。薄暮西風急，清砧響未休。"]'),
('yuding-22','楚城秋夕','鄭巢','唐','御定全唐诗','yuding','','[]','故苑多愁夕，西風木葉黃。寒江浸霧月，曉角滿城霜。',48,'御定全唐詩/json/504.json','["故苑多愁夕，西風木葉黃。寒江浸霧月，曉角滿城霜。", "弟侄來書少，關河去路長。幾時停桂楫，故國隔瀟湘。"]'),
('yuding-23','秋日陪姚郎中登郡中南亭','鄭巢','唐','御定全唐诗','yuding','','[]','雲水生寒色，高亭發遠心。雁來疏角韻，槐落減秋陰。',48,'御定全唐詩/json/504.json','["雲水生寒色，高亭發遠心。雁來疏角韻，槐落減秋陰。", "隔石嘗茶坐，當山抱瑟吟。誰知瀟灑意，不似有朝簪。"]'),
('yuding-24','宿天竺寺','鄭巢','唐','御定全唐诗','yuding','','[]','暮過潭上寺，獨宿白雲間。鐘磬遙連樹，星河半隔山。',48,'御定全唐詩/json/504.json','["暮過潭上寺，獨宿白雲間。鐘磬遙連樹，星河半隔山。", "石中泉暗落，松外戶初關。卻憶終南裏，前秋此夕還。"]'),
('yuding-25','陳氏園林','鄭巢','唐','御定全唐诗','yuding','','[]','當門三四峰，高興幾人同。尋鶴新泉外，留僧古木中。',48,'御定全唐詩/json/504.json','["當門三四峰，高興幾人同。尋鶴新泉外，留僧古木中。", "蟬鳴槐葉雨，魚散芰荷風。多喜陪幽賞，清吟繞石叢。"]'),
('yuding-26','題崔中丞北齋','鄭巢','唐','御定全唐诗','yuding','','[]','湖近草侵庭，秋來道興生。寒潮添井味，遠漏帶松聲。',48,'御定全唐詩/json/504.json','["湖近草侵庭，秋來道興生。寒潮添井味，遠漏帶松聲。", "放卷聽泉坐，尋僧踏雪行。何年各無事，高論宿青城。"]'),
('yuding-27','題崔行先石室別墅','鄭巢','唐','御定全唐诗','yuding','','[]','山空水繞籬，幾日此棲遲。采菊頻秋醉，留僧擬夜棋。',48,'御定全唐詩/json/504.json','["山空水繞籬，幾日此棲遲。采菊頻秋醉，留僧擬夜棋。", "桂陰生野菌，石縫結寒澌。更喜連幽洞，唯君與我知。"]'),
('yuding-28','題靈隱寺皖公院','鄭巢','唐','御定全唐诗','yuding','','[]','山寒葉滿衣，孤鶴偶清羸。已在雲房老，休為內殿期。',48,'御定全唐詩/json/504.json','["山寒葉滿衣，孤鶴偶清羸。已在雲房老，休為內殿期。", "嵐昏聲磬早，果熟喚猿遲。未得終高論，明朝更別離。"]'),
('yuding-0','題寺壁二首','呂群','唐','御定全唐诗','yuding','','[]','路行三蜀盡，身及一陽生。賴有殘燈火，相依坐到明。',48,'御定全唐詩/json/505.json','["路行三蜀盡，身及一陽生。賴有殘燈火，相依坐到明。", "社後辭巢燕，霜前別蒂蓬。願為蝴蝶夢，飛去覓關中。"]'),
('yuding-1','黃蜀葵','崔涯','唐','御定全唐诗','yuding','','[]','野欄秋景晚，疏散兩三枝。嫩碧淺輕態，幽香閑澹姿。',48,'御定全唐詩/json/505.json','["野欄秋景晚，疏散兩三枝。嫩碧淺輕態，幽香閑澹姿。", "露傾金盞小，風引道冠欹。獨立悄無語，清愁人詎知。"]'),
('yuding-2','詠春風','崔涯','唐','御定全唐诗','yuding','','[]','動地經天物不傷，高情逸韻住何方。扶持燕雀連天去，',40,'御定全唐詩/json/505.json','["動地經天物不傷，高情逸韻住何方。扶持燕雀連天去，", "孤雲雖是無心物，借便吹教到帝鄉。"]'),
('yuding-3','竹','崔涯','唐','御定全唐诗','yuding','','[]','領得溪風不放回，傍窗緣砌遍庭栽。須招野客為鄰住，',40,'御定全唐詩/json/505.json','["領得溪風不放回，傍窗緣砌遍庭栽。須招野客為鄰住，", "誰憐翠色兼寒影，靜落茶甌與酒杯。"]'),
('yuding-4','俠士詩','崔涯','唐','御定全唐诗','yuding','','[]','太行嶺上二尺雪，崔涯袖中三尺鐵。',32,'御定全唐詩/json/505.json','["太行嶺上二尺雪，崔涯袖中三尺鐵。", "一朝若遇有心人，出門便與妻兒別。"]'),
('yuding-5','別妻','崔涯','唐','御定全唐诗','yuding','','[]','隴上泉流隴下分，斷腸嗚咽不堪聞。',32,'御定全唐詩/json/505.json','["隴上泉流隴下分，斷腸嗚咽不堪聞。", "嫦娥一入月中去，巫峽千秋空白雲。"]'),
('yuding-6','雜嘲二首','崔涯','唐','御定全唐诗','yuding','','[]','二年不到宋家東，阿母深居僻巷中。',64,'御定全唐詩/json/505.json','["二年不到宋家東，阿母深居僻巷中。", "含淚向人羞不語，琵琶弦斷倚屏風。", "日暮迎來香合中，百年心事一宵同。", "寒雞鼓翼紗窗外，已覺恩情逐曉風。"]'),
('yuding-7','悼妓','崔涯','唐','御定全唐诗','yuding','','[]','赤板橋西小竹籬，槿花還似去年時。',32,'御定全唐詩/json/505.json','["赤板橋西小竹籬，槿花還似去年時。", "淡黃衫子渾無色，腸斷丁香畫雀兒。"]'),
('yuding-8','自蘇州至望亭驛有作','郭良驥','唐','御定全唐诗','yuding','','[]','南浦菰蒲繞白蘋，東吳黎庶逐黃巾。野棠自發空流水，',40,'御定全唐詩/json/505.json','["南浦菰蒲繞白蘋，東吳黎庶逐黃巾。野棠自發空流水，", "那堪回首長洲苑，烽火年年報虜塵。"]'),
('yuding-9','鄴中行','郭良驥','唐','御定全唐诗','yuding','','[]','年去年來秋更春，魏家園廟已成塵。',32,'御定全唐詩/json/505.json','["年去年來秋更春，魏家園廟已成塵。", "只今惟有西陵在，無複當時歌舞人。"]'),
('yuding-10','公無渡河','王睿','唐','御定全唐诗','yuding','','[]','濁波洋洋兮凝曉霧，公無渡河兮公竟渡。',96,'御定全唐詩/json/505.json','["濁波洋洋兮凝曉霧，公無渡河兮公竟渡。", "風號水激兮呼不聞，提壺看入兮中流去。", "浪擺衣裳兮隨步沒，沉屍深入兮蛟螭窟。", "蛟螭盡醉兮君血幹，推出黃沙兮泛君骨。", "當時君死妾何適，遂就波濤合魂魄。願持精衛銜石心，"]'),
('yuding-11','松','王睿','唐','御定全唐诗','yuding','','[]','寒松聳拔倚蒼岑，綠葉扶疏自結陰。丁固夢時還有意，',40,'御定全唐詩/json/505.json','["寒松聳拔倚蒼岑，綠葉扶疏自結陰。丁固夢時還有意，", "好是特凋群木後，護霜淩雪翠逾深。"]'),
('yuding-12','竹','王睿','唐','御定全唐诗','yuding','','[]','庭竹森疏玉質寒，色包蔥碧盡琅玕。翠筠不樂湘娥淚，',40,'御定全唐詩/json/505.json','["庭竹森疏玉質寒，色包蔥碧盡琅玕。翠筠不樂湘娥淚，", "此君引鳳為龍日，聳節稍雲直上看。"]'),
('yuding-13','解昭君怨','王睿','唐','御定全唐诗','yuding','','[]','莫怨工人醜畫身，莫嫌明主遣和親。',32,'御定全唐詩/json/505.json','["莫怨工人醜畫身，莫嫌明主遣和親。", "當時若不嫁胡虜，只是宮中一舞人。"]'),
('yuding-14','祠漁山神女歌二首','王睿','唐','御定全唐诗','yuding','','[]','蓪草頭花椰葉裙，蒲葵樹下舞蠻雲。',64,'御定全唐詩/json/505.json','["蓪草頭花椰葉裙，蒲葵樹下舞蠻雲。", "引領望江遙滴酒，白蘋風起水生文。", "棖棖山響答琵琶，酒濕青莎肉飼鴉。", "樹葉無聲神去後，紙錢灰出木綿花。"]'),
('yuding-15','牡丹','王睿','唐','御定全唐诗','yuding','','[]','牡丹妖豔亂人心，一國如狂不惜金。',32,'御定全唐詩/json/505.json','["牡丹妖豔亂人心，一國如狂不惜金。", "曷若東園桃與李，果成無語自成陰。"]'),
('yuding-16','秋','王睿','唐','御定全唐诗','yuding','','[]','蟬噪古槐疏葉下，樹銜斜日映孤城。',32,'御定全唐詩/json/505.json','["蟬噪古槐疏葉下，樹銜斜日映孤城。", "欲知潘鬢愁多少，一夜新添白數莖。"]'),
('yuding-17','燕','王睿','唐','御定全唐诗','yuding','','[]','海燕雙飛意若何，曲梁嘔嘎語聲多。',32,'御定全唐詩/json/505.json','["海燕雙飛意若何，曲梁嘔嘎語聲多。", "茅簷不必嫌卑陋，猶勝吳宮爇爾窠。"]'),
('yuding-18','白雲向空盡','焦郁','唐','御定全唐诗','yuding','','[]','白雲升遠岫，搖曳入晴空。乘化隨舒卷，無心任始終。',72,'御定全唐詩/json/505.json','["白雲升遠岫，搖曳入晴空。乘化隨舒卷，無心任始終。", "欲銷仍帶日，將斷更因風。勢薄飛難定，天高色易窮。", "影收元氣表，光滅太虛中。倘若從龍去，還施濟物功。"]'),
('yuding-19','春雪','焦鬱','唐','御定全唐诗','yuding','','[]','散漫天涯色，乘春四望平。不分殘照影，何處斷鴻聲。',104,'御定全唐詩/json/505.json','["散漫天涯色，乘春四望平。不分殘照影，何處斷鴻聲。", "繚繞先經塞，霏微近過城。因風低未斂，帶雨重還輕。", "幹呂知時泰，如膏候歲成。小儒同品物，無以答皇明。", "春雪空蒙簾外斜，霏微半入野人家。", "長天遠樹山山白，不辨梅花與柳花。"]'),
('yuding-20','贈去婢','崔郊','唐','御定全唐诗','yuding','','[]','公子王孫逐後塵，綠珠垂淚滴羅巾。',32,'御定全唐詩/json/505.json','["公子王孫逐後塵，綠珠垂淚滴羅巾。", "侯門一入深如海，從此蕭郎是路人。"]'),
('yuding-21','江西投謁所知為典客所阻因賦','劉魯風','唐','御定全唐诗','yuding','','[]','萬卷書生劉魯風，煙波萬里謁文翁。',32,'御定全唐詩/json/505.json','["萬卷書生劉魯風，煙波萬里謁文翁。", "無錢乞與韓知客，名紙毛生不肯通。"]'),
('yuding-22','玉清行','柳泌','唐','御定全唐诗','yuding','','[]','遙遙寒冬時，蕭蕭躡太無。仰望蕊宮殿，橫天臨不虛。',192,'御定全唐詩/json/505.json','["遙遙寒冬時，蕭蕭躡太無。仰望蕊宮殿，橫天臨不虛。", "下看白日流，上造真皇居。西牖日門開，南衢星宿疏。", "王母來瑤池，慶雲擁瓊輿。嵬峨丹鳳冠，搖曳紫霞裾。", "照徹聖姿嚴，飄颻神步徐。仙郎執玉節，侍女捧金書。", "靈香散彩煙，北闕路輧闐。龍馬行無跡，歌鐘聲沸天。", "馭風升寶座，郁景晏華筵。妙奏三春曲，高羅萬古仙。", "七珍飛滿座，九液酌如泉。靈佩垂軒下，旗幡列帳前。", "獅麟威赫赫，鸞鳳影翩翩。顧盼乃須臾，已是數千年。"]'),
('yuding-23','瓊台','柳泌','唐','御定全唐诗','yuding','','[]','崖壁盤空天路回，白雲行盡見瓊台。',32,'御定全唐詩/json/505.json','["崖壁盤空天路回，白雲行盡見瓊台。", "洞門黯黯陰雲閉，金闕曈曈日殿開。"]'),
('yuding-24','操蓮曲','何希堯','唐','御定全唐诗','yuding','','[]','錦蓮浮處水粼粼，風外香生襪底塵。',32,'御定全唐詩/json/505.json','["錦蓮浮處水粼粼，風外香生襪底塵。", "荷葉荷裙相映色，聞歌不見採蓮人。"]'),
('yuding-25','一枝花','何希堯','唐','御定全唐诗','yuding','','[]','幾樹晴葩映水開，亂紅狼藉點蒼苔。',32,'御定全唐詩/json/505.json','["幾樹晴葩映水開，亂紅狼藉點蒼苔。", "東風留得殘枝在，為惜餘芳獨看來。"]'),
('yuding-26','柳枝詞','何希堯','唐','御定全唐诗','yuding','','[]','大堤楊柳雨沉沉，萬縷千條惹恨深。',32,'御定全唐詩/json/505.json','["大堤楊柳雨沉沉，萬縷千條惹恨深。", "飛絮滿天人去遠，東風無力系春心。"]'),
('yuding-27','海棠','何希堯','唐','御定全唐诗','yuding','','[]','著雨胭脂點點消，半開時節最妖嬈。',32,'御定全唐詩/json/505.json','["著雨胭脂點點消，半開時節最妖嬈。", "誰家更有黃金屋，深鎖東風貯阿嬌。"]'),
('yuding-28','遺臨平監吏','朱沖和','唐','御定全唐诗','yuding','','[]','三千裏外布干戈，果得鯨鯢入網羅。',32,'御定全唐詩/json/505.json','["三千裏外布干戈，果得鯨鯢入網羅。", "今日寶刀無殺氣，只緣君處受恩多。"]'),
('yuding-29','荻塘西莊贈房元垂','張光朝','唐','御定全唐诗','yuding','','[]','門在荻塘西，塘高何聯聯。往昔分地利，遠近無閒田。',144,'御定全唐詩/json/505.json','["門在荻塘西，塘高何聯聯。往昔分地利，遠近無閒田。", "水國信汙下，霖霪即成川。苗稼盡淹沒，茲鄉獨豐年。", "家肥待親懿，人樂思管弦。日晏始能起，盥漱看廚煙。", "醞酒寒正熟，養魚長食鮮。黃昏鐘未鳴，偃息早已眠。", "何意久城市，寂寥丘中緣。俯仰在顏色，區區人事間。", "憶昔炎漢時，乃知綺季賢。靜默不能仕，養老終南山。"]'),
('yuding-30','天門街西觀榮王聘妃','張光朝','唐','御定全唐诗','yuding','','[]','仙媛來朱邸，名山出紫微。三周初展義，百兩遂言歸。',72,'御定全唐詩/json/505.json','["仙媛來朱邸，名山出紫微。三周初展義，百兩遂言歸。", "鄭國通梁苑，天津接帝畿。橋成烏鵲助，蓋轉鳳凰飛。", "霜仗迎秋色，星缸滿夜輝。從茲磐石固，應為得賢妃。"]'),
('yuding-31','天門街西觀榮王聘妃','梁鉉','唐','御定全唐诗','yuding','','[]','帝子乘龍夜，三星照戶前。兩行宮火出，十裏道鋪筵。',72,'御定全唐詩/json/505.json','["帝子乘龍夜，三星照戶前。兩行宮火出，十裏道鋪筵。", "羅綺明中識，簫韶暗裏傳。燈攢九華扇，帳撒五銖錢。", "交頸文鴛合，和鳴彩鳳連。欲知來日美，雙拜紫微天。"]'),
('yuding-0','上浙東元相','章孝標','唐','御定全唐诗','yuding','','[]','婺女星邊喜氣頻，越王臺上坐詩人。雪晴山水勾留客，',40,'御定全唐詩/json/506.json','["婺女星邊喜氣頻，越王臺上坐詩人。雪晴山水勾留客，", "何言禹跡無人繼，萬頃湖田又斬新。"]'),
('yuding-1','贈茅山高拾遺蔓','章孝標','唐','御定全唐诗','yuding','','[]','人皆貪祿利，白首更營營。若見無為理，兼忘不朽名。',48,'御定全唐詩/json/506.json','["人皆貪祿利，白首更營營。若見無為理，兼忘不朽名。", "幽禽窺飯下，好藥入籬生。夢覺幽泉滴，應疑禁漏聲。"]'),
('yuding-2','次韻和光祿錢卿二首','章孝標','唐','御定全唐诗','yuding','','[]','大隱嚴城內，閑門向水開。扇風知暑退，樹影覺秋來。',96,'御定全唐詩/json/506.json','["大隱嚴城內，閑門向水開。扇風知暑退，樹影覺秋來。", "望遠雲生海，行稀砌長苔。廢興今古事，何必歎池灰。", "閑論憂王室，愁眉仗酒開。方嗟三覆役，又喜四愁來。", "晨起螢穿竹，晡餐鳥下苔。同期陽月至，靈室祝葭灰。"]'),
('yuding-3','贈廬山錢卿','章孝標','唐','御定全唐诗','yuding','','[]','象魏抽簪早，匡廬築室牢。宦情歸去薄，天爵隱來高。',48,'御定全唐詩/json/506.json','["象魏抽簪早，匡廬築室牢。宦情歸去薄，天爵隱來高。", "篋有新征詔，囊餘舊縕袍。何如舍麋鹿，明主仰風騷。"]'),
('yuding-4','山中送進士劉蟾赴舉','章孝標','唐','御定全唐诗','yuding','','[]','去住跡雖異，愛憎情不同。因君向帝裏，使我厭山中。',48,'御定全唐詩/json/506.json','["去住跡雖異，愛憎情不同。因君向帝裏，使我厭山中。", "故友多朝客，新文盡國風。藝精心更苦，何患不成功。"]'),
('yuding-5','送進士陳嶢往睦州謁馮郎中','章孝標','唐','御定全唐诗','yuding','','[]','孤帆幾日程，投刺水邊城。倚棹逢春老，登筵見月生。',48,'御定全唐詩/json/506.json','["孤帆幾日程，投刺水邊城。倚棹逢春老，登筵見月生。", "飲酣杯有浪，棋散漏無聲。太守憐才者，從容禮不輕。"]'),
('yuding-6','豐城劍池即事','章孝標','唐','御定全唐诗','yuding','','[]','神物不復見，小池空在茲。因嫌沖鬥夜，未是偃戈時。',48,'御定全唐詩/json/506.json','["神物不復見，小池空在茲。因嫌沖鬥夜，未是偃戈時。", "岸古魚藏穴，蒲凋翠立危。吾皇別有劍，何必鑄金為。"]'),
('yuding-7','詠弓','章孝標','唐','御定全唐诗','yuding','','[]','較量武藝論勳庸，曾發將軍箭落鴻。握內從誇彎似月，',40,'御定全唐詩/json/506.json','["較量武藝論勳庸，曾發將軍箭落鴻。握內從誇彎似月，", "得病自從杯裏後，至今形狀怕相逢。"]'),
('yuding-8','送無相禪師入關','章孝標','唐','御定全唐诗','yuding','','[]','九衢車馬塵，不染了空人。暫舍中峰雪，應看內殿春。',48,'御定全唐詩/json/506.json','["九衢車馬塵，不染了空人。暫舍中峰雪，應看內殿春。", "齋心無外事，定力見前身。聖主方崇教，深宜謁紫宸。"]'),
('yuding-9','贈匡山道者','章孝標','唐','御定全唐诗','yuding','','[]','嘗聞一粒功，足以反衰容。方寸如不達，此生安可逢。',48,'御定全唐詩/json/506.json','["嘗聞一粒功，足以反衰容。方寸如不達，此生安可逢。", "寄書時態盡，憶語道情濃。爭得攜巾屨，同歸鳥外峰。"]'),
('yuding-10','道者與金丹開合已失，因為二首，再有投擲','章孝標','唐','御定全唐诗','yuding','','[]','木鑽鑽磐石，辛勤四十年。一朝才見物，五色互呈妍。',96,'御定全唐詩/json/506.json','["木鑽鑽磐石，辛勤四十年。一朝才見物，五色互呈妍。", "七魄憎陽盛，三彭惡命延。被他迷失卻，歎息只潸然。", "陰陽曾作炭，造化亦分功。減自青囊裏，收安玉合中。", "凡材難度世，神物自歸空。惆悵流年速，看成白首翁。"]'),
('yuding-11','思越州山水寄朱慶餘','章孝標','唐','御定全唐诗','yuding','','[]','窗戶潮頭雪，雲霞鏡裏天。島桐秋送雨，江艇暮搖煙。',48,'御定全唐詩/json/506.json','["窗戶潮頭雪，雲霞鏡裏天。島桐秋送雨，江艇暮搖煙。", "藕折蓮芽脆，茶挑茗眼鮮。還將歐冶劍，更淬若耶泉。"]'),
('yuding-12','蜀中上王尚書','章孝標','唐','御定全唐诗','yuding','','[]','梓桐花幕碧雲浮，天許文星寄上頭。武略劍峰環相府，',40,'御定全唐詩/json/506.json','["梓桐花幕碧雲浮，天許文星寄上頭。武略劍峰環相府，", "自古名高閑不得，肯容王粲賦登樓。"]'),
('yuding-13','贈陸鬯浙西進詩除官','章孝標','唐','御定全唐诗','yuding','','[]','帝城雲物得陽春，水國煙花失主人。',32,'御定全唐詩/json/506.json','["帝城雲物得陽春，水國煙花失主人。", "昨日天風吹樂府，六宮絲管一時新。"]'),
('yuding-14','古行宮','章孝標','唐','御定全唐诗','yuding','','[]','瓦煙疏冷古行宮，寂寞朱門反鎖空。殘粉水銀流砌下，',40,'御定全唐詩/json/506.json','["瓦煙疏冷古行宮，寂寞朱門反鎖空。殘粉水銀流砌下，", "天子時清不巡幸，只應鸞鳳集梧桐。"]'),
('yuding-15','題上皇觀','章孝標','唐','御定全唐诗','yuding','','[]','煙霞星蓋七星壇，想像先朝駐禁鑾。輦路已平栽藥地，',40,'御定全唐詩/json/506.json','["煙霞星蓋七星壇，想像先朝駐禁鑾。輦路已平栽藥地，", "翻感惠休並李郭，劍門空處望長安。"]'),
('yuding-16','鷹','章孝標','唐','御定全唐诗','yuding','','[]','星眸未放瞥秋毫，頻掣金鈴試雪毛。會使老拳供口腹，',40,'御定全唐詩/json/506.json','["星眸未放瞥秋毫，頻掣金鈴試雪毛。會使老拳供口腹，", "可惜忍饑寒日暮，向人鵮斷碧絲絛。"]'),
('yuding-17','方山寺松下泉','章孝標','唐','御定全唐诗','yuding','','[]','石脈綻寒光，松根噴曉霜。注瓶雲母滑，漱齒茯苓香。',48,'御定全唐詩/json/506.json','["石脈綻寒光，松根噴曉霜。注瓶雲母滑，漱齒茯苓香。", "野客偷煎茗，山僧惜淨床。三禪不要問，孤月在中央。"]'),
('yuding-18','瀑布','章孝標','唐','御定全唐诗','yuding','','[]','秋河溢長空，天灑萬丈布。深雷隱雲壑，孤電掛岩樹。',48,'御定全唐詩/json/506.json','["秋河溢長空，天灑萬丈布。深雷隱雲壑，孤電掛岩樹。", "滄溟曉噴寒，碧落晴蕩素。非趨下流急，熱使不得住。"]'),
('yuding-19','送張使君赴饒州','章孝標','唐','御定全唐诗','yuding','','[]','饒陽因富得州名，不獨農桑別有營。日暖提筐依茗樹，',40,'御定全唐詩/json/506.json','["饒陽因富得州名，不獨農桑別有營。日暖提筐依茗樹，", "太守能詩兼愛靜，西樓見月幾篇成。"]'),
('yuding-20','和滕邁先輩傷馬','章孝標','唐','御定全唐诗','yuding','','[]','浮雲變化失龍兒，始憶嘶風噴沫時。蹄想塵中翻碧玉，',40,'御定全唐詩/json/506.json','["浮雲變化失龍兒，始憶嘶風噴沫時。蹄想塵中翻碧玉，", "今日櫪前興一歎，不關行李乏金羈。"]'),
('yuding-21','省試騏驥長鳴','章孝標','唐','御定全唐诗','yuding','','[]','有馬骨堪驚，無人眼暫明。力窮吳阪峻，嘶苦朔風生。',72,'御定全唐詩/json/506.json','["有馬骨堪驚，無人眼暫明。力窮吳阪峻，嘶苦朔風生。", "逐逐懷良禦，蕭蕭顧樂鳴。瑤池期弄影，天路擬飛聲。", "皎月誰知種，浮雲莫問程。鹽車今願脫，千里為君行。"]'),
('yuding-22','鯉魚','章孝標','唐','御定全唐诗','yuding','','[]','眼似真珠鱗似金，時時動浪出還沈。',32,'御定全唐詩/json/506.json','["眼似真珠鱗似金，時時動浪出還沈。", "河中得上龍門去，不歎江湖歲月深。"]'),
('yuding-23','饑鷹詞','章孝標','唐','御定全唐诗','yuding','','[]','遙想平原兔正肥，千回礪吻振毛衣。',32,'御定全唐詩/json/506.json','["遙想平原兔正肥，千回礪吻振毛衣。", "縱令啄解絲絛結，未得人呼不敢飛。"]'),
('yuding-24','歸燕詞辭工部侍郎','章孝標','唐','御定全唐诗','yuding','','[]','舊壘危巢泥已落，今年故向社前歸。',32,'御定全唐詩/json/506.json','["舊壘危巢泥已落，今年故向社前歸。", "連雲大廈無棲處，更望誰家門戶飛。"]'),
('yuding-25','歸海上舊居','章孝標','唐','御定全唐诗','yuding','','[]','鄉路繞蒹葭，縈紆出海涯。人衣披蜃氣，馬跡印鹽花。',48,'御定全唐詩/json/506.json','["鄉路繞蒹葭，縈紆出海涯。人衣披蜃氣，馬跡印鹽花。", "草沒題詩石，潮摧坐釣槎。還歸舊窗裏，凝思向餘霞。"]'),
('yuding-26','答友人惠牙簪','章孝標','唐','御定全唐诗','yuding','','[]','牙簪不可忘，來處隔炎荒。截得半環月，磨成四寸霜。',48,'御定全唐詩/json/506.json','["牙簪不可忘，來處隔炎荒。截得半環月，磨成四寸霜。", "曉辭梳齒膩，秋入發根涼。好是紗巾下，纖纖錐出囊。"]'),
('yuding-27','日者','章孝標','唐','御定全唐诗','yuding','','[]','十指中央了五行，說人休咎見前生。',32,'御定全唐詩/json/506.json','["十指中央了五行，說人休咎見前生。", "我來本乞真消息，卻怕呵錢卦欲成。"]'),
('yuding-28','送金可紀歸新羅','章孝標','唐','御定全唐诗','yuding','','[]','登唐科第語唐音，望日初生憶故林。鮫室夜眠陰火冷，',40,'御定全唐詩/json/506.json','["登唐科第語唐音，望日初生憶故林。鮫室夜眠陰火冷，", "想把文章合夷樂，蟠桃花裏醉人參。"]'),
('yuding-29','聞角','章孝標','唐','御定全唐诗','yuding','','[]','邊秋畫角怨金微，半夜對吹驚賊圍。塞雁繞空秋不下，',40,'御定全唐詩/json/506.json','["邊秋畫角怨金微，半夜對吹驚賊圍。塞雁繞空秋不下，", "餘韻嫋空何處盡，戍天寥落曉星稀。"]'),
('yuding-30','夢鄉','章孝標','唐','御定全唐诗','yuding','','[]','家住吳王舊苑東，屋頭山水勝屏風。',32,'御定全唐詩/json/506.json','["家住吳王舊苑東，屋頭山水勝屏風。", "尋常夢在秋江上，釣艇游揚藕葉中。"]'),
('yuding-31','織綾詞','章孝標','唐','御定全唐诗','yuding','','[]','去年蠶惡綾帛貴，官急無絲織紅淚。殘經脆緯不通梭，',48,'御定全唐詩/json/506.json','["去年蠶惡綾帛貴，官急無絲織紅淚。殘經脆緯不通梭，", "瑤台雪裏鶴張翅，禁苑風前梅折枝。不學鄰家婦慵懶，"]'),
('yuding-32','諸葛武侯廟','章孝標','唐','御定全唐诗','yuding','','[]','木牛零落陣圖殘，山姥燒錢古柏寒。',32,'御定全唐詩/json/506.json','["木牛零落陣圖殘，山姥燒錢古柏寒。", "七縱七擒何處在，茅花櫪葉蓋神壇。"]'),
('yuding-33','長安秋夜','章孝標','唐','御定全唐诗','yuding','','[]','田家無五行，水旱蔔蛙聲。牛犢乘春放，兒童候暖耕。',48,'御定全唐詩/json/506.json','["田家無五行，水旱蔔蛙聲。牛犢乘春放，兒童候暖耕。", "池塘煙未起，桑柘雨初晴。步晚香醪熟，村村自送迎。"]'),
('yuding-34','錢塘贈武翊黃','章孝標','唐','御定全唐诗','yuding','','[]','曾將心劍作戈矛，一戰名場造化愁。花錦文章開四面，',40,'御定全唐詩/json/506.json','["曾將心劍作戈矛，一戰名場造化愁。花錦文章開四面，", "時伴庾公看海月，好吟詩斷望潮樓。"]'),
('yuding-35','風不鳴條','章孝標','唐','御定全唐诗','yuding','','[]','旭日懸清景，微風在綠條。入松聲不發，過柳影空搖。',72,'御定全唐詩/json/506.json','["旭日懸清景，微風在綠條。入松聲不發，過柳影空搖。", "長養應潛變，扶疏每暗飄。有林時杳杳，無樹暫蕭蕭。", "慢逐清煙散，輕和瑞氣饒。豐年知有待，歌詠美唐堯。"]'),
('yuding-36','貽美人','章孝標','唐','御定全唐诗','yuding','','[]','諸侯帳下慣新妝，皆怯劉家薄媚娘。寶髻巧梳金翡翠，',40,'御定全唐詩/json/506.json','["諸侯帳下慣新妝，皆怯劉家薄媚娘。寶髻巧梳金翡翠，", "何事不歸巫峽去，故來人世斷人腸。"]'),
('yuding-37','聞雲中唳鶴','章孝標','唐','御定全唐诗','yuding','','[]','久在青田唳，天高忽暫聞。翩翩縈碧落，嘹唳入重雲。',48,'御定全唐詩/json/506.json','["久在青田唳，天高忽暫聞。翩翩縈碧落，嘹唳入重雲。", "出谷鶯何待，鳴岐鳳欲群。九皋寧足道，此去透絪縕。"]'),
('yuding-38','柘枝','章孝標','唐','御定全唐诗','yuding','','[]','柘枝初出鼓聲招，花鈿羅衫聳細腰。移步錦靴空綽約，',40,'御定全唐詩/json/506.json','["柘枝初出鼓聲招，花鈿羅衫聳細腰。移步錦靴空綽約，", "只恐相公看未足，便隨風雨上青霄。"]'),
('yuding-39','上太皇先生','章孝標','唐','御定全唐诗','yuding','','[]','顥氣貫精神，蒼崖老姓名。煙霞空送景，水木苦無情。',120,'御定全唐詩/json/506.json','["顥氣貫精神，蒼崖老姓名。煙霞空送景，水木苦無情。", "劚藥雲根斷，眠花石面平。折鬆開月色，決水放秋聲。", "顏為忘憂嫩，身緣絕粒輕。圍棋看局勢，對鏡戮妖精。", "過海量鯨力，歸天算鶴程。露凝鐘乳冷，風定玉簫清。", "坐覺衣裳古，行疑羽翼生。應憐市朝客，開眼鎖浮榮。"]'),
('yuding-40','破山水屏風','章孝標','唐','御定全唐诗','yuding','','[]','時人嫌古畫，倚壁不曾收。雨滴膠山斷，風吹絹海秋。',48,'御定全唐詩/json/506.json','["時人嫌古畫，倚壁不曾收。雨滴膠山斷，風吹絹海秋。", "殘雲飛屋裏，片水落床頭。尚勝凡花鳥，君能補綴休。"]'),
('yuding-41','覽楊校書文卷','章孝標','唐','御定全唐诗','yuding','','[]','跪伸霜素剖琅玕，身墮瑤池魄暗寒。紅錦晚開雲母殿，',40,'御定全唐詩/json/506.json','["跪伸霜素剖琅玕，身墮瑤池魄暗寒。紅錦晚開雲母殿，", "誰有軒轅古銅片，為持相並照妖看。"]'),
('yuding-42','送陳校書赴蔡州幕','章孝標','唐','御定全唐诗','yuding','','[]','天假縱橫入幕籌，東南頓減一方憂。行齎健筆辭天閣，',40,'御定全唐詩/json/506.json','["天假縱橫入幕籌，東南頓減一方憂。行齎健筆辭天閣，", "此行領取從軍樂，莫慮功名不拜侯。"]'),
('yuding-43','少年行','章孝標','唐','御定全唐诗','yuding','','[]','平明小獵出中軍，異國名香滿袖熏。畫榼倒懸鸚鵡嘴，',40,'御定全唐詩/json/506.json','["平明小獵出中軍，異國名香滿袖熏。畫榼倒懸鸚鵡嘴，", "落日胡姬樓上飲，風吹簫管滿樓聞。"]'),
('yuding-44','蜀中贈廣上人','章孝標','唐','御定全唐诗','yuding','','[]','曾持麈尾引金根，萬乘前頭草五言。疏講青龍歸禁苑，',40,'御定全唐詩/json/506.json','["曾持麈尾引金根，萬乘前頭草五言。疏講青龍歸禁苑，", "今日西川無子美，詩風又起浣花村。"]'),
('yuding-45','和顧校書新開井','章孝標','唐','御定全唐诗','yuding','','[]','霜鍤破桐陰，青絲試淺深。月輪開地脈，鏡面寫天心。',48,'御定全唐詩/json/506.json','["霜鍤破桐陰，青絲試淺深。月輪開地脈，鏡面寫天心。", "碧甃花千片，香泉乳百尋。欲知爭汲引，聽取轆轤音。"]'),
('yuding-46','遊雲際寺','章孝標','唐','御定全唐诗','yuding','','[]','衫袖拂青冥，推鞍上翠屏。塵埃辭馬尾，城闕入窗櫺。',48,'御定全唐詩/json/506.json','["衫袖拂青冥，推鞍上翠屏。塵埃辭馬尾，城闕入窗櫺。", "雲領浮名去，鐘撞大夢醒。茫茫山下事，滿眼送流萍。"]'),
('yuding-47','贈劉寬夫昆季','章孝標','唐','御定全唐诗','yuding','','[]','文聚星辰衣彩霞，問誰兄弟是劉家。雁行雲摻參差翼，',40,'御定全唐詩/json/506.json','["文聚星辰衣彩霞，問誰兄弟是劉家。雁行雲摻參差翼，", "曾窮晉漢儒林傳，龍虎雖多未足誇。"]'),
('yuding-48','贈杭州嚴史君','章孝標','唐','御定全唐诗','yuding','','[]','州青縣白浙河濆，飽向蒼龍闕下聞。鼓角自嚴寒海月，',40,'御定全唐詩/json/506.json','["州青縣白浙河濆，飽向蒼龍闕下聞。鼓角自嚴寒海月，", "長恐抱轅留不住，九天鴛鷺待成群。"]'),
('yuding-49','題朱秀城南亭子','章孝標','唐','御定全唐诗','yuding','','[]','朱家亭子象懸匏，階瑩青莎棟剪茆。癭掛眼開欺鴝鵒，',40,'御定全唐詩/json/506.json','["朱家亭子象懸匏，階瑩青莎棟剪茆。癭掛眼開欺鴝鵒，", "土木欲知精潔處，社天歸燕怯安巢。"]'),
('yuding-50','上西川王尚書','章孝標','唐','御定全唐诗','yuding','','[]','人人入蜀謁文翁，妍醜終須露鏡中。詩景荒涼難道合，',40,'御定全唐詩/json/506.json','["人人入蜀謁文翁，妍醜終須露鏡中。詩景荒涼難道合，", "下客低頭來又去，暗堆冰炭在深衷。"]'),
('yuding-51','駱谷行','章孝標','唐','御定全唐诗','yuding','','[]','捫雲嫋棧入青冥，鞿馬鈴騾傍日星。仰踏劍棱梯萬仞，',40,'御定全唐詩/json/506.json','["捫雲嫋棧入青冥，鞿馬鈴騾傍日星。仰踏劍棱梯萬仞，", "若比爭名求利處，尋思此路卻安寧。"]'),
('yuding-52','初及第歸酬孟元翊見贈','章孝標','唐','御定全唐诗','yuding','','[]','六年衣破帝城塵，一日天池水脫鱗。未有片言驚後輩，',40,'御定全唐詩/json/506.json','["六年衣破帝城塵，一日天池水脫鱗。未有片言驚後輩，", "何幸致詩相慰賀，東歸花發杏桃春。"]'),
('yuding-53','淮南李相公紳席上賦春雪','章孝標','唐','御定全唐诗','yuding','','[]','六出花飛處處飄，粘窗著砌上寒條。',32,'御定全唐詩/json/506.json','["六出花飛處處飄，粘窗著砌上寒條。", "朱門到曉難盈尺，儘是三軍喜氣消。"]'),
('yuding-54','及第後寄廣陵故人','章孝標','唐','御定全唐诗','yuding','','[]','及第全勝十政官，金鞍鍍了出長安。',32,'御定全唐詩/json/506.json','["及第全勝十政官，金鞍鍍了出長安。", "馬頭漸入揚州郭，為報時人洗眼看。"]'),
('yuding-55','小松','章孝標','唐','御定全唐诗','yuding','','[]','爪葉鱗條龍不盤，梳風幕翠一庭寒。',32,'御定全唐詩/json/506.json','["爪葉鱗條龍不盤，梳風幕翠一庭寒。", "莫言只是人長短，須作浮雲向上看。"]'),
('yuding-56','宮詞','章孝標','唐','御定全唐诗','yuding','','[]','明日鑾輿欲向東，守宮金翠帶愁紅。',32,'御定全唐詩/json/506.json','["明日鑾輿欲向東，守宮金翠帶愁紅。", "九門佳氣已西去，千里花開一夜風。"]'),
('yuding-57','題杭州樟亭驛','章孝標','唐','御定全唐诗','yuding','','[]','樟亭驛上題詩客，一半尋為山下塵。',32,'御定全唐詩/json/506.json','["樟亭驛上題詩客，一半尋為山下塵。", "世事日隨流水去，紅花還似白頭人。"]'),
('yuding-58','劉侍中宅盤花紫薔薇','章孝標','唐','御定全唐诗','yuding','','[]','真宰偏饒麗景家，當春盤出帶根霞。',32,'御定全唐詩/json/506.json','["真宰偏饒麗景家，當春盤出帶根霞。", "從開一朵朝衣色，免踏塵埃看雜花。"]'),
('yuding-59','題東林寺寄江州李員外','章孝標','唐','御定全唐诗','yuding','','[]','山勢棱層入杳冥，寺形高下趁山行。象牙床坐蓮花佛，',40,'御定全唐詩/json/506.json','["山勢棱層入杳冥，寺形高下趁山行。象牙床坐蓮花佛，", "門前更有清江水，便是潯陽太守廳。"]'),
('yuding-60','玄都觀栽桃十韻','章孝標','唐','御定全唐诗','yuding','','[]','驅使鬼神功，攢栽萬樹紅。熏香丹鳳闕，妝點紫瓊宮。',120,'御定全唐詩/json/506.json','["驅使鬼神功，攢栽萬樹紅。熏香丹鳳闕，妝點紫瓊宮。", "寶帳重庶日，妖金遍累空。色然燒藥火，影舞步虛風。", "粉撲青牛過，枝驚白鶴沖。拜星春錦上，服食晚霞中。", "棋局陰長合，簫聲秘不通。豔陽迷俗客，幽邃失壺公。", "根柢終磐石，桑麻自轉蓬。求師飽靈藥，他日訪遼東。"]'),
('yuding-61','僧院小松','章孝標','唐','御定全唐诗','yuding','','[]','拋杉背柏冷僧簾，鎖月梳風出殿簷。',32,'御定全唐詩/json/506.json','["拋杉背柏冷僧簾，鎖月梳風出殿簷。", "還似天臺新雨後，小峰雲外碧尖尖。"]'),
('yuding-62','春原早望','章孝標','唐','御定全唐诗','yuding','','[]','一忝鄉書薦，長安未得回。年光逐渭水，春色上秦台。',48,'御定全唐詩/json/506.json','["一忝鄉書薦，長安未得回。年光逐渭水，春色上秦台。", "燕掠平蕪去，人沖細雨來。東風生故里，又過幾花開。"]'),
('yuding-63','西山廣福院','章孝標','唐','御定全唐诗','yuding','','[]','野寺孤峰上，危樓聳翠微。捲簾滄海近，洗缽白雲飛。',48,'御定全唐詩/json/506.json','["野寺孤峰上，危樓聳翠微。捲簾滄海近，洗缽白雲飛。", "竹影臨經案，松花點衲衣。日斜登望處，湖畔一僧歸。"]'),
('yuding-64','遊地肺','章孝標','唐','御定全唐诗','yuding','','[]','市朝擾擾千古，林壑冥冥四賢。黃鶴不歸丹灶，',35,'御定全唐詩/json/506.json','["市朝擾擾千古，林壑冥冥四賢。黃鶴不歸丹灶，", "高跡無人更躡，碧峰寥落孤煙。"]'),
('yuding-65','八月','章孝標','唐','御定全唐诗','yuding','','[]','徙倚仙居繞翠樓，分明宮漏靜兼秋。',32,'御定全唐詩/json/506.json','["徙倚仙居繞翠樓，分明宮漏靜兼秋。", "長安夜夜家家月，幾處笙歌幾處愁。"]'),
('yuding-66','題紫微山上方','章孝標','唐','御定全唐诗','yuding','','[]','地勢連滄海，山名號紫微。景閑僧坐久，路僻客來稀。',48,'御定全唐詩/json/506.json','["地勢連滄海，山名號紫微。景閑僧坐久，路僻客來稀。", "峽影雲相照，河流石自圍。塵喧都不到，安得此忘歸。"]'),
('yuding-0','題杜賓客新豐裏幽居','蔣防','唐','御定全唐诗','yuding','','[]','退跡依三徑，辭榮繼二疏。聖情容解印，帝裏許懸車。',72,'御定全唐詩/json/507.json','["退跡依三徑，辭榮繼二疏。聖情容解印，帝裏許懸車。", "已去龍樓籍，猶分禦廩儲。風泉輸耳目，松竹助玄虛。", "調護心常在，山林意有餘。應嗤紫芝客，遠就白雲居。"]'),
('yuding-1','望禁苑祥光','蔣防','唐','御定全唐诗','yuding','','[]','嘉瑞生天色，蔥蘢幾效祥。樹搖三殿側，日映九城傍。',72,'御定全唐詩/json/507.json','["嘉瑞生天色，蔥蘢幾效祥。樹搖三殿側，日映九城傍。", "仙霧今同色，卿雲未可章。拱汾疑鼎氣，臨渭比螢光。", "豈並春風舊，俄同聖壽長。微臣時一望，短羽欲翱翔。"]'),
('yuding-2','冬至日祥風應候','蔣防','唐','御定全唐诗','yuding','','[]','節逢清景空，氣占二儀中。獨喜登高日，先知應候風。',72,'御定全唐詩/json/507.json','["節逢清景空，氣占二儀中。獨喜登高日，先知應候風。", "瑞呈光舜化，慶表盛堯聰。況與承時葉，還將入律同。", "微微萬井逼，習習九門通。繞殿爐煙起，殷勤報歲功。"]'),
('yuding-3','春風扇微和','蔣防','唐','御定全唐诗','yuding','','[]','麗日催遲景，和風扇早春。暖浮丹鳳闕，韶媚黑龍津。',72,'御定全唐詩/json/507.json','["麗日催遲景，和風扇早春。暖浮丹鳳闕，韶媚黑龍津。", "澹蕩迎仙仗，霏微送畫輪。綠搖官柳散，紅待禁花新。", "舞席皆回雪，歌筵暗送塵。幸當陽律候，惟願及佳辰。"]'),
('yuding-4','日暖萬年枝','蔣防','唐','御定全唐诗','yuding','','[]','新陽歸上苑，嘉樹獨含妍。散漫添和氣，曈曨卷曙煙。',72,'御定全唐詩/json/507.json','["新陽歸上苑，嘉樹獨含妍。散漫添和氣，曈曨卷曙煙。", "流輝宜聖日，接影貴芳年。自與恩光近，那關煦嫗偏。", "結根誠得地，表壽願符天。誰道淩寒質，從茲不曖然。"]'),
('yuding-5','秋月懸清輝','蔣防','唐','御定全唐诗','yuding','','[]','秋月沿霄漢，亭亭委素輝。山明桂花發，池滿夜珠歸。',72,'御定全唐詩/json/507.json','["秋月沿霄漢，亭亭委素輝。山明桂花發，池滿夜珠歸。", "入牖人偏攬，臨枝鵲正飛。影連平野淨，輪度曉雲微。", "晶晃浮輕露，裴回映薄帷。此時千里道，延望獨依依。"]'),
('yuding-6','八風從律','蔣防','唐','御定全唐诗','yuding','','[]','制律窺元化，因聲感八風。還從萬籟起，更與五音同。',72,'御定全唐詩/json/507.json','["制律窺元化，因聲感八風。還從萬籟起，更與五音同。", "習習蘆灰上，泠泠玉管中。氣隨時物好，響徹霽天空。", "自得陰陽順，能令惠澤通。願吹寒穀裏，從此達前蒙。"]'),
('yuding-7','藩臣戀魏闕','蔣防','唐','御定全唐诗','yuding','','[]','剖竹隨皇命，分憂鎮大藩。恩波懷魏闕，獻納望天閽。',72,'御定全唐詩/json/507.json','["剖竹隨皇命，分憂鎮大藩。恩波懷魏闕，獻納望天閽。", "政奉南風順，心依北極尊。夢魂通玉陛，動息寄朱軒。", "直以蒸黎念，思陳政化源。如何子牟意，今古道斯存。"]'),
('yuding-8','秋稼如雲','蔣防','唐','御定全唐诗','yuding','','[]','肆目如雲處，三田大有秋。蔥蘢初蔽野，散漫正盈疇。',72,'御定全唐詩/json/507.json','["肆目如雲處，三田大有秋。蔥蘢初蔽野，散漫正盈疇。", "稍混從龍勢，甯同觸石幽。紫芒分冪冪，青穎澹油油。", "始愜倉箱望，終無滅裂憂。西成知不遠，雨露複何酬。"]'),
('yuding-9','玉卮無當','蔣防','唐','御定全唐诗','yuding','','[]','美玉常為器，茲焉變漏卮。酒漿悲莫挹，樽俎念空施。',72,'御定全唐詩/json/507.json','["美玉常為器，茲焉變漏卮。酒漿悲莫挹，樽俎念空施。", "符彩功難補，盈虛數已虧。豈惟孤玩好，抑亦類瑕疵。", "清越音雖在，操持意漸隳。賦形期大匠，良璞勿同斯。"]'),
('yuding-10','至人無夢','蔣防','唐','御定全唐诗','yuding','','[]','已賾希微理，知將靜默鄰。坐忘寧有夢，跡滅未凝神。',72,'御定全唐詩/json/507.json','["已賾希微理，知將靜默鄰。坐忘寧有夢，跡滅未凝神。", "化蝶誠知幻，征蘭匪契真。抱玄雖解帶，守一自離塵。", "寥朗壺中曉，虛明洞裏春。翛然碧霞客，那比漆園人。"]'),
('yuding-11','玄都樓桃','蔣防','唐','御定全唐诗','yuding','','[]','舊傳天上千年熟，今日人間五日香。',32,'御定全唐詩/json/507.json','["舊傳天上千年熟，今日人間五日香。", "紅軟滿枝須作意，莫交方朔施偷將。"]'),
('yuding-12','題李賓客舊居','李虞','唐','御定全唐诗','yuding','','[]','逢時不得致升平，豈是明君忘姓名。',32,'御定全唐詩/json/507.json','["逢時不得致升平，豈是明君忘姓名。", "眼暗發枯緣世事，今來無淚哭先生。"]'),
('yuding-13','前相國贊皇公早葺平泉山居暫還憩旋起赴詔命作鎮浙右輒抒懷賦四言詩十四首奉寄','裴潾','唐','御定全唐诗','yuding','','[]','動複有原，進退有期。用在得正，明以知微。夫惟哲人，',360,'御定全唐詩/json/507.json','["動複有原，進退有期。用在得正，明以知微。夫惟哲人，", "植愛在根，鐘福有兆。珠潛巨海，玉蘊昆嶠。披室生白，", "曆難求試，執憲成風。四鎮咸乂，三階以融。捧日柱天，", "我力或屈，我躬莫汙。三黜如飴，三起惟懼。再賓為寵，", "有鳳自南，亦翽其羽。好姱佳麗，于伊之滸。五彩含章，", "鑿龍中辟，伊原古奔。下有秘洞，豁起石門。竹澗水橫，", "南溪回舟，西嶺望竦。水遠如空，山微似巃。二室峰連，", "飛泉掛空，如決天潯。萬仞懸注，直貫潭心。月正中央，", "鳥之在巢，風起林搖。退翔城顛，翠虯捫天。雨止雪旋，", "邈矣其山，默矣其泉。", "寢丘之田，土山之上。孫既貽謀，謝亦遐想。儉則為福，", "其風自西，言發帝庭。飄彼黃素，墮於山楹。公拜稽首，", "公昔南邁，我不及睹。言旋舊觀，莫獲安語。今則不遑，", "山嵇之舊，劉盧之恩。舉世莫尚，惟公是敦。哀我蠢蠢，", "迢迢秦塞，南望吳門。對酒不飲，設琴不援。何以代面，"]'),
('yuding-14','白牡丹','裴潾','唐','御定全唐诗','yuding','','[]','長安豪貴惜春殘，爭賞先開紫牡丹。',32,'御定全唐詩/json/507.json','["長安豪貴惜春殘，爭賞先開紫牡丹。", "別有玉杯承露冷，無人起就月中看。"]'),
('yuding-15','送黃明府曄赴岳州湘陰任','劉三複','唐','御定全唐诗','yuding','','[]','擬占名場第一科，龍門十上困風波。三年護塞從戎遠，',40,'御定全唐詩/json/507.json','["擬占名場第一科，龍門十上困風波。三年護塞從戎遠，", "遙知布惠蘇民後，應向祠堂吊汨羅。"]'),
('yuding-16','留題桂州碧潯亭','韋瓘','唐','御定全唐诗','yuding','','[]','半年領郡固無勞，一日為心素所操。輪奐未成繩墨在，',40,'御定全唐詩/json/507.json','["半年領郡固無勞，一日為心素所操。輪奐未成繩墨在，", "從此歸耕洛川上，大千江路任風濤。"]'),
('yuding-17','贈毛仙翁','崔郾','唐','御定全唐诗','yuding','','[]','存亡去住一壺中，兄事安期弟葛洪。甲子已過千歲鶴，',40,'御定全唐詩/json/507.json','["存亡去住一壺中，兄事安期弟葛洪。甲子已過千歲鶴，", "終待此身無系累，武陵山下等黃公。"]'),
('yuding-0','鳥散餘花落','孔溫業','唐','御定全唐诗','yuding','','[]','美景春堪賞，芳園白日斜。共看飛好鳥，複見落餘花。',72,'御定全唐詩/json/508.json','["美景春堪賞，芳園白日斜。共看飛好鳥，複見落餘花。", "來往驚翻電，經過想散霞。雨餘飄處處，風送滿家家。", "求友聲初去，離枝色可嗟。從茲時節換，誰為惜年華。"]'),
('yuding-1','鳥散餘花落','趙存約','唐','御定全唐诗','yuding','','[]','春曉游禽集，幽庭幾樹花。坐來驚豔色，飛去墮晴霞。',72,'御定全唐詩/json/508.json','["春曉游禽集，幽庭幾樹花。坐來驚豔色，飛去墮晴霞。", "翅拂繁枝落，風添舞影斜。彩雲飄玉砌，絳雪下仙家。", "分散音初靜，凋零蕊帶葩。空階瞻玩久，應共惜年華。"]'),
('yuding-2','鳥散餘花落','竇洵直','唐','御定全唐诗','yuding','','[]','晚樹春歸後，花飛鳥下初。參差分羽翼，零落滿空虛。',72,'御定全唐詩/json/508.json','["晚樹春歸後，花飛鳥下初。參差分羽翼，零落滿空虛。", "風外清香轉，林邊豔影疏。輕盈疑雪舞，仿佛似霞舒。", "萬片情難極，遷喬思有餘。微臣一何幸，吟賞對寒居。"]'),
('yuding-3','公無渡河','陳標','唐','御定全唐诗','yuding','','[]','陰雲颯颯浪花愁，半度驚湍半掛舟。聲盡雲天君不住，',40,'御定全唐詩/json/508.json','["陰雲颯颯浪花愁，半度驚湍半掛舟。聲盡雲天君不住，", "餘魄豈能銜木石，獨將遺恨付箜篌。"]'),
('yuding-4','秦王卷衣','陳標','唐','御定全唐诗','yuding','','[]','秦王宮闕靄春煙，珠樹瓊枝近碧天。禦氣馨香蘇合啟，',40,'御定全唐詩/json/508.json','["秦王宮闕靄春煙，珠樹瓊枝近碧天。禦氣馨香蘇合啟，", "從此咸陽一回首，暮雲愁色已千年。"]'),
('yuding-5','婕妤怨','陳標','唐','御定全唐诗','yuding','','[]','掌上恩移玉帳空，香珠滿眼泣春風。飄零怨柳凋眉翠，',40,'御定全唐詩/json/508.json','["掌上恩移玉帳空，香珠滿眼泣春風。飄零怨柳凋眉翠，", "笙歌處處回天眷，獨自無情長信宮。"]'),
('yuding-6','飲馬長城窟','陳標','唐','御定全唐诗','yuding','','[]','日日風吹虜騎塵，年年飲馬漢營人。千堆戰骨那知主，',40,'御定全唐詩/json/508.json','["日日風吹虜騎塵，年年飲馬漢營人。千堆戰骨那知主，", "金鞍玉勒無顏色，淚滿征衣怨暴秦。"]'),
('yuding-7','江南行','陳標','唐','御定全唐诗','yuding','','[]','水光春色滿江天，蘋葉風吹荷葉錢。香蟻翠旗臨岸市，',40,'御定全唐詩/json/508.json','["水光春色滿江天，蘋葉風吹荷葉錢。香蟻翠旗臨岸市，", "不怕江洲芳草暮，待將秋興折湖蓮。"]'),
('yuding-8','長安秋思','陳標','唐','御定全唐诗','yuding','','[]','吳女秋機織曙霜，冰蠶吐絲月盈筐。金刀玉指裁縫促，',40,'御定全唐詩/json/508.json','["吳女秋機織曙霜，冰蠶吐絲月盈筐。金刀玉指裁縫促，", "唯愁陌上芳菲度，狼藉風池荷葉黃。"]'),
('yuding-9','贈元和十三年登第進士','陳標','唐','御定全唐诗','yuding','','[]','春官南院粉牆東，地色初分月色紅。文字一千重馬擁，',40,'御定全唐詩/json/508.json','["春官南院粉牆東，地色初分月色紅。文字一千重馬擁，", "莫怪雲泥從此別，總曾惆悵去年中。"]'),
('yuding-10','焦桐樹','陳標','唐','御定全唐诗','yuding','','[]','江上烹魚采野樵，鸞枝摧折半曾燒。未經良匠材雖散，',40,'御定全唐詩/json/508.json','["江上烹魚采野樵，鸞枝摧折半曾燒。未經良匠材雖散，", "還能萬里傳山水，三峽泉聲豈寂寥。"]'),
('yuding-11','寄友人','陳標','唐','御定全唐诗','yuding','','[]','杜甫在時貪入蜀，孟郊生處卻歸秦。',32,'御定全唐詩/json/508.json','["杜甫在時貪入蜀，孟郊生處卻歸秦。", "如今始會麻姑意，借問山川與後人。"]'),
('yuding-12','啄木謠','陳標','唐','御定全唐诗','yuding','','[]','丁丁向晚急還稀，啄遍庭槐未肯歸。',32,'御定全唐詩/json/508.json','["丁丁向晚急還稀，啄遍庭槐未肯歸。", "終日與君除蠹害，莫嫌無事不頻飛。"]'),
('yuding-13','僧院牡丹','陳標','唐','御定全唐诗','yuding','','[]','琉璃地上開紅豔，碧落天頭散曉霞。',32,'御定全唐詩/json/508.json','["琉璃地上開紅豔，碧落天頭散曉霞。", "應是向西無地種，不然爭肯重蓮花。"]'),
('yuding-14','蜀葵','陳標','唐','御定全唐诗','yuding','','[]','眼前無奈蜀葵何，淺紫深紅數百窠。',32,'御定全唐詩/json/508.json','["眼前無奈蜀葵何，淺紫深紅數百窠。", "能共牡丹爭幾許，得人嫌處只緣多。"]'),
('yuding-15','離家','袁不約','唐','御定全唐诗','yuding','','[]','步步遠晨昏，淒心出裏門。見烏唯有淚，看雁更傷魂。',48,'御定全唐詩/json/508.json','["步步遠晨昏，淒心出裏門。見烏唯有淚，看雁更傷魂。", "宿酒寧辭醉，回書諱苦言。野人應怪笑，不解愛田園。"]'),
('yuding-16','送人至嶺南','袁不約','唐','御定全唐诗','yuding','','[]','度嶺春風暖，花多不識名。瘴煙迷月色，巴路傍溪聲。',48,'御定全唐詩/json/508.json','["度嶺春風暖，花多不識名。瘴煙迷月色，巴路傍溪聲。", "畏藥將銀試，防蛟避水行。知君憐酒興，莫殺醉猩猩。"]'),
('yuding-17','長安夜遊','袁不約','唐','御定全唐诗','yuding','','[]','鳳城連夜九門通，帝女皇妃出漢宮。千乘寶蓮珠箔卷，',40,'御定全唐詩/json/508.json','["鳳城連夜九門通，帝女皇妃出漢宮。千乘寶蓮珠箔卷，", "長樂曉鐘歸騎後，遺簪墮珥滿街中。"]'),
('yuding-18','病宮人','袁不約','唐','御定全唐诗','yuding','','[]','佳人臥病動經秋，簾幕襤縿不掛鉤。四體強扶藤夾膝，',40,'御定全唐詩/json/508.json','["佳人臥病動經秋，簾幕襤縿不掛鉤。四體強扶藤夾膝，", "惆悵近來銷瘦盡，淚珠時傍枕函流。"]'),
('yuding-19','句','袁不約','唐','御定全唐诗','yuding','','[]','愁聲秋繞杵，寒色碧歸山。',24,'御定全唐詩/json/508.json','["愁聲秋繞杵，寒色碧歸山。", "送將歡笑去，收得寂寥回。"]'),
('yuding-20','臨邛怨','李餘','唐','御定全唐诗','yuding','','[]','藕花衫子柳花裙，多著沈香慢火熏。',32,'御定全唐詩/json/508.json','["藕花衫子柳花裙，多著沈香慢火熏。", "惆悵妝成君不見，空教綠綺伴文君。"]'),
('yuding-21','寒食','李餘','唐','御定全唐诗','yuding','','[]','玉輪江上雨絲絲，公子游春醉不知。',32,'御定全唐詩/json/508.json','["玉輪江上雨絲絲，公子游春醉不知。", "翦渡歸來風正急，水濺鞍帕嫩鵝兒。"]'),
('yuding-22','句','李餘','唐','御定全唐诗','yuding','','[]','長安東門別，立馬生白髮。',36,'御定全唐詩/json/508.json','["長安東門別，立馬生白髮。", "霽後軒蓋繁，南山瑞煙發。", "嘗憂車馬繁，土薄聞水聲。"]'),
('yuding-23','至日上公獻壽酒','白敏中','唐','御定全唐诗','yuding','','[]','候曉天門辟，朝天萬國同。瑞雲升觀闕，香氣映華宮。',72,'御定全唐詩/json/508.json','["候曉天門辟，朝天萬國同。瑞雲升觀闕，香氣映華宮。", "日色臨仙籞，龍顏對昊宮。羽儀瞻百姓，獻壽侍三公。", "化被君王洽，恩沾草木豐。自欣朝玉座，宴此詠皇風。"]'),
('yuding-24','賀收復秦原諸州詩','白敏中','唐','御定全唐诗','yuding','','[]','一詔皇城四海頒，醜戎無數束身還。戍樓吹笛人休戰，',40,'御定全唐詩/json/508.json','["一詔皇城四海頒，醜戎無數束身還。戍樓吹笛人休戰，", "西邊北塞今無事，為報東南夷與蠻。"]'),
('yuding-25','句','白敏中','唐','御定全唐诗','yuding','','[]','南浦花臨水，東樓月映風。（鎮劍南，經忠州，尋樂天',34,'御定全唐詩/json/508.json','["南浦花臨水，東樓月映風。（鎮劍南，經忠州，尋樂天", "遺跡作。見《紀事》）"]'),
('yuding-26','遣興','李敬方','唐','御定全唐诗','yuding','','[]','果窺丹灶鶴，莫羨白頭翁。日月仙壺外，筋骸藥臼中。',48,'御定全唐詩/json/508.json','["果窺丹灶鶴，莫羨白頭翁。日月仙壺外，筋骸藥臼中。", "雲歸無定所，鳥跡不留空。何必勞方寸，嶇崎問遠公。"]'),
('yuding-27','勸酒','李敬方','唐','御定全唐诗','yuding','','[]','不向花前醉，花應解笑人。只憂連夜雨，又過一年春。',48,'御定全唐詩/json/508.json','["不向花前醉，花應解笑人。只憂連夜雨，又過一年春。", "日日無窮事，區區有限身。若非杯酒裏，何以寄天真。"]'),
('yuding-28','近無西耗','李敬方','唐','御定全唐诗','yuding','','[]','遠戎兵壓境，遷客淚橫襟。烽候驚春塞，縲囚困越吟。',48,'御定全唐詩/json/508.json','["遠戎兵壓境，遷客淚橫襟。烽候驚春塞，縲囚困越吟。", "自憐牛馬走，未識犬羊心。一月無消息，西看日又沈。"]'),
('yuding-29','天臺晴望','李敬方','唐','御定全唐诗','yuding','','[]','天臺十二旬，一片雨中春。林果黃梅盡，山苗半夏新。',48,'御定全唐詩/json/508.json','["天臺十二旬，一片雨中春。林果黃梅盡，山苗半夏新。", "陽烏晴展翅，陰魄夜飛輪。坐冀無雲物，分明見北辰。"]'),
('yuding-30','聞高侍禦卒貶所','李敬方','唐','御定全唐诗','yuding','','[]','西京高院長，直氣似吾徒。走馬論邊備，飛聲感廟謨。',48,'御定全唐詩/json/508.json','["西京高院長，直氣似吾徒。走馬論邊備，飛聲感廟謨。", "官移人未察，身沒事多符。寂寞他年後，名編野史無。"]'),
('yuding-31','題黃山湯院','李敬方','唐','御定全唐诗','yuding','','[]','楚鎮惟黃岫，靈泉浴聖源。煎熬何處所，爐炭孰司存。',456,'御定全唐詩/json/508.json','["楚鎮惟黃岫，靈泉浴聖源。煎熬何處所，爐炭孰司存。", "沙暖泉長拂，霜籠水更溫。不疏還自決，雖撓未嘗渾。", "地啟岩為洞，天開石作盆。常留今日色，不減故年痕。", "陰焰潛生海，陽光暗燭坤。定應鄰火宅，非獨過焦原。", "龍訝經冬潤，鶯疑滿穀暄。善烹寒食茗，能變早春園。", "及物功何大，隨流道益尊。潔齋齊物主，療病奪醫門。", "外秘千峰秀，旁通百潦奔。禪家休問疾，騷客罷招魂。", "臥理黔川守，分憂漢主恩。慘傷因有暇，徒禦誡無喧。", "癢悶頭風切，爬搔臂力煩。披榛通白道，束馬置朱幡。", "謝屐緣危磴，戎裝逗遠村。慢游登竹徑，高步入山根。", "崖巘差行灶，蓬茅過小軒。禦寒增帳幕，甃影盡璵璠。", "不與華池語，寧將浴室論。洗心過頃刻，浸發迨朝暾。", "汗洽聊箕踞，支羸暫虎蹲。濯纓閑更入，漱齒渴仍吞。", "氣燠勝重絸，風和敵一尊。適來還蹭蹬，複出又攀援。", "形穢忻除垢，神囂喜破昏。明夷征立象，既濟感文言。", "已閡眠沙麂，仍妨臥石猿。香驅蒸霧起，煙霿濕雲屯。", "破險更祠宇，憑高易廟垣。舊基絕仄足，新構忽行鵷。", "勝地非無棟，征途遽改轅。貪程歸路遠，折政訟庭繁。", "興往留年月，詩成遺子孫。已鐫東壁石，名姓寄無垠。"]'),
('yuding-32','太和公主還宮','李敬方','唐','御定全唐诗','yuding','','[]','二紀煙塵外，淒涼轉戰歸。胡笳悲蔡琰，漢使泣明妃。',120,'御定全唐詩/json/508.json','["二紀煙塵外，淒涼轉戰歸。胡笳悲蔡琰，漢使泣明妃。", "金殿更戎幄，青祛換毳衣。登車隨伴仗，謁廟入中闈。", "湯沐疏封在，關山故夢非。笑看鴻北向，休詠鵲南飛。", "宮髻憐新樣，庭柯想舊圍。生還侍兒少，熟識內家稀。", "鳳去樓扃夜，鸞孤匣掩輝。應憐禁園柳，相見倍依依。"]'),
('yuding-33','汴河直進船','李敬方','唐','御定全唐诗','yuding','','[]','汴水通淮利最多，生人為害亦相和。',32,'御定全唐詩/json/508.json','["汴水通淮利最多，生人為害亦相和。", "東南四十三州地，取盡脂膏是此河。"]'),
('yuding-34','享太廟樂章','李回','唐','御定全唐诗','yuding','','[]','受天明命，敷佑下土。化時以儉，衛文以武。',40,'御定全唐詩/json/508.json','["受天明命，敷佑下土。化時以儉，衛文以武。", "氛消夷夏，俗臻往古。億萬斯年，形於律呂。"]'),
('yuding-35','天長路別朱大山路卻寄','李回','唐','御定全唐诗','yuding','','[]','驛騎難隨伴，尋山半憶君。蒼崖殘月路，猶數過溪雲。',24,'御定全唐詩/json/508.json','["驛騎難隨伴，尋山半憶君。蒼崖殘月路，猶數過溪雲。"]'),
('yuding-36','寄酬朱大後亭夜坐留別','李回','唐','御定全唐诗','yuding','','[]','十夜郡城宿，苦吟身未閑。那堪西郭別，雪路問青山。',24,'御定全唐詩/json/508.json','["十夜郡城宿，苦吟身未閑。那堪西郭別，雪路問青山。"]'),
('yuding-37','祖龍行','常楚老','唐','御定全唐诗','yuding','','[]','黑雲兵氣射天裂，壯士朝眠夢冤結。祖龍一夜死沙丘，',48,'御定全唐詩/json/508.json','["黑雲兵氣射天裂，壯士朝眠夢冤結。祖龍一夜死沙丘，", "墓接驪山土未幹，瑞光已向芒碭起。陳勝城中鼓三下，"]'),
('yuding-38','江上蚊子','常楚老','唐','御定全唐诗','yuding','','[]','飄搖挾翅亞紅腹，江邊夜起如雷哭。請問貪婪一點心。',64,'御定全唐詩/json/508.json','["飄搖挾翅亞紅腹，江邊夜起如雷哭。請問貪婪一點心。", "臭腐填腹幾多足。越女如花住江曲，嫦娥夜夜凝雙睩。", "怕君撩亂錦窗中，十軸輕綃圍夜玉。"]'),
('yuding-39','句','常楚老','唐','御定全唐诗','yuding','','[]','一從黃帝葬橋山，碧落千門鎖元氣。（《天上行》。',30,'御定全唐詩/json/508.json','["一從黃帝葬橋山，碧落千門鎖元氣。（《天上行》。", "《詩話總歸》）"]'),
('yuding-40','九成宮','李甘','唐','御定全唐诗','yuding','','[]','中原無鹿海無波，鳳輦鸞旗出幸多。',32,'御定全唐詩/json/508.json','["中原無鹿海無波，鳳輦鸞旗出幸多。", "今日故宮歸寂寞，太平功業在山河。"]'),
('yuding-41','謁李相不遇','平曾','唐','御定全唐诗','yuding','','[]','老夫三日門前立，珠箔銀屏晝不開。',32,'御定全唐詩/json/508.json','["老夫三日門前立，珠箔銀屏晝不開。", "詩卷卻拋書袋裏，正如閑看華山來。"]'),
('yuding-42','留別薛僕射','平曾','唐','御定全唐诗','yuding','','[]','梯山航海幾崎嶇，來謁金陵薛大夫。毛髮豎時趨劍戟，',40,'御定全唐詩/json/508.json','["梯山航海幾崎嶇，來謁金陵薛大夫。毛髮豎時趨劍戟，", "明日過江風景好，不堪回首望勾吳。"]'),
('yuding-43','縶白馬詩上薛僕射','平曾','唐','御定全唐诗','yuding','','[]','白馬披鬃練一團，今朝被絆欲行難。雪中放去空留跡，',40,'御定全唐詩/json/508.json','["白馬披鬃練一團，今朝被絆欲行難。雪中放去空留跡，", "自知毛骨還應異，更請孫陽仔細看。"]'),
('yuding-44','題所書黃庭經後','景審','唐','御定全唐诗','yuding','','[]','金粉為書重莫過，黃庭舊許右軍多。',32,'御定全唐詩/json/508.json','["金粉為書重莫過，黃庭舊許右軍多。", "請看今日酬恩德，何似當年為愛鵝。"]'),
('yuding-45','句','景審','唐','御定全唐诗','yuding','','[]','暮鴉不噪禁城樹，衙鼓未殘兵衛秋。',16,'御定全唐詩/json/508.json','["暮鴉不噪禁城樹，衙鼓未殘兵衛秋。"]'),
('yuding-0','秋日陝州道中作','顧非熊','唐','御定全唐诗','yuding','','[]','孤客秋風裏，驅車入陝西。關河午時路，村落一聲雞。',48,'御定全唐詩/json/509.json','["孤客秋風裏，驅車入陝西。關河午時路，村落一聲雞。", "樹勢標秦遠，天形到嶽低。誰知我名姓，來往自棲棲。"]'),
('yuding-1','經杭州','顧非熊','唐','御定全唐诗','yuding','','[]','郡郭繞江濆，人家近白雲。晚濤臨檻看，夜櫓隔城聞。',48,'御定全唐詩/json/509.json','["郡郭繞江濆，人家近白雲。晚濤臨檻看，夜櫓隔城聞。", "浦轉山初盡，虹斜雨未分。有誰知我意，心緒逐鷗群。"]'),
('yuding-2','經河中','顧非熊','唐','御定全唐诗','yuding','','[]','一望蒲城路，關河氣象雄。樓臺山色裏，楊柳水聲中。',48,'御定全唐詩/json/509.json','["一望蒲城路，關河氣象雄。樓臺山色裏，楊柳水聲中。", "思起懷吳客，行斜向磧鴻。我來尋古跡，唯見舜祠風。"]'),
('yuding-3','送僧歸洞庭','顧非熊','唐','御定全唐诗','yuding','','[]','江山萬萬重，歸去指何峰。未入連雲寺，先齋越浪鐘。',48,'御定全唐詩/json/509.json','["江山萬萬重，歸去指何峰。未入連雲寺，先齋越浪鐘。", "島香回棧柏，秋蔭出庵松。若救吳人病，須降震澤龍。"]'),
('yuding-4','題覺真上人院','顧非熊','唐','御定全唐诗','yuding','','[]','長安車馬地，此院閉松聲。新罷九天講，舊曾諸嶽行。',48,'御定全唐詩/json/509.json','["長安車馬地，此院閉松聲。新罷九天講，舊曾諸嶽行。", "能詩因作偈，好客豈關名。約我中秋夜，同來看月明。"]'),
('yuding-5','寄太白無能禪師','顧非熊','唐','御定全唐诗','yuding','','[]','太白山中寺，師居最上方。獵人偷佛火，櫟鼠戲禪床。',48,'御定全唐詩/json/509.json','["太白山中寺，師居最上方。獵人偷佛火，櫟鼠戲禪床。", "定久衣塵積，行稀徑草長。有誰來問法，林杪過殘陽。"]'),
('yuding-6','舒州酬別侍禦','顧非熊','唐','御定全唐诗','yuding','','[]','故交他郡見，下馬失愁容。執手向殘日，分襟在晚鐘。',48,'御定全唐詩/json/509.json','["故交他郡見，下馬失愁容。執手向殘日，分襟在晚鐘。", "鄉心隨皖水，客路過廬峰。眾惜君材器，何為滯所從。"]'),
('yuding-7','姚岩寺路懷友','顧非熊','唐','御定全唐诗','yuding','','[]','路向姚岩寺，多行洞壑間。鶴聲連塢靜，溪色帶村閑。',48,'御定全唐詩/json/509.json','["路向姚岩寺，多行洞壑間。鶴聲連塢靜，溪色帶村閑。", "疏葉秋前渚，斜陽雨外山。憐君不得見，詩思最相關。"]'),
('yuding-8','天河閣到啼猿閣即事','顧非熊','唐','御定全唐诗','yuding','','[]','萬壑褒中路，何層不架虛。濕雲和棧起，燋枿帶佘餘。',48,'御定全唐詩/json/509.json','["萬壑褒中路，何層不架虛。濕雲和棧起，燋枿帶佘餘。", "岩狖牽垂果，湍禽接迸魚。每逢維艇處，塢裏有人居。"]'),
('yuding-9','夏日會修行段將軍宅','顧非熊','唐','御定全唐诗','yuding','','[]','愛君書院靜，莎覆蘚階濃。連穗古藤暗，領雛幽鳥重。',48,'御定全唐詩/json/509.json','["愛君書院靜，莎覆蘚階濃。連穗古藤暗，領雛幽鳥重。", "樽前迎遠客，林杪見晴峰。誰謂朱門內，雲山滿座逢。"]'),
('yuding-10','送杭州姚員外','顧非熊','唐','御定全唐诗','yuding','','[]','浙江江上郡，楊柳到時春。塹起背城雁，帆分向海人。',48,'御定全唐詩/json/509.json','["浙江江上郡，楊柳到時春。塹起背城雁，帆分向海人。", "嶠雲侵寺吐，汀月隔樓新。靜理更何事，還應詠白蘋。"]'),
('yuding-11','送樸處士歸新羅','顧非熊','唐','御定全唐诗','yuding','','[]','少年離本國，今去已成翁。客夢孤舟裏，鄉山積水東。',48,'御定全唐詩/json/509.json','["少年離本國，今去已成翁。客夢孤舟裏，鄉山積水東。", "鼇沈崩巨岸，龍鬥出遙空。學得中華語，將歸誰與同。"]'),
('yuding-12','送馬戴入山','顧非熊','唐','御定全唐诗','yuding','','[]','古木亂重重，何人識去蹤。斜陽收萬壑，圓月上三峰。',48,'御定全唐詩/json/509.json','["古木亂重重，何人識去蹤。斜陽收萬壑，圓月上三峰。", "雲裏泉縈石，窗間鳥下松。唯應采藥客，時與此相逢。"]'),
('yuding-13','送喻鳧春歸江南','顧非熊','唐','御定全唐诗','yuding','','[]','去年登第客，今日及春歸。鶯影離秦馬，蓮香入楚衣。',48,'御定全唐詩/json/509.json','["去年登第客，今日及春歸。鶯影離秦馬，蓮香入楚衣。", "裏閭爭慶賀，親戚共光輝。唯我門前浦，苔應滿釣磯。"]'),
('yuding-14','送友人及第歸蘇州','顧非熊','唐','御定全唐诗','yuding','','[]','見君先得意，希我命還通。不道才堪並，多緣蹇共同。',48,'御定全唐詩/json/509.json','["見君先得意，希我命還通。不道才堪並，多緣蹇共同。", "鶴鳴荒苑內，魚躍夜潮中。若問家山路，知連震澤東。"]'),
('yuding-15','送皇甫司錄赴黔南幕','顧非熊','唐','御定全唐诗','yuding','','[]','黔南從事客，祿利先來饒。官受外台屈，家移一舸遙。',48,'御定全唐詩/json/509.json','["黔南從事客，祿利先來饒。官受外台屈，家移一舸遙。", "夜猿聲不斷，寒木葉微凋。遠別因多感，新郎倍寂寥。"]'),
('yuding-16','寄九華山費拾遺','顧非熊','唐','御定全唐诗','yuding','','[]','先生九華隱，鳥道隔塵埃。石室和雲住，山田引燒開。',48,'御定全唐詩/json/509.json','["先生九華隱，鳥道隔塵埃。石室和雲住，山田引燒開。", "久聞仙客降，高臥詔書來。一入深林去，人間更不回。"]'),
('yuding-17','雁','顧非熊','唐','御定全唐诗','yuding','','[]','逐暖來南國，迎寒背朔雲。下時波勢出，起處陣形分。',48,'御定全唐詩/json/509.json','["逐暖來南國，迎寒背朔雲。下時波勢出，起處陣形分。", "聲急奔前侶，行低續後群。何人寄書劄，絕域可知聞。"]'),
('yuding-18','銅雀妓','顧非熊','唐','御定全唐诗','yuding','','[]','鴉散陵樹曉，筵開繐帳空。嬋娟寵休妒，歌舞怨來同。',48,'御定全唐詩/json/509.json','["鴉散陵樹曉，筵開繐帳空。嬋娟寵休妒，歌舞怨來同。", "往事與塵化，新愁生曲終。回軒葉正落，寂寞聽秋風。"]'),
('yuding-19','早秋雨夕','顧非熊','唐','御定全唐诗','yuding','','[]','貧居常寂寞，況複是秋天。黃葉如霜後，清風似水邊。',48,'御定全唐詩/json/509.json','["貧居常寂寞，況複是秋天。黃葉如霜後，清風似水邊。", "中宵疑有雁，當夕暫無蟬。就枕終難寐，殘燈滅又然。"]'),
('yuding-20','天津橋晚望','顧非熊','唐','御定全唐诗','yuding','','[]','晴登洛橋望，寒色古槐稀。流水東不息，翠華西未歸。',48,'御定全唐詩/json/509.json','["晴登洛橋望，寒色古槐稀。流水東不息，翠華西未歸。", "雲收中嶽近，鐘出後宮微。回首禁門路，群鴉度落暉。"]'),
('yuding-21','月夜登王屋仙壇','顧非熊','唐','御定全唐诗','yuding','','[]','月臨峰頂壇，氣爽覺天寬。身去銀河近，衣沾玉露寒。',48,'御定全唐詩/json/509.json','["月臨峰頂壇，氣爽覺天寬。身去銀河近，衣沾玉露寒。", "雲中日已赤，山外夜初殘。即此是仙境，惟愁再上難。"]'),
('yuding-22','下第後曉坐','顧非熊','唐','御定全唐诗','yuding','','[]','遠客滯都邑，老驚時節催。海邊身夢覺，枕上鼓聲來。',48,'御定全唐詩/json/509.json','["遠客滯都邑，老驚時節催。海邊身夢覺，枕上鼓聲來。", "起見銀河沒，坐知閶闔開。何為此生內，終夜泣塵埃。"]'),
('yuding-23','下第後送友人不及','顧非熊','唐','御定全唐诗','yuding','','[]','失意經寒食，情偏感別離。來逢人已去，坐見柳空垂。',48,'御定全唐詩/json/509.json','["失意經寒食，情偏感別離。來逢人已去，坐見柳空垂。", "細雨飛黃鳥，新蒲長綠池。自傾相送酒，終不展愁眉。"]'),
('yuding-24','與無可宿輝公院','顧非熊','唐','御定全唐诗','yuding','','[]','夜僧同靜語，秋寺近嚴城。世路雖多梗，玄心各自明。',48,'御定全唐詩/json/509.json','["夜僧同靜語，秋寺近嚴城。世路雖多梗，玄心各自明。", "寒池清月彩，危閣聽林聲。倘許雙摩頂，隨緣萬劫生。"]'),
('yuding-25','題平陸縣亭','顧非熊','唐','御定全唐诗','yuding','','[]','孤亭臨峭岸，別有遠泉來。山與中條合，河逢一曲回。',48,'御定全唐詩/json/509.json','["孤亭臨峭岸，別有遠泉來。山與中條合，河逢一曲回。", "夜聲多雁過，晚色亂雲開。卻自求僮僕，淹留莫謾催。"]'),
('yuding-26','題馬儒乂石門山居','顧非熊','唐','御定全唐诗','yuding','','[]','尋君石門隱，山近漸無青。鹿跡入柴戶，樹身穿草亭。',48,'御定全唐詩/json/509.json','["尋君石門隱，山近漸無青。鹿跡入柴戶，樹身穿草亭。", "雲低收藥徑，苔惹取泉瓶。此地客難到，夜琴誰共聽。"]'),
('yuding-27','題春明門外鎮國禪院','顧非熊','唐','御定全唐诗','yuding','','[]','空門臨大道，師坐此中禪。過客自生敬，焚香惟默然。',48,'御定全唐詩/json/509.json','["空門臨大道，師坐此中禪。過客自生敬，焚香惟默然。", "書燈明象外，古木覆簷前。不得如馴鴿，人間萬慮牽。"]'),
('yuding-28','夏夜漢渚歸舟即事','顧非熊','唐','御定全唐诗','yuding','','[]','扁舟江瀨盡，歸路海山青。巨浸分圓象，危檣入眾星。',48,'御定全唐詩/json/509.json','["扁舟江瀨盡，歸路海山青。巨浸分圓象，危檣入眾星。", "雨遙明電影，蜃曉識樓形。不是長遊客，那知造化靈。"]'),
('yuding-29','酬均州鄭使君見送歸茅山','顧非熊','唐','御定全唐诗','yuding','','[]','餞行詩意厚，惜別獨筵重。解纜城邊柳，還舟海上峰。',48,'御定全唐詩/json/509.json','["餞行詩意厚，惜別獨筵重。解纜城邊柳，還舟海上峰。", "飲猿當瀨見，浴鳥帶槎逢。吏隱應難逐，為霖是蟄龍。"]'),
('yuding-30','成名後將歸茅山酬群公見送','顧非熊','唐','御定全唐诗','yuding','','[]','此名誰不得，人賀至公難。素業承家了，離筵去國歡。',48,'御定全唐詩/json/509.json','["此名誰不得，人賀至公難。素業承家了，離筵去國歡。", "暮天行雁斷，曉渡落潮寒。舊隱茅峰下，松根石上盤。"]'),
('yuding-31','酬陳摽評事喜及第與段何共貽','顧非熊','唐','御定全唐诗','yuding','','[]','至公平得意，自喜不因媒。榜入金門去，名從玉案來。',48,'御定全唐詩/json/509.json','["至公平得意，自喜不因媒。榜入金門去，名從玉案來。", "歡情聽鳥語，笑眼對花開。若擬華筵賀，當期醉百杯。"]'),
('yuding-32','關試後嘉會裏聞蟬感懷呈主司','顧非熊','唐','御定全唐诗','yuding','','[]','昔聞驚節換，常抱異鄉愁。今聽當名遂，方歡上國遊。',48,'御定全唐詩/json/509.json','["昔聞驚節換，常抱異鄉愁。今聽當名遂，方歡上國遊。", "吟才依樹午，風已報庭秋。並覺聲聲好，懷恩忽淚流。"]'),
('yuding-33','贈友人','顧非熊','唐','御定全唐诗','yuding','','[]','吾友昔同道，唯予今獨行。青雲期未遂，白髮鑷還生。',48,'御定全唐詩/json/509.json','["吾友昔同道，唯予今獨行。青雲期未遂，白髮鑷還生。", "舊隱連江色，新春聞鳥聲。休明獨不遇，何計可歸耕。"]'),
('yuding-34','落第後贈同居友人','顧非熊','唐','御定全唐诗','yuding','','[]','有情天地內，多感是詩人。見月長憐夜，看花又惜春。',48,'御定全唐詩/json/509.json','["有情天地內，多感是詩人。見月長憐夜，看花又惜春。", "愁為終日客，閑過少年身。寂寞正相對，笙歌滿四鄰。"]'),
('yuding-35','冬日寄蔡先輩校書京','顧非熊','唐','御定全唐诗','yuding','','[]','弱冠下茅嶺，中年道不行。舊交因貴絕，新月對愁生。',48,'御定全唐詩/json/509.json','["弱冠下茅嶺，中年道不行。舊交因貴絕，新月對愁生。", "旅思風飄葉，歸心雁過城。惟君知我苦，何異爨桐鳴。"]'),
('yuding-36','行經褒城寄興元姚從事','顧非熊','唐','御定全唐诗','yuding','','[]','往歲客龜城，同時聽鹿鳴。君兼蓮幕貴，我得桂枝榮。',48,'御定全唐詩/json/509.json','["往歲客龜城，同時聽鹿鳴。君兼蓮幕貴，我得桂枝榮。", "棧閣危初盡，褒川路忽平。心期一壺酒，靜話別離情。"]'),
('yuding-37','下第後寄高山人','顧非熊','唐','御定全唐诗','yuding','','[]','我家堂屋前，仰視大茅巔。潭靜鳥聲異，地寒松色鮮。',48,'御定全唐詩/json/509.json','["我家堂屋前，仰視大茅巔。潭靜鳥聲異，地寒松色鮮。", "人眠甕牖月，鹿飲竹門泉。多愧鄰高隱，無成又一年。"]'),
('yuding-38','寄紫閣無名新羅頭陀僧','顧非熊','唐','御定全唐诗','yuding','','[]','棕床已自檠，野宿更何營。大海誰同過，空山虎共行。',48,'御定全唐詩/json/509.json','["棕床已自檠，野宿更何營。大海誰同過，空山虎共行。", "身心相外盡，鬢髮定中生。紫閣人來禮，無名便是名。"]'),
('yuding-39','送信州盧員外兼寄薛員外','顧非熊','唐','御定全唐诗','yuding','','[]','五馬弋陽行，分憂出禁城。粉闈移席近，茜旆越疆行。',48,'御定全唐詩/json/509.json','["五馬弋陽行，分憂出禁城。粉闈移席近，茜旆越疆行。", "德茂榮方漸，仁深瑞必呈。疲甿複何幸，前政已殘聲。"]'),
('yuding-40','送於中丞入回鶻','顧非熊','唐','御定全唐诗','yuding','','[]','風沙萬里行，邊色看雙旌。去展中華禮，將安外國情。',48,'御定全唐詩/json/509.json','["風沙萬里行，邊色看雙旌。去展中華禮，將安外國情。", "朝衣驚異俗，牙帳見新正。料得歸來路，春深草未生。"]'),
('yuding-41','送李廓侍禦赴劍南','顧非熊','唐','御定全唐诗','yuding','','[]','鳥道見狼煙，元戎正急賢。圖書借朋友，吟詠入戈鋋。',48,'御定全唐詩/json/509.json','["鳥道見狼煙，元戎正急賢。圖書借朋友，吟詠入戈鋋。", "山色城池近，江聲鼓角連。不應誇戰勝，知在檄蠻篇。"]'),
('yuding-42','送友人歸漢陽','顧非熊','唐','御定全唐诗','yuding','','[]','樽前別楚客，雲水思縈回。秦野春將盡，商山花不開。',48,'御定全唐詩/json/509.json','["樽前別楚客，雲水思縈回。秦野春將盡，商山花不開。", "鷗驚帆乍起，虹見雨初來。自有歸期在，蟬聲處處催。"]'),
('yuding-43','送造微上人歸淮南覲兄','顧非熊','唐','御定全唐诗','yuding','','[]','到家方坐夏，柳巷對兄禪。雨斷蕪城路，虹分建鄴天。',48,'御定全唐詩/json/509.json','["到家方坐夏，柳巷對兄禪。雨斷蕪城路，虹分建鄴天。", "赴齋隨野鶴，迎水上漁船。終擬歸何處，三湘思渺然。"]'),
('yuding-44','賦得江邊柳送陳許郭員外','顧非熊','唐','御定全唐诗','yuding','','[]','拂水複含煙，行分古岸邊。春風正搖落，客思共悠然。',48,'御定全唐詩/json/509.json','["拂水複含煙，行分古岸邊。春風正搖落，客思共悠然。", "絮急頻縈水，根靈複系船。微陰覆離岸，只此醉昏眠。"]'),
('yuding-45','武宗挽歌詞二首','顧非熊','唐','御定全唐诗','yuding','','[]','睿略皇威遠，英風帝業開。竹林方受位，薤露忽興哀。',96,'御定全唐詩/json/509.json','["睿略皇威遠，英風帝業開。竹林方受位，薤露忽興哀。", "靜塞妖星落，和戎貴主回。龍髯不可附，空見望仙台。", "蒼生期漸泰，皇道欲中興。國用銷靈像，農功複冗僧。", "冕旒辭北闕，歌舞怨西陵。惟有金莖石，長宵對玉繩。"]'),
('yuding-46','會中賦得新年','顧非熊','唐','御定全唐诗','yuding','','[]','萬古如昨日，一年加一晨。暗生無限事，潛老幾多人。',48,'御定全唐詩/json/509.json','["萬古如昨日，一年加一晨。暗生無限事，潛老幾多人。", "歸路舊侶盡，故鄉回雁新。那堪獨惆悵，猶是白衣身。"]'),
('yuding-47','斜谷郵亭玩海棠花','顧非熊','唐','御定全唐诗','yuding','','[]','忽識海棠花，令人只歎嗟。豔繁惟共笑，香近試堪誇。',48,'御定全唐詩/json/509.json','["忽識海棠花，令人只歎嗟。豔繁惟共笑，香近試堪誇。", "駐騎忘山險，持杯任日斜。何川是多處，應繞羽人家。"]'),
('yuding-48','萬年厲員外宅殘菊','顧非熊','唐','御定全唐诗','yuding','','[]','才過重陽後，人心已為殘。近霜須苦惜，帶蝶更宜看。',48,'御定全唐詩/json/509.json','["才過重陽後，人心已為殘。近霜須苦惜，帶蝶更宜看。", "色減頻經雨，香銷恐漸寒。今朝陶令宅，不醉卻應難。"]'),
('yuding-49','題永福寺臨淮亭','顧非熊','唐','御定全唐诗','yuding','','[]','淮上前朝寺，因公始建亭。雖無山可望，多有鶴堪聽。',120,'御定全唐詩/json/509.json','["淮上前朝寺，因公始建亭。雖無山可望，多有鶴堪聽。", "引客閑垂釣，看僧靜灌瓶。帶潮秋見月，隔竹曉聞經。", "水氣侵衣冷，蘋風入座馨。路逢沙獺上，船值海人停。", "砧杵鳴孤戍，烏鳶下遠汀。連波芳草闊，極目暮天青。", "創置嗟心匠，幽棲得地形。常來勸農事，賴此近郊坰。"]'),
('yuding-50','陳情上鄭主司','顧非熊','唐','御定全唐诗','yuding','','[]','登第久無緣，歸情思渺然。藝慚公道日，身賤太平年。',168,'御定全唐詩/json/509.json','["登第久無緣，歸情思渺然。藝慚公道日，身賤太平年。", "未識笙歌樂，虛逢歲月遷。羈懷吟獨苦，愁眼愧花妍。", "求達非榮己，修辭欲繼先。秦城春十二，吳苑路三千。", "茅屋山嵐入，柴門海浪連。遙心猶送雁，歸夢不離船。", "時節思家夜，風霜作客天。庭闈乖旦暮，兄弟阻團圓。", "朝乏新知己，村荒舊業田。受恩期望外，效死誓生前。", "願察為裘意，彷徉和角篇。懇情今吐盡，萬一冀哀憐。"]'),
('yuding-51','長安清明言懷','顧非熊','唐','御定全唐诗','yuding','','[]','明時帝裏遇清明，還逐遊人出禁城。九陌芳菲鶯自囀，',40,'御定全唐詩/json/509.json','["明時帝裏遇清明，還逐遊人出禁城。九陌芳菲鶯自囀，", "春色來年誰是主，不堪憔悴更無成。"]'),
('yuding-52','出塞即事二首','顧非熊','唐','御定全唐诗','yuding','','[]','塞山行盡到烏延，萬頃沙堆見極邊。河上月沉鴻雁起，',80,'御定全唐詩/json/509.json','["塞山行盡到烏延，萬頃沙堆見極邊。河上月沉鴻雁起，", "此處遊人堪下淚，更聞終日望狼煙。", "賀蘭山便是戎疆，此去蕭關路幾荒。無限城池非漢界，", "回望風光成異域，誰能獻計複河湟。"]'),
('yuding-53','送李相公昭義平復起彼宣慰員外副行','顧非熊','唐','御定全唐诗','yuding','','[]','天井雖收寇未平，所司促戰急王程。曉馳雲騎穿花去，',40,'御定全唐詩/json/509.json','["天井雖收寇未平，所司促戰急王程。曉馳雲騎穿花去，", "時逢寒食遊人識，竟說從來有大名。"]'),
('yuding-54','送從叔尉澠池','顧非熊','唐','御定全唐诗','yuding','','[]','同登科第皆清列，尚愛東畿一尉閑。雖有田園供海畔，',40,'御定全唐詩/json/509.json','["同登科第皆清列，尚愛東畿一尉閑。雖有田園供海畔，", "白首青衫猶未換，又騎羸馬出函關。"]'),
('yuding-55','哭韓將軍','顧非熊','唐','御定全唐诗','yuding','','[]','將軍不復見儀形，笑語隨風入杳冥。戰馬舊騎嘶引葬，',40,'御定全唐詩/json/509.json','["將軍不復見儀形，笑語隨風入杳冥。戰馬舊騎嘶引葬，", "寂寞一家春色裏，百花開落滿山庭。"]'),
('yuding-56','崔卿雙白鷺','顧非熊','唐','御定全唐诗','yuding','','[]','朝客高清愛水禽，綠波雙鷺在園林。立當風裏絲搖急，',40,'御定全唐詩/json/509.json','["朝客高清愛水禽，綠波雙鷺在園林。立當風裏絲搖急，", "我鄉多傍門前見，坐覺煙波思不禁。"]'),
('yuding-57','子夜夏秋二曲','顧非熊','唐','御定全唐诗','yuding','','[]','相持薄羅扇，綠樹聽鳴蜩。君筵呈妙舞，香汗濕鮫綃。',48,'御定全唐詩/json/509.json','["相持薄羅扇，綠樹聽鳴蜩。君筵呈妙舞，香汗濕鮫綃。", "銀床梧葉下，便覺漏聲長。露砌蛩吟切，那憐白苧涼。"]'),
('yuding-58','關山月','顧非熊','唐','御定全唐诗','yuding','','[]','海上清光發，邊營照轉淒。深閨此宵夢，帶月過遼西。',24,'御定全唐詩/json/509.json','["海上清光發，邊營照轉淒。深閨此宵夢，帶月過遼西。"]'),
('yuding-59','採蓮詞','顧非熊','唐','御定全唐诗','yuding','','[]','纖手折芙蕖，花灑羅衫濕。女伴喚回船，前溪風浪急。',24,'御定全唐詩/json/509.json','["纖手折芙蕖，花灑羅衫濕。女伴喚回船，前溪風浪急。"]'),
('yuding-60','秋月夜','顧非熊','唐','御定全唐诗','yuding','','[]','旅雁迎風度，階翻月露華。砧聲鳴夜永，江上幾多家。',24,'御定全唐詩/json/509.json','["旅雁迎風度，階翻月露華。砧聲鳴夜永，江上幾多家。"]'),
('yuding-61','登樓','顧非熊','唐','御定全唐诗','yuding','','[]','登樓一南望，淮樹楚山連。見雁無書寄，歸吳定此年。',24,'御定全唐詩/json/509.json','["登樓一南望，淮樹楚山連。見雁無書寄，歸吳定此年。"]'),
('yuding-62','閶門書感','顧非熊','唐','御定全唐诗','yuding','','[]','鳧鷖踏波舞，樹色接橫塘。遠近蘼蕪綠，吳宮總夕陽。',24,'御定全唐詩/json/509.json','["鳧鷖踏波舞，樹色接橫塘。遠近蘼蕪綠，吳宮總夕陽。"]'),
('yuding-63','送內鄉張主簿赴任','顧非熊','唐','御定全唐诗','yuding','','[]','松窗久是餐霞客，山縣新為主印官。',32,'御定全唐詩/json/509.json','["松窗久是餐霞客，山縣新為主印官。", "混俗故來分利祿，不教長作異人看。"]'),
('yuding-64','瓜洲送朱萬言','顧非熊','唐','御定全唐诗','yuding','','[]','渡頭風晚葉飛頻，君去還吳我入秦。',32,'御定全唐詩/json/509.json','["渡頭風晚葉飛頻，君去還吳我入秦。", "雙淚別家猶未斷，不堪仍送故鄉人。"]'),
('yuding-65','秋夜長安病後作','顧非熊','唐','御定全唐诗','yuding','','[]','秋中帝裏經旬雨，晴後蟬聲更不聞。',32,'御定全唐詩/json/509.json','["秋中帝裏經旬雨，晴後蟬聲更不聞。", "牢落閒庭新病起，故鄉南去雁成群。"]'),
('yuding-66','題王使君片石','顧非熊','唐','御定全唐诗','yuding','','[]','勢似孤峰一片成，坐來疑有白雲生。',32,'御定全唐詩/json/509.json','["勢似孤峰一片成，坐來疑有白雲生。", "主人莫怪殷勤看，遠客長懷舊隱情。"]'),
('yuding-67','暮春早起','顧非熊','唐','御定全唐诗','yuding','','[]','柳梢暗露滴清晨，簾下偏驚獨起人。',32,'御定全唐詩/json/509.json','["柳梢暗露滴清晨，簾下偏驚獨起人。", "鶗鴂數聲花漸落，園林是處總殘春。"]'),
('yuding-68','途次懷歸','顧非熊','唐','御定全唐诗','yuding','','[]','隴頭禾偃乳烏飛，兀倚征鞍倍憶歸。',32,'御定全唐詩/json/509.json','["隴頭禾偃乳烏飛，兀倚征鞍倍憶歸。", "正值江南新釀熟，可容閑卻老萊衣。"]'),
('yuding-69','寄陸隱君','顧非熊','唐','御定全唐诗','yuding','','[]','相思迢遞隔重城，鳥散階前竹塢清。',32,'御定全唐詩/json/509.json','["相思迢遞隔重城，鳥散階前竹塢清。", "定擬秋涼過南崦，長松石上聽泉聲。"]'),
('yuding-70','寄吳山淨上人','顧非熊','唐','御定全唐诗','yuding','','[]','憶共蒲團話夜鐘，別來落葉閟行蹤。',32,'御定全唐詩/json/509.json','["憶共蒲團話夜鐘，別來落葉閟行蹤。", "遙知黛色秋常玩，住向靈岩第幾峰。"]'),
('yuding-71','送徐五綸南行過吳','顧非熊','唐','御定全唐诗','yuding','','[]','吳門東去路三千，到得閶門暫泊船。',32,'御定全唐詩/json/509.json','["吳門東去路三千，到得閶門暫泊船。", "老父出迎應倒屣，貧居江上信誰傳。"]'),
('yuding-0','游天臺山','張祜','唐','御定全唐诗','yuding','','[]','崔嵬海西鎮，靈跡傳萬古。群峰日來朝，累累孫侍祖。',360,'御定全唐詩/json/510.json','["崔嵬海西鎮，靈跡傳萬古。群峰日來朝，累累孫侍祖。", "三茅即拳石，二室猶塊土。傍洞窟神仙，中岩宅龍虎。", "名從幹取象，位與坤作輔。鸞鶴自相群，前人空若瞽。", "巉巉割秋碧，媧女徒巧補。視聽出塵埃，處高心漸苦。", "才登招手石，肘底笑天姥。仰看華蓋尖，赤日雲上午。", "奔雷撼深谷，下見山腳雨。回首望四明，矗若城一堵。", "昏晨邈千態，恐動非自主。控鵠大夢中，坐覺身栩栩。", "東溟子時月，卻孕元化母。彭蠡不盈杯，浙江微辨縷。", "石樑屹橫架，萬仞青壁豎。卻瞰赤城顛，勢來如刀弩。", "盤松國清道，九裏天莫睹。穹崇上攢三，突兀傍聳五。", "空崖絕凡路，癡立麋與麈。邈峻極天門，覷深窺地戶。", "金庭路非遠，徒步將欲舉。身樂道家流，惇儒若一矩。", "行尋白雲叟，禮象登峻宇。佛窟繞杉嵐，仙壇半榛莽。", "懸崖與飛瀑，險噴難足俯。海眼三井通，洞門雙闕拄。", "瓊台下昏側，手足前采乳。但造不死鄉，前勞何足數。"]'),
('yuding-1','送蜀客','張祜','唐','御定全唐诗','yuding','','[]','楚客去岷江，西南指天末。平生不達意，萬里船一發。',120,'御定全唐詩/json/510.json','["楚客去岷江，西南指天末。平生不達意，萬里船一發。", "行行三峽夜，十二峰頂月。哀猿別曾林，忽忽聲斷咽。", "嘉陵水初漲，岩嶺耗積雪。不妨高唐雲，卻藉宋玉說。", "峨眉遠凝黛，腳底穀洞穴。錦城晝氳氳，錦水春活活。", "成都滯遊地，酒客須醉殺。莫戀卓家壚，相如已屑屑。"]'),
('yuding-2','團扇郎','張祜','唐','御定全唐诗','yuding','','[]','白團扇，今來此去捐。願得入郎手，團圓郎眼前。',22,'御定全唐詩/json/510.json','["白團扇，今來此去捐。願得入郎手，團圓郎眼前。"]'),
('yuding-3','西江行','張祜','唐','御定全唐诗','yuding','','[]','日下西塞山，南來洞庭客。晴空一鳥渡，萬里秋江碧。',36,'御定全唐詩/json/510.json','["日下西塞山，南來洞庭客。晴空一鳥渡，萬里秋江碧。", "惆悵異鄉人，偶言空脈脈。"]'),
('yuding-4','溳川寺路','張祜','唐','御定全唐诗','yuding','','[]','日沉西澗陰，遠驅愁突兀。煙苔濕凝地，露竹光滴月。',36,'御定全唐詩/json/510.json','["日沉西澗陰，遠驅愁突兀。煙苔濕凝地，露竹光滴月。", "時見一僧來，腳邊雲勃勃。"]'),
('yuding-5','夜雨','張祜','唐','御定全唐诗','yuding','','[]','靄靄雲四黑，秋林響空堂。始從寒瓦中，淅瀝斷人腸。',36,'御定全唐詩/json/510.json','["靄靄雲四黑，秋林響空堂。始從寒瓦中，淅瀝斷人腸。", "愁腸方九回，寂寂夜未央。"]'),
('yuding-6','秋晚途中作','張祜','唐','御定全唐诗','yuding','','[]','落日馳車道，秋郊思不勝。水雲遙斷緒，山日半銜棱。',36,'御定全唐詩/json/510.json','["落日馳車道，秋郊思不勝。水雲遙斷緒，山日半銜棱。", "遠吠鄰村處，計想羨他能。"]'),
('yuding-7','拔蒲歌','張祜','唐','御定全唐诗','yuding','','[]','拔蒲來，領郎鏡湖邊。郎心在何處，莫趁新蓮去。',34,'御定全唐詩/json/510.json','["拔蒲來，領郎鏡湖邊。郎心在何處，莫趁新蓮去。", "拔得無心蒲，問郎看好無。"]'),
('yuding-8','車遙遙','張祜','唐','御定全唐诗','yuding','','[]','東方曨曨車軋軋，地色不分新去轍。閨門半掩窗半空，',48,'御定全唐詩/json/510.json','["東方曨曨車軋軋，地色不分新去轍。閨門半掩窗半空，", "碧川迢迢山宛宛，馬蹄在耳輪在眼。桑間女兒情不淺，"]'),
('yuding-9','捉搦歌','張祜','唐','御定全唐诗','yuding','','[]','門上關，牆上棘，窗中女子聲唧唧。洛陽大道徒自直。',46,'御定全唐詩/json/510.json','["門上關，牆上棘，窗中女子聲唧唧。洛陽大道徒自直。", "女子心在婆舍側，嗚嗚籠鳥觸四隅。養男男娶婦，"]'),
('yuding-10','雁門太守行','張祜','唐','御定全唐诗','yuding','','[]','城頭月沒霜如水，趚趚踏沙人似鬼。燈前拭淚試香裘，',48,'御定全唐詩/json/510.json','["城頭月沒霜如水，趚趚踏沙人似鬼。燈前拭淚試香裘，", "閨中年少妻莫哀，魚金虎竹天上來，雁門山邊骨成灰。"]'),
('yuding-11','思歸引','張祜','唐','御定全唐诗','yuding','','[]','重重作閨清旦鐍，兩耳深聲長不徹。深宮坐愁百年身，',40,'御定全唐詩/json/510.json','["重重作閨清旦鐍，兩耳深聲長不徹。深宮坐愁百年身，", "故鄉不歸誰共穴，石上作蒲蒲九節。"]'),
('yuding-12','司馬相如琴歌','張祜','唐','御定全唐诗','yuding','','[]','鳳兮鳳兮非無皇，山重水闊不可量。',32,'御定全唐詩/json/510.json','["鳳兮鳳兮非無皇，山重水闊不可量。", "梧桐結陰在朝陽，濯羽弱水鳴高翔。"]'),
('yuding-13','雉朝飛操','張祜','唐','御定全唐诗','yuding','','[]','朝陽隴東泛暖景，雙啄雙飛雙顧影。朱冠錦襦聊日整，',48,'御定全唐詩/json/510.json','["朝陽隴東泛暖景，雙啄雙飛雙顧影。朱冠錦襦聊日整，", "雄飛在草雌在田，衷腸結憤氣呵天。聖人在上心不偏，"]'),
('yuding-14','觀徐州李司空獵','張祜','唐','御定全唐诗','yuding','','[]','曉出郡城東，分圍淺草中。紅旗開向日，白馬驟迎風。',48,'御定全唐詩/json/510.json','["曉出郡城東，分圍淺草中。紅旗開向日，白馬驟迎風。", "背手抽金鏃，翻身控角弓。萬人齊指處，一雁落寒空。"]'),
('yuding-15','獵','張祜','唐','御定全唐诗','yuding','','[]','殘獵渭城東，蕭蕭西北風。雪花鷹背上，冰片馬蹄中。',48,'御定全唐詩/json/510.json','["殘獵渭城東，蕭蕭西北風。雪花鷹背上，冰片馬蹄中。", "臂掛捎荊兔，腰懸落箭鴻。歸來逞餘勇，兒子亂彎弓。"]'),
('yuding-16','鸚鵡','張祜','唐','御定全唐诗','yuding','','[]','棲棲南越鳥，色麗思沈淫。暮隔碧雲海，春依紅樹林。',48,'御定全唐詩/json/510.json','["棲棲南越鳥，色麗思沈淫。暮隔碧雲海，春依紅樹林。", "雕籠悲斂翅，畫閣豈關心。無事能言語，人聞怨恨深。"]'),
('yuding-17','再吟鸚鵡','張祜','唐','御定全唐诗','yuding','','[]','萬里去心違，奇毛覺自非。美人憐解語，凡鳥畏多機。',48,'御定全唐詩/json/510.json','["萬里去心違，奇毛覺自非。美人憐解語，凡鳥畏多機。", "未勝無丹嘴，何勞事綠衣。雕籠終不戀，會向故山歸。"]'),
('yuding-18','酬鄭模司直見寄','張祜','唐','御定全唐诗','yuding','','[]','故人滄海曲，聊複話平生。喜是狂奴態，羞為老婢聲。',48,'御定全唐詩/json/510.json','["故人滄海曲，聊複話平生。喜是狂奴態，羞為老婢聲。", "宦途終日薄，身事長年輕。猶賴書千卷，長隨一棹行。"]'),
('yuding-19','送蘇紹之歸嶺南','張祜','唐','御定全唐诗','yuding','','[]','孤舟越客吟，萬里曠離襟。夜月江流闊，春雲嶺路深。',48,'御定全唐詩/json/510.json','["孤舟越客吟，萬里曠離襟。夜月江流闊，春雲嶺路深。", "珠繁楊氏果，翠耀孔家禽。無複天南夢，相思空樹林。"]'),
('yuding-20','送沈下賢謫尉南康','張祜','唐','御定全唐诗','yuding','','[]','秋風江上草，先是客心摧。萬里故人去，一行新雁來。',48,'御定全唐詩/json/510.json','["秋風江上草，先是客心摧。萬里故人去，一行新雁來。", "山高雲緒斷，浦迥日波頹。莫怪南康遠，相思不可裁。"]'),
('yuding-21','送盧弘本浙東覲省','張祜','唐','御定全唐诗','yuding','','[]','東望故山高，秋歸值小舠。懷中陸績橘，江上伍員濤。',48,'御定全唐詩/json/510.json','["東望故山高，秋歸值小舠。懷中陸績橘，江上伍員濤。", "好去寧雞口，加餐及蟹螯。知君思無倦，為我續離騷。"]'),
('yuding-22','晚次荊溪館呈崔明府','張祜','唐','御定全唐诗','yuding','','[]','艤舟陽羨館，飛步繚疏楹。山暝水雲碧，月涼煙樹清。',48,'御定全唐詩/json/510.json','["艤舟陽羨館，飛步繚疏楹。山暝水雲碧，月涼煙樹清。", "長橋深漾影，遠櫓下搖聲。況是無三害，弦歌初政成。"]'),
('yuding-23','寄朗州徐員外','張祜','唐','御定全唐诗','yuding','','[]','江嶺昔飄蓬，人間值俊雄。關西今孔子，城北舊徐公。',48,'御定全唐詩/json/510.json','["江嶺昔飄蓬，人間值俊雄。關西今孔子，城北舊徐公。", "清夜遊何處，良辰此不同。傷心幾年事，一半在湖中。"]'),
('yuding-24','旅次上饒溪','張祜','唐','御定全唐诗','yuding','','[]','碧溪行幾折，凝棹宿汀沙。角斷孤城掩，樓深片月斜。',48,'御定全唐詩/json/510.json','["碧溪行幾折，凝棹宿汀沙。角斷孤城掩，樓深片月斜。", "夜橋昏水氣，秋竹靜霜華。更想曾題壁，凋零可歎嗟。"]'),
('yuding-25','送徐彥夫南遷','張祜','唐','御定全唐诗','yuding','','[]','萬里客南遷，孤城漲海邊。瘴雲秋不斷，陰火夜長然。',48,'御定全唐詩/json/510.json','["萬里客南遷，孤城漲海邊。瘴雲秋不斷，陰火夜長然。", "月上行虛市，風回望舶船。知君還自潔，更為酌貪泉。"]'),
('yuding-26','送韋整尉長沙','張祜','唐','御定全唐诗','yuding','','[]','遠遠長沙去，憐君利一官。風帆彭蠡疾，雲水洞庭寬。',48,'御定全唐詩/json/510.json','["遠遠長沙去，憐君利一官。風帆彭蠡疾，雲水洞庭寬。", "木客提蔬束，江烏接飯丸。莫言卑濕地，未必乏新歡。"]'),
('yuding-27','送外甥','張祜','唐','御定全唐诗','yuding','','[]','衰年生侄少，唯爾最關心。偶作魏舒別，聊為殷浩吟。',48,'御定全唐詩/json/510.json','["衰年生侄少，唯爾最關心。偶作魏舒別，聊為殷浩吟。", "白波舟不定，黃葉路難尋。自此尊中物，誰當更共斟。"]'),
('yuding-28','贈薛鼎臣侍禦','張祜','唐','御定全唐诗','yuding','','[]','一命前途遠，雙曹小邑閑。夜潮人到郭，春霧鳥啼山。',48,'御定全唐詩/json/510.json','["一命前途遠，雙曹小邑閑。夜潮人到郭，春霧鳥啼山。", "淺瀨橫沙堰，高岩峻石斑。不堪曾倚棹，猶複夢升攀。"]'),
('yuding-29','送曾黯遊夔州','張祜','唐','御定全唐诗','yuding','','[]','不遠夔州路，層波灩澦連。下來千里峽，入去一條天。',48,'御定全唐詩/json/510.json','["不遠夔州路，層波灩澦連。下來千里峽，入去一條天。", "樹色秋帆上，灘聲夜枕前。何堪正危側，百丈半山顛。"]'),
('yuding-30','送李長史歸涪州','張祜','唐','御定全唐诗','yuding','','[]','涪江江上客，歲晚卻還鄉。暮過高唐雨，秋經巫峽霜。',48,'御定全唐詩/json/510.json','["涪江江上客，歲晚卻還鄉。暮過高唐雨，秋經巫峽霜。", "急灘船失次，疊嶂樹無行。好為題新什，知君思不常。"]'),
('yuding-31','贈契衡上人','張祜','唐','御定全唐诗','yuding','','[]','小門開板閣，終日是逢迎。語笑人同坐，修持意別行。',48,'御定全唐詩/json/510.json','["小門開板閣，終日是逢迎。語笑人同坐，修持意別行。", "水花秋始發，風竹夏長清。一恨悽惶久，憐師記姓名。"]'),
('yuding-32','走筆贈許玖赴桂州命','張祜','唐','御定全唐诗','yuding','','[]','桂林真重德，蓮幕藉殊才。直氣自消瘴，遠心無暫灰。',48,'御定全唐詩/json/510.json','["桂林真重德，蓮幕藉殊才。直氣自消瘴，遠心無暫灰。", "劍棱叢石險，箭激亂流回。莫說雁不到，長江魚盡來。"]'),
('yuding-33','題上饒亭','張祜','唐','御定全唐诗','yuding','','[]','溪亭拂一琴，促軫坐披衿。夜月水南寺，秋風城外砧。',48,'御定全唐詩/json/510.json','["溪亭拂一琴，促軫坐披衿。夜月水南寺，秋風城外砧。", "早霜紅葉靜，新雨碧潭深。唯是壺中物，憂來且自斟。"]'),
('yuding-34','題僧壁','張祜','唐','御定全唐诗','yuding','','[]','出門無一事，忽忽到天涯。客地多逢酒，僧房卻厭花。',48,'御定全唐詩/json/510.json','["出門無一事，忽忽到天涯。客地多逢酒，僧房卻厭花。", "棋因王粲覆，鼓是禰衡撾。自喜疏成品，生前不怨嗟。"]'),
('yuding-35','寄盧載','張祜','唐','御定全唐诗','yuding','','[]','故人盧氏子，十載曠佳期。少見雙魚信，多聞八米詩。',48,'御定全唐詩/json/510.json','["故人盧氏子，十載曠佳期。少見雙魚信，多聞八米詩。", "侏儒他甚飽，款段爾應羸。忽謂今劉二，相逢不熟槌。"]'),
('yuding-36','送楊秀才游蜀','張祜','唐','御定全唐诗','yuding','','[]','鄂渚逢遊客，瞿塘上去船。峽深明月夜，江靜碧雲天。',48,'御定全唐詩/json/510.json','["鄂渚逢遊客，瞿塘上去船。峽深明月夜，江靜碧雲天。", "舊俗巴渝舞，新聲蜀國弦。不堪揮慘恨，一涕自潸然。"]'),
('yuding-37','送楊秀才往夔州','張祜','唐','御定全唐诗','yuding','','[]','鄂渚逢遊客，瞿塘上去船。江連萬里海，峽入一條天。',48,'御定全唐詩/json/510.json','["鄂渚逢遊客，瞿塘上去船。江連萬里海，峽入一條天。", "鳥影沉沙日，猿聲隔樹煙。新詩逢北使，為草幾巴箋。"]'),
('yuding-38','途中逢李道實游蔡州','張祜','唐','御定全唐诗','yuding','','[]','征馬漢江頭，逢君上蔡遊。野橋經亥市，山路過申州。',48,'御定全唐詩/json/510.json','["征馬漢江頭，逢君上蔡遊。野橋經亥市，山路過申州。", "僻地人行澀，荒林虎跡稠。殷勤話新守，生物賴諸侯。"]'),
('yuding-39','富陽道中送王正夫','張祜','唐','御定全唐诗','yuding','','[]','析析上荒原，霜林赤葉翻。孤帆天外出，遠戍日中昏。',48,'御定全唐詩/json/510.json','["析析上荒原，霜林赤葉翻。孤帆天外出，遠戍日中昏。", "摘橘防深刺，攀蘿畏斷根。何堪衰草色，一酌送王孫。"]'),
('yuding-40','送韋正字析貫赴制舉','張祜','唐','御定全唐诗','yuding','','[]','可愛漢文年，鴻恩蕩海壖。木雞方備德，金馬正求賢。',48,'御定全唐詩/json/510.json','["可愛漢文年，鴻恩蕩海壖。木雞方備德，金馬正求賢。", "大戰希遊刃，長途在著鞭。佇看晁董策，便向史中傳。"]'),
('yuding-41','贈貞固上人','張祜','唐','御定全唐诗','yuding','','[]','南國披僧籍，高標一道林。律儀精氈布，真行正吞針。',48,'御定全唐詩/json/510.json','["南國披僧籍，高標一道林。律儀精氈布，真行正吞針。", "掇火身潛起，焚香口旋吟。非論坐中社，余亦舊知音。"]'),
('yuding-42','題贈志凝上人','張祜','唐','御定全唐诗','yuding','','[]','悟色身無染，觀空事不生。道心長日笑，覺路幾年行。',48,'御定全唐詩/json/510.json','["悟色身無染，觀空事不生。道心長日笑，覺路幾年行。", "片月山林靜，孤雲海棹輕。願為塵外契，一就智珠明。"]'),
('yuding-43','送瓊貞發述懷','張祜','唐','御定全唐诗','yuding','','[]','送出南溪日，離情不忍看。漸遙猶顧首，帆去意難判。',48,'御定全唐詩/json/510.json','["送出南溪日，離情不忍看。漸遙猶顧首，帆去意難判。", "最恨臨行夜，相期幾百般。但能存歲節，終久得同歡。"]'),
('yuding-44','寄靈澈上人','張祜','唐','御定全唐诗','yuding','','[]','老僧何處寺，秋夢繞江濱。獨樹月中鶴，孤舟雲外人。',48,'御定全唐詩/json/510.json','["老僧何處寺，秋夢繞江濱。獨樹月中鶴，孤舟雲外人。", "榮華長指幻，衰病久觀身。應笑無成者，滄洲垂一輪。"]'),
('yuding-45','溪行寄京師故人道侶','張祜','唐','御定全唐诗','yuding','','[]','白日長多事，清溪偶獨尋。雲歸秋水闊，月出夜山深。',48,'御定全唐詩/json/510.json','["白日長多事，清溪偶獨尋。雲歸秋水闊，月出夜山深。", "坐想天涯去，行悲澤畔吟。東郊故人在，應笑未抽簪。"]'),
('yuding-46','贈僧雲棲','張祜','唐','御定全唐诗','yuding','','[]','麈尾與筇枝，幾年離石壇。梵餘林雪厚，棋罷岳鐘殘。',48,'御定全唐詩/json/510.json','["麈尾與筇枝，幾年離石壇。梵餘林雪厚，棋罷岳鐘殘。", "開卷喜先悟，漱瓶知早寒。衡陽寺前雁，今日到長安。"]'),
('yuding-47','送魏尚書赴鎮州行營','張祜','唐','御定全唐诗','yuding','','[]','河塞日駸駸，恩仇報盡深。伍員忠是節，陸績孝為心。',48,'御定全唐詩/json/510.json','["河塞日駸駸，恩仇報盡深。伍員忠是節，陸績孝為心。", "坐激書生憤，行歌壯士吟。慚非燕地客，不得受黃金。"]'),
('yuding-48','寄遷客','張祜','唐','御定全唐诗','yuding','','[]','萬里南遷客，辛勤嶺路遙。溪行防水弩，野店避山魈。',48,'御定全唐詩/json/510.json','["萬里南遷客，辛勤嶺路遙。溪行防水弩，野店避山魈。", "瘴海須求藥，貪泉莫舉瓢。但能堅志義，白日甚昭昭。"]'),
('yuding-49','題蘇小小墓','張祜','唐','御定全唐诗','yuding','','[]','漠漠窮塵地，蕭蕭古樹林。臉濃花自發，眉恨柳長深。',48,'御定全唐詩/json/510.json','["漠漠窮塵地，蕭蕭古樹林。臉濃花自發，眉恨柳長深。", "夜月人何待，春風鳥為吟。不知誰共穴，徒願結同心。"]'),
('yuding-50','江南作','張祜','唐','御定全唐诗','yuding','','[]','楚塞南行久，秦城北望遙。少年花已過，衰病柳先凋。',48,'御定全唐詩/json/510.json','["楚塞南行久，秦城北望遙。少年花已過，衰病柳先凋。", "客淚收回日，鄉心寄落潮。殷勤問春雁，何處是煙霄。"]'),
('yuding-51','題王右丞山水障二首','張祜','唐','御定全唐诗','yuding','','[]','精華在筆端，咫尺匠心難。日月中堂見，江湖滿座看。',96,'御定全唐詩/json/510.json','["精華在筆端，咫尺匠心難。日月中堂見，江湖滿座看。", "夜凝嵐氣濕，秋浸壁光寒。料得昔人意，平生詩思殘。", "右丞今已歿，遺畫世間稀。咫尺江湖盡，尋常鷗鳥飛。", "山光全在掌，雲氣欲生衣。以此常為玩，平生滄海機。"]'),
('yuding-52','將之衡陽道中作','張祜','唐','御定全唐诗','yuding','','[]','萬里南方去，扁舟泛自身。長年無愛物，深話少情人。',48,'御定全唐詩/json/510.json','["萬里南方去，扁舟泛自身。長年無愛物，深話少情人。", "醉臥襟長散，閒書字不真。衡陽路猶遠，獨與雁為賓。"]'),
('yuding-53','讀狄梁公傳','張祜','唐','御定全唐诗','yuding','','[]','失運廬陵厄，乘時武后尊。五丁扶造化，一柱正乾坤。',48,'御定全唐詩/json/510.json','["失運廬陵厄，乘時武后尊。五丁扶造化，一柱正乾坤。", "上保儲皇位，深然國老勳。聖朝雖百代，長合問王孫。"]'),
('yuding-54','題真娘墓','張祜','唐','御定全唐诗','yuding','','[]','佛地葬羅衣，孤魂此是歸。舞為蝴蝶夢，歌謝伯勞飛。',48,'御定全唐詩/json/510.json','["佛地葬羅衣，孤魂此是歸。舞為蝴蝶夢，歌謝伯勞飛。", "翠發朝雲在，青蛾夜月微。傷心一花落，無複怨春輝。"]'),
('yuding-55','洞庭南館','張祜','唐','御定全唐诗','yuding','','[]','一徑逗霜林，朱欄繞碧岑。地盤雲夢角，山鎮洞庭心。',48,'御定全唐詩/json/510.json','["一徑逗霜林，朱欄繞碧岑。地盤雲夢角，山鎮洞庭心。", "樹白看煙起，沙紅見日沉。還因此悲屈，惆悵又行吟。"]'),
('yuding-56','題贈仲儀上人院','張祜','唐','御定全唐诗','yuding','','[]','星霜幾朝寺，香火靜居人。黃葉不經意，青山無事身。',48,'御定全唐詩/json/510.json','["星霜幾朝寺，香火靜居人。黃葉不經意，青山無事身。", "拋生臺上日，結座履中塵。自說一時課，別來詩更新。"]'),
('yuding-57','題聖女廟','張祜','唐','御定全唐诗','yuding','','[]','古廟無人入，蒼皮澀老桐。蟻行蟬殼上，蛇竄雀巢中。',48,'御定全唐詩/json/510.json','["古廟無人入，蒼皮澀老桐。蟻行蟬殼上，蛇竄雀巢中。", "淺水孤舟泊，輕塵一座蒙。晚來雲雨去，荒草是殘風。"]'),
('yuding-58','題山水障子','張祜','唐','御定全唐诗','yuding','','[]','一見秋山色，方憐畫手稀。波濤連壁動，雲物下簷飛。',48,'御定全唐詩/json/510.json','["一見秋山色，方憐畫手稀。波濤連壁動，雲物下簷飛。", "嶺樹冬猶發，江帆暮不歸。端然是漁叟，相向日依依。"]'),
('yuding-59','詠風','張祜','唐','御定全唐诗','yuding','','[]','搖搖歌扇舉，悄悄舞衣輕。引笛秋臨塞，吹沙夜繞城。',48,'御定全唐詩/json/510.json','["搖搖歌扇舉，悄悄舞衣輕。引笛秋臨塞，吹沙夜繞城。", "向峰回雁影，出峽送猿聲。何似琴中奏，依依別帶情。"]'),
('yuding-60','奉和令狐相公送陳肱侍禦','張祜','唐','御定全唐诗','yuding','','[]','高館動離瑟，親賓聊歎稀。笑歌情不盡，歡待禮無違。',48,'御定全唐詩/json/510.json','["高館動離瑟，親賓聊歎稀。笑歌情不盡，歡待禮無違。", "清露府蓮結，碧雲皋鶴飛。還家與□惠，雨露豈殊歸。"]'),
('yuding-61','陪范宣城北樓夜宴','張祜','唐','御定全唐诗','yuding','','[]','華軒敞碧流，官妓擁諸侯。粉項高叢鬢，檀妝慢裹頭。',48,'御定全唐詩/json/510.json','["華軒敞碧流，官妓擁諸侯。粉項高叢鬢，檀妝慢裹頭。", "亞身摧蠟燭，斜眼送香球。何處偏堪恨，千回下客籌。"]'),
('yuding-62','憲宗皇帝挽歌詞','張祜','唐','御定全唐诗','yuding','','[]','嗚咽上攀龍，升平不易逢。武皇虛好道，文帝未登封。',48,'御定全唐詩/json/510.json','["嗚咽上攀龍，升平不易逢。武皇虛好道，文帝未登封。", "壽域無千載，泉門是九重。橋山非遠地，雲去莫疑峰。"]'),
('yuding-63','發蜀客','張祜','唐','御定全唐诗','yuding','','[]','風吹魯國人，飄蕩蜀江濱。濕地饒蛙黽，衰年足鬼神。',48,'御定全唐詩/json/510.json','["風吹魯國人，飄蕩蜀江濱。濕地饒蛙黽，衰年足鬼神。", "時清歸去路，日複病來身。千萬長堤柳，從他爛熳春。"]'),
('yuding-64','江城晚眺','張祜','唐','御定全唐诗','yuding','','[]','重檻構雲端，江城四鬱盤。河流出郭靜，山色對樓寒。',48,'御定全唐詩/json/510.json','["重檻構雲端，江城四鬱盤。河流出郭靜，山色對樓寒。", "浪草侵天白，霜林映日丹。悠然此江思，樹杪幾檣竿。"]'),
('yuding-65','題樟亭','張祜','唐','御定全唐诗','yuding','','[]','曉霽憑虛檻，雲山四望通。地盤江岸絕，天映海門空。',48,'御定全唐詩/json/510.json','["曉霽憑虛檻，雲山四望通。地盤江岸絕，天映海門空。", "樹色連秋靄，潮聲入夜風。年年此光景，催盡白頭翁。"]'),
('yuding-66','樂靜','張祜','唐','御定全唐诗','yuding','','[]','引手強篸巾，徐徐起病身。遠心群野鶴，閒話對村人。',48,'御定全唐詩/json/510.json','["引手強篸巾，徐徐起病身。遠心群野鶴，閒話對村人。", "發匣琴徽靜，開瓶酒味真。縱聞兵賦急，原憲本家貧。"]'),
('yuding-67','登廣武原','張祜','唐','御定全唐诗','yuding','','[]','廣武原西北，華夷此浩然。地盤山入海，河繞國連天。',48,'御定全唐詩/json/510.json','["廣武原西北，華夷此浩然。地盤山入海，河繞國連天。", "遠樹千門邑，高檣萬里船。鄉心日雲暮，猶在楚城邊。"]'),
('yuding-68','觀宋州田大夫打球','張祜','唐','御定全唐诗','yuding','','[]','白馬頓紅纓，梢球紫袖輕。曉冰蹄下裂，寒瓦杖頭鳴。',48,'御定全唐詩/json/510.json','["白馬頓紅纓，梢球紫袖輕。曉冰蹄下裂，寒瓦杖頭鳴。", "叉手膠粘去，分鬃線道絣。自言無戰伐，髀肉已曾生。"]'),
('yuding-69','題丹陽永泰寺練湖亭','張祜','唐','御定全唐诗','yuding','','[]','小檻俯澄鮮，龍宮浸浩然。孤光懸夜月，一片割秋天。',48,'御定全唐詩/json/510.json','["小檻俯澄鮮，龍宮浸浩然。孤光懸夜月，一片割秋天。", "淺派胤沙草，餘波漂岸船。聊當因畎澮，披拂坐潺湲。"]'),
('yuding-70','題程氏書齋','張祜','唐','御定全唐诗','yuding','','[]','僻巷難通馬，深園不藉籬。青蘿纏柏葉，紅粉墜蓮枝。',48,'御定全唐詩/json/510.json','["僻巷難通馬，深園不藉籬。青蘿纏柏葉，紅粉墜蓮枝。", "雨燕銜泥近，風魚咂網遲。緣君尋小阮，好是更題詩。"]'),
('yuding-71','毀浮圖年逢東林寺舊','張祜','唐','御定全唐诗','yuding','','[]','可惜東林寺，空門失所依。翻經謝靈運，畫壁陸探微。',48,'御定全唐詩/json/510.json','["可惜東林寺，空門失所依。翻經謝靈運，畫壁陸探微。", "隙地泉聲在，荒途馬跡稀。殷勤話僧輩，未敢保儒衣。"]'),
('yuding-72','貴池道中作','張祜','唐','御定全唐诗','yuding','','[]','羸驂驅野岸，山遠路盤盤。清露月華曉，碧江星影寒。',48,'御定全唐詩/json/510.json','["羸驂驅野岸，山遠路盤盤。清露月華曉，碧江星影寒。", "離群徒長泣，去國自加餐。霄漢寧無舊，相哀自語端。"]'),
('yuding-73','喜王子載話舊','張祜','唐','御定全唐诗','yuding','','[]','相逢青眼日，相歎白頭時。累話三朝事，重看一局棋。',48,'御定全唐詩/json/510.json','["相逢青眼日，相歎白頭時。累話三朝事，重看一局棋。", "歡娛非老大，成長是嬰兒。且盡尊中物，無煩更後期。"]'),
('yuding-74','秋日病中','張祜','唐','御定全唐诗','yuding','','[]','析析簷前竹，秋聲拂簟涼。病加陰已久，愁覺夜初長。',48,'御定全唐詩/json/510.json','["析析簷前竹，秋聲拂簟涼。病加陰已久，愁覺夜初長。", "坐拾車前子，行看肘後方。無端憂食忌，開鏡倍萎黃。"]'),
('yuding-75','訪許用晦','張祜','唐','御定全唐诗','yuding','','[]','遠郭日曛曛，停橈一訪君。小橋通野水，高樹入江雲。',48,'御定全唐詩/json/510.json','["遠郭日曛曛，停橈一訪君。小橋通野水，高樹入江雲。", "酒興曾無敵，詩情舊逸群。怪來音信少，五十我無聞。"]'),
('yuding-76','題海鹽南館','張祜','唐','御定全唐诗','yuding','','[]','故人營此地，台館尚依依。黑夜山魈語，黃昏海燕歸。',48,'御定全唐詩/json/510.json','["故人營此地，台館尚依依。黑夜山魈語，黃昏海燕歸。", "舊陰楊葉在，殘雨槿花稀。無複南亭賞，高簷紅燭輝。"]'),
('yuding-77','晚秋江上作','張祜','唐','御定全唐诗','yuding','','[]','萬里窮秋客，蕭條對落暉。煙霞山鳥散，風雨廟神歸。',48,'御定全唐詩/json/510.json','["萬里窮秋客，蕭條對落暉。煙霞山鳥散，風雨廟神歸。", "地遠蛩聲切，天長雁影稀。那堪正砧杵，幽思想寒衣。"]'),
('yuding-78','吳宮曲','張祜','唐','御定全唐诗','yuding','','[]','日下苑西宮，花飄香徑紅。玉釵斜白燕，羅帶弄青蟲。',48,'御定全唐詩/json/510.json','["日下苑西宮，花飄香徑紅。玉釵斜白燕，羅帶弄青蟲。", "皓齒初含雪，柔枝欲斷風。可憐傾國豔，誰信女為戎。"]'),
('yuding-79','賦昭君塚','張祜','唐','御定全唐诗','yuding','','[]','萬里關山塚，明妃舊死心。恨為秋色晚，愁結暮雲陰。',48,'御定全唐詩/json/510.json','["萬里關山塚，明妃舊死心。恨為秋色晚，愁結暮雲陰。", "夜切胡風起，天高漢月臨。已知無玉貌，何事送黃金。"]'),
('yuding-80','哭汴州陸大夫','張祜','唐','御定全唐诗','yuding','','[]','利劍太堅操，何妨拔一毛。冤深陸機霧，憤積伍員濤。',48,'御定全唐詩/json/510.json','["利劍太堅操，何妨拔一毛。冤深陸機霧，憤積伍員濤。", "直道非無驗，明時不錄勞。誰當青史上，卒為顯詞褒。"]'),
('yuding-81','晚夏歸別業','張祜','唐','御定全唐诗','yuding','','[]','古岸扁舟晚，荒園一徑微。鳥啼新果熟，花落故人稀。',48,'御定全唐詩/json/510.json','["古岸扁舟晚，荒園一徑微。鳥啼新果熟，花落故人稀。", "宿潤侵苔甃，斜陽照竹扉。相逢盡鄉老，無複話時機。"]'),
('yuding-82','公子行','張祜','唐','御定全唐诗','yuding','','[]','春色滿城池，杯盤著處移。鐙金斜雁子，鞍帕嫩鵝兒。',48,'御定全唐詩/json/510.json','["春色滿城池，杯盤著處移。鐙金斜雁子，鞍帕嫩鵝兒。", "買笑歌桃李，尋歌折柳枝。可憐明月夜，長是管弦隨。"]'),
('yuding-83','題曾氏園林','張祜','唐','御定全唐诗','yuding','','[]','十畝長堤宅，蕭疏半老槐。醉眠風卷簟，棋罷月移階。',48,'御定全唐詩/json/510.json','["十畝長堤宅，蕭疏半老槐。醉眠風卷簟，棋罷月移階。", "斫樹遺桑斧，澆花濕筍鞋。還將齊物論，終歲自安排。"]'),
('yuding-84','讀始興公傳','張祜','唐','御定全唐诗','yuding','','[]','歿世議方存，升平道幾論。詩情光日月，筆力動乾坤。',48,'御定全唐詩/json/510.json','["歿世議方存，升平道幾論。詩情光日月，筆力動乾坤。", "亂首光雄算，朝綱在典墳。明時封禪績，山下見丘門。"]'),
('yuding-85','中秋月','張祜','唐','御定全唐诗','yuding','','[]','碧落桂含姿，清秋是素期。一年逢好夜，萬里見明時。',48,'御定全唐詩/json/510.json','["碧落桂含姿，清秋是素期。一年逢好夜，萬里見明時。", "絕域行應久，高城下更遲。人間系情事，何處不相思。"]'),
('yuding-86','江西道中作三首','張祜','唐','御定全唐诗','yuding','','[]','日落江村遠，煙雲度幾重。問人孤驛路，驅馬亂山峰。',144,'御定全唐詩/json/510.json','["日落江村遠，煙雲度幾重。問人孤驛路，驅馬亂山峰。", "夜入霜林火，寒生水寺鐘。淒涼哭途意，行處又饑凶。", "西江江上月，遠遠照征衣。夜色草中網，秋聲林外機。", "渚田牛路熟，石岸客船稀。無複是鄉井，鷓鴣聊自飛。", "秋灘一望平，遠遠見山城。落日啼烏桕，空林露寄生。", "燒畬殘火色，蕩槳夜溪聲。況是會游處，桑田小變更。"]'),
('yuding-87','題常州水西館','張祜','唐','御定全唐诗','yuding','','[]','隙地叢筠植，修廊列堵環。樓臺疏占水，岡岸遠成山。',48,'御定全唐詩/json/510.json','["隙地叢筠植，修廊列堵環。樓臺疏占水，岡岸遠成山。", "盡日草深映，無風舟自閑。聊當俟芳夕，一泛芰荷間。"]'),
('yuding-88','題李瀆山居玉潭','張祜','唐','御定全唐诗','yuding','','[]','古樹千年色，蒼崖百尺陰。發寒泉氣靜，神駭玉光沉。',48,'御定全唐詩/json/510.json','["古樹千年色，蒼崖百尺陰。發寒泉氣靜，神駭玉光沉。", "上穴青冥小，中連碧海深。何當煙月下，一聽夜龍吟。"]'),
('yuding-89','題陸墉金沙洞居','張祜','唐','御定全唐诗','yuding','','[]','東溪泉一眼，歸臥愜高疏。決水金沙靜，梯雲石壁虛。',48,'御定全唐詩/json/510.json','["東溪泉一眼，歸臥愜高疏。決水金沙靜，梯雲石壁虛。", "細吟搔短髮，深話笑長裾。莫道遺名品，嘗聞入洛初。"]'),
('yuding-90','題陸敦禮山居伏牛潭','張祜','唐','御定全唐诗','yuding','','[]','伏牛真怪事，餘勝幾人諳。日彩沉青壁，煙容靜碧潭。',48,'御定全唐詩/json/510.json','["伏牛真怪事，餘勝幾人諳。日彩沉青壁，煙容靜碧潭。", "泛心何慮冷，漱齒詎忘甘。幸挈壺中物，期君正興酣。"]'),
('yuding-91','旅次石頭岸','張祜','唐','御定全唐诗','yuding','','[]','行行石頭岸，身事兩相違。舊國日邊遠，故人江上稀。',48,'御定全唐詩/json/510.json','["行行石頭岸，身事兩相違。舊國日邊遠，故人江上稀。", "水聲寒不盡，山色暮相依。惆悵未成語，數行鴉又飛。"]'),
('yuding-92','觀宋州於使君家樂琵琶','張祜','唐','御定全唐诗','yuding','','[]','歷歷四弦分，重來上界聞。玉盤飛夜雹，金磬入秋雲。',48,'御定全唐詩/json/510.json','["歷歷四弦分，重來上界聞。玉盤飛夜雹，金磬入秋雲。", "隴霧笳凝水，砂風雁咽群。不堪天塞恨，青塚是昭君。"]'),
('yuding-93','箏','張祜','唐','御定全唐诗','yuding','','[]','綽綽下雲煙，微收皓腕鮮。夜風生碧柱，春水咽紅弦。',48,'御定全唐詩/json/510.json','["綽綽下雲煙，微收皓腕鮮。夜風生碧柱，春水咽紅弦。", "翠佩輕猶觸，鶯枝澀未遷。芳音何更妙，清月共嬋娟。"]'),
('yuding-94','歌','張祜','唐','御定全唐诗','yuding','','[]','一夜列三清，聞歌曲阜城。雪飛紅燼影，珠貫碧雲聲。',48,'御定全唐詩/json/510.json','["一夜列三清，聞歌曲阜城。雪飛紅燼影，珠貫碧雲聲。", "皓齒嬌微發，青蛾怨自生。不知新弟子，誰解囀喉輕。"]'),
('yuding-95','笙','張祜','唐','御定全唐诗','yuding','','[]','董雙成一妙，歷歷韻風篁。清露鶴聲遠，碧雲仙吹長。',48,'御定全唐詩/json/510.json','["董雙成一妙，歷歷韻風篁。清露鶴聲遠，碧雲仙吹長。", "氣侵銀項濕，膏胤漆瓢香。曲罷不知處，巫山空夕陽。"]'),
('yuding-96','五弦','張祜','唐','御定全唐诗','yuding','','[]','小小月輪中，斜抽半袖紅。玉瓶秋滴水，珠箔夜懸風。',48,'御定全唐詩/json/510.json','["小小月輪中，斜抽半袖紅。玉瓶秋滴水，珠箔夜懸風。", "徵調侵弦乙，商聲過指攏。只愁才曲罷，雲雨去巴東。"]'),
('yuding-97','觱篥','張祜','唐','御定全唐诗','yuding','','[]','一管妙清商，纖紅玉指長。雪藤新換束，霞錦旋抽囊。',48,'御定全唐詩/json/510.json','["一管妙清商，纖紅玉指長。雪藤新換束，霞錦旋抽囊。", "並揭聲猶遠，深含曲未央。坐中知密顧，微笑是周郎。"]'),
('yuding-98','笛','張祜','唐','御定全唐诗','yuding','','[]','紫清人一管，吹在月堂中。雁起雪雲夕，龍吟煙水空。',48,'御定全唐詩/json/510.json','["紫清人一管，吹在月堂中。雁起雪雲夕，龍吟煙水空。", "虜塵深漢地，羌思切邊風。試弄陽春曲，西園桃已紅。"]'),
('yuding-99','舞','張祜','唐','御定全唐诗','yuding','','[]','荊台呈妙舞，雲雨半羅衣。嫋嫋腰疑折，褰褰袖欲飛。',48,'御定全唐詩/json/510.json','["荊台呈妙舞，雲雨半羅衣。嫋嫋腰疑折，褰褰袖欲飛。", "霧輕紅躑躅，風豔紫薔薇。強許傳新態，人間弟子稀。"]'),
('yuding-100','箜篌','張祜','唐','御定全唐诗','yuding','','[]','星漢夜牢牢，深簾調更高。亂流公莫度，沉骨嫗空嗥。',48,'御定全唐詩/json/510.json','["星漢夜牢牢，深簾調更高。亂流公莫度，沉骨嫗空嗥。", "向月輕輪甲，迎風重紉條。不堪聞別引，滄海恨波濤。"]'),
('yuding-101','簫','張祜','唐','御定全唐诗','yuding','','[]','清籟遠愔愔，秦樓夜思深。碧空人已去，滄海鳳難尋。',48,'御定全唐詩/json/510.json','["清籟遠愔愔，秦樓夜思深。碧空人已去，滄海鳳難尋。", "杳妙和雲絕，依微向水沉。還將九成意，高閣佇芳音。"]'),
('yuding-102','夕次桐廬','張祜','唐','御定全唐诗','yuding','','[]','百里清溪口，扁舟此去過。晚潮風勢急，寒葉雨聲多。',48,'御定全唐詩/json/510.json','["百里清溪口，扁舟此去過。晚潮風勢急，寒葉雨聲多。", "戍出山頭鼓，樵通竹裏歌。不堪無酒夜，回首夢煙波。"]'),
('yuding-103','入潼關','張祜','唐','御定全唐诗','yuding','','[]','都城三百里，雄險此回環。地勢遙尊嶽，河流側讓關。',48,'御定全唐詩/json/510.json','["都城三百里，雄險此回環。地勢遙尊嶽，河流側讓關。", "秦皇曾虎視，漢祖昔龍顏。何處梟凶輩，干戈自不閑。"]'),
('yuding-104','南宮歎亦述玄宗追恨太真妃事','張祜','唐','御定全唐诗','yuding','','[]','北陸冰初結，南宮漏更長。何勞卻睡草，不驗返魂香。',48,'御定全唐詩/json/510.json','["北陸冰初結，南宮漏更長。何勞卻睡草，不驗返魂香。", "月隱仙娥豔，風殘夢蝶揚。徒悲舊行跡，一夜玉階霜。"]'),
('yuding-105','題平望驛','張祜','唐','御定全唐诗','yuding','','[]','一派吳興水，西來此驛分。路遙經幾日，身去是孤雲。',48,'御定全唐詩/json/510.json','["一派吳興水，西來此驛分。路遙經幾日，身去是孤雲。", "雨氣朝忙蟻，雷聲夜聚蚊。何堪秋草色，到處重離群。"]'),
('yuding-106','隋宮懷古','張祜','唐','御定全唐诗','yuding','','[]','廢宮深苑路，煬帝此東行。往事餘山色，流年是水聲。',48,'御定全唐詩/json/510.json','["廢宮深苑路，煬帝此東行。往事餘山色，流年是水聲。", "古牆丹雘盡，深棟黑煤生。惆悵從今客，經過未了情。"]'),
('yuding-107','偶蘇求至話別','張祜','唐','御定全唐诗','yuding','','[]','幾年滄海別，萬里白頭吟。夜月江流闊，春雲嶺路深。',48,'御定全唐詩/json/510.json','["幾年滄海別，萬里白頭吟。夜月江流闊，春雲嶺路深。", "珠繁楊氏果，翠耀孔家禽。無複天南夢，相思空樹林。"]'),
('yuding-108','秋霽','張祜','唐','御定全唐诗','yuding','','[]','垂老歸休意，棲棲陋巷中。暗燈棋子落，殘語酒瓶空。',48,'御定全唐詩/json/510.json','["垂老歸休意，棲棲陋巷中。暗燈棋子落，殘語酒瓶空。", "滴冪侵簷露，虛疏入檻風。何妨一蟬嘒，自抱木蘭叢。"]'),
('yuding-109','詠史二首','張祜','唐','御定全唐诗','yuding','','[]','漢代非良計，西戎世世塵。無何求善馬，不算苦生民。',96,'御定全唐詩/json/510.json','["漢代非良計，西戎世世塵。無何求善馬，不算苦生民。", "外國讎虛結，中華憤莫伸。卻教為後恥，昭帝遠和親。", "留名魯連去，於世絕遺音。盡愛聊城下，寧知滄海深。", "偶然飛一箭，無事在千金。回望淩煙閣，何人是此心。"]'),
('yuding-110','洞房燕','張祜','唐','御定全唐诗','yuding','','[]','清曉洞房開，佳人喜燕來。乍疑釵上動，輕似掌中回。',48,'御定全唐詩/json/510.json','["清曉洞房開，佳人喜燕來。乍疑釵上動，輕似掌中回。", "暗語臨窗戶，深窺傍鏡臺。新妝正含思，莫拂畫梁埃。"]'),
('yuding-111','答僧贈柱杖','張祜','唐','御定全唐诗','yuding','','[]','千回掌上橫，珍重遠方情。客問何人與，閩僧寄一莖。',48,'御定全唐詩/json/510.json','["千回掌上橫，珍重遠方情。客問何人與，閩僧寄一莖。", "畫空疑未決，卓地計初成。幸以文堪采，扶持力不輕。"]'),
('yuding-112','鷺鷥','張祜','唐','御定全唐诗','yuding','','[]','深窺思不窮，揭趾淺沙中。一點山光淨，孤飛潭影空。',48,'御定全唐詩/json/510.json','["深窺思不窮，揭趾淺沙中。一點山光淨，孤飛潭影空。", "暗棲松葉露，雙下蓼花風。好是滄波侶，垂絲趣亦同。"]'),
('yuding-113','塞下','張祜','唐','御定全唐诗','yuding','','[]','萬里配長征，連年慣野營。入群來揀馬，拋伴去擒生。',48,'御定全唐詩/json/510.json','["萬里配長征，連年慣野營。入群來揀馬，拋伴去擒生。", "箭插雕翎闊，弓盤鵲角輕。閑看行近遠，西去受降城。"]'),
('yuding-114','憶雲陽宅','張祜','唐','御定全唐诗','yuding','','[]','一別雲陽宅，深愁度歲華。翠濃春檻柳，紅滿夜庭花。',48,'御定全唐詩/json/510.json','["一別雲陽宅，深愁度歲華。翠濃春檻柳，紅滿夜庭花。", "鳥影垂纖竹，魚行踐淺沙。聊當因寤寐，歸思浩無涯。"]'),
('yuding-115','題造微禪師院','張祜','唐','御定全唐诗','yuding','','[]','夜香聞偈後，岑寂掩雙扉。照竹燈和雪，穿雲月到衣。',48,'御定全唐詩/json/510.json','["夜香聞偈後，岑寂掩雙扉。照竹燈和雪，穿雲月到衣。", "草堂疏磬斷，江寺故人稀。唯憶江南雨，春風獨鳥歸。"]'),
('yuding-116','酬武蘊之，乙丑之歲始見華髮餘自悲遂成繼和','張祜','唐','御定全唐诗','yuding','','[]','賈生年尚少，華髮近相侵。不是流光促，因緣別恨深。',48,'御定全唐詩/json/510.json','["賈生年尚少，華髮近相侵。不是流光促，因緣別恨深。", "憐君成苦調，感我獨長吟。豈料清秋日，星星共映簪。"]'),
('yuding-117','題萬道人禪房','張祜','唐','御定全唐诗','yuding','','[]','何處鑿禪壁，西南江上峰。殘陽過遠水，落葉滿疏鐘。',48,'御定全唐詩/json/510.json','["何處鑿禪壁，西南江上峰。殘陽過遠水，落葉滿疏鐘。", "世事靜中去，道心塵外逢。欲知情不動，床下虎留蹤。"]'),
('yuding-118','病後訪山客','張祜','唐','御定全唐诗','yuding','','[]','久病倦衾枕，獨行來訪君。因逢歸馬客，共對出溪雲。',48,'御定全唐詩/json/510.json','["久病倦衾枕，獨行來訪君。因逢歸馬客，共對出溪雲。", "新月坐中見，暮蟬愁處聞。相歡貴無事，莫想路歧分。"]'),
('yuding-119','題松汀驛','張祜','唐','御定全唐诗','yuding','','[]','山色遠含空，蒼茫澤國東。海明先見日，江白迥聞風。',48,'御定全唐詩/json/510.json','["山色遠含空，蒼茫澤國東。海明先見日，江白迥聞風。", "鳥道高原去，人煙小徑通。那知舊遺逸，不在五湖中。"]'),
('yuding-120','處士隱居','張祜','唐','御定全唐诗','yuding','','[]','斜日半飛閣，高簾輕翳空。清香芙蓉水，碧冷琅玕風。',48,'御定全唐詩/json/510.json','["斜日半飛閣，高簾輕翳空。清香芙蓉水，碧冷琅玕風。", "絕岸派沿洑，修廊趾崇隆。唯當餌仙術，坐作朱顏翁。"]'),
('yuding-121','早春錢塘湖晚眺','張祜','唐','御定全唐诗','yuding','','[]','落日下林阪，撫襟睇前蹤。輕澌流回浦，殘雪明高峰。',48,'御定全唐詩/json/510.json','["落日下林阪，撫襟睇前蹤。輕澌流回浦，殘雪明高峰。", "仰視天宇曠，俯登雲樹重。聊當問真界，昨夜西巒鐘。"]'),
('yuding-122','濠州水館','張祜','唐','御定全唐诗','yuding','','[]','高閣去煩燠，客心遂安舒。清流中浴鳥，白石下游魚。',48,'御定全唐詩/json/510.json','["高閣去煩燠，客心遂安舒。清流中浴鳥，白石下游魚。", "秋樹色凋翠，夜橋聲嫋虛。南軒更何待，坐見玉蟾蜍。"]'),
('yuding-123','石頭城寺','張祜','唐','御定全唐诗','yuding','','[]','山勢抱煙光，重門突兀傍。連簷金像閣，半壁石龕廊。',48,'御定全唐詩/json/510.json','["山勢抱煙光，重門突兀傍。連簷金像閣，半壁石龕廊。", "碧樹叢高頂，清池占下方。徒悲宦遊意，盡日老僧房。"]'),
('yuding-124','傷遷客歿南中','張祜','唐','御定全唐诗','yuding','','[]','故人何處歿，謫宦極南天。遠地身狼狽，窮途事果然。',48,'御定全唐詩/json/510.json','["故人何處歿，謫宦極南天。遠地身狼狽，窮途事果然。", "白須才過海，丹旐卻歸船。腸斷相逢路，新來客又遷。"]'),
('yuding-125','烏夜啼','張祜','唐','御定全唐诗','yuding','','[]','忽忽南飛返，危絲共怨淒。暗霜移樹宿，殘夜繞枝啼。',48,'御定全唐詩/json/510.json','["忽忽南飛返，危絲共怨淒。暗霜移樹宿，殘夜繞枝啼。", "咽絕聲重敘，愔淫思乍迷。不妨還報喜，誤使玉顏低。"]'),
('yuding-126','題潤州金山寺','張祜','唐','御定全唐诗','yuding','','[]','一宿金山寺，超然離世群。僧歸夜船月，龍出曉堂雲。',48,'御定全唐詩/json/510.json','["一宿金山寺，超然離世群。僧歸夜船月，龍出曉堂雲。", "樹色中流見，鐘聲兩岸聞。翻思在朝市，終日醉醺醺。"]'),
('yuding-127','題潤州甘露寺','張祜','唐','御定全唐诗','yuding','','[]','千重構橫險，高步出塵埃。日月光先見，江山勢盡來。',48,'御定全唐詩/json/510.json','["千重構橫險，高步出塵埃。日月光先見，江山勢盡來。", "冷雲歸水石，清露滴樓臺。況是東溟上，平生意一開。"]'),
('yuding-128','題杭州孤山寺','張祜','唐','御定全唐诗','yuding','','[]','樓臺聳碧岑，一徑入湖心。不雨山長潤，無雲水自陰。',48,'御定全唐詩/json/510.json','["樓臺聳碧岑，一徑入湖心。不雨山長潤，無雲水自陰。", "斷橋荒蘚澀，空院落花深。猶憶西窗月，鐘聲在北林。"]'),
('yuding-129','題餘杭縣龍泉觀','張祜','唐','御定全唐诗','yuding','','[]','四回山一面，台殿已嵯峨。中路見山遠，上方行石多。',48,'御定全唐詩/json/510.json','["四回山一面，台殿已嵯峨。中路見山遠，上方行石多。", "天晴花氣漫，地暖鳥音和。徒漱葛仙井，此生其奈何。"]'),
('yuding-130','題徑山大覺禪師影堂','張祜','唐','御定全唐诗','yuding','','[]','超然彼岸人，一徑謝微塵。見相即非相，觀身豈是身。',48,'御定全唐詩/json/510.json','["超然彼岸人，一徑謝微塵。見相即非相，觀身豈是身。", "空門性未滅，舊裏化猶新。謾指堂中影，誰言影似真。"]'),
('yuding-131','題濠州鐘離寺','張祜','唐','御定全唐诗','yuding','','[]','遙遙東郭寺，數裏占原田。遠岫碧光合，長淮清派連。',48,'御定全唐詩/json/510.json','["遙遙東郭寺，數裏占原田。遠岫碧光合，長淮清派連。", "院藏歸鳥樹，鐘到落帆船。唯羨空門叟，棲心盡百年。"]'),
('yuding-132','秋夜宿靈隱寺師上人','張祜','唐','御定全唐诗','yuding','','[]','月色荒城外，江聲野寺中。貧知交道薄，老信釋門空。',48,'御定全唐詩/json/510.json','["月色荒城外，江聲野寺中。貧知交道薄，老信釋門空。", "露葉凋階蘚，風枝戛井桐。不妨無酒夜，閒話值生公。"]'),
('yuding-133','題蘇州靈岩寺','張祜','唐','御定全唐诗','yuding','','[]','碧海西陵岸，吳王此盛時。山行今佛寺，水見舊宮池。',48,'御定全唐詩/json/510.json','["碧海西陵岸，吳王此盛時。山行今佛寺，水見舊宮池。", "亡國人遺恨，空門事少悲。聊當值僧語，盡日把松枝。"]'),
('yuding-134','題蘇州楞伽寺','張祜','唐','御定全唐诗','yuding','','[]','樓臺山半腹，又此一經行。樹隔夫差苑，溪連勾踐城。',48,'御定全唐詩/json/510.json','["樓臺山半腹，又此一經行。樹隔夫差苑，溪連勾踐城。", "上坡松徑澀，深坐石池清。況是西峰頂，淒涼故國情。"]'),
('yuding-135','題蘇州思益寺','張祜','唐','御定全唐诗','yuding','','[]','四面山形斷，樓臺此迥臨。兩峰高崒屼，一水下淫滲。',48,'御定全唐詩/json/510.json','["四面山形斷，樓臺此迥臨。兩峰高崒屼，一水下淫滲。", "鑿石西龕小，穿松北塢深。會當來結社，長日為僧吟。"]'),
('yuding-136','題重居寺','張祜','唐','御定全唐诗','yuding','','[]','浮圖經近郭，長日羨僧閑。竹徑深開院，松門遠對山。',48,'御定全唐詩/json/510.json','["浮圖經近郭，長日羨僧閑。竹徑深開院，松門遠對山。", "重廊標板榜，高殿鎖金環。更問尋雷室，西行咫尺間。"]'),
('yuding-137','題善權寺','張祜','唐','御定全唐诗','yuding','','[]','碧峰南一寺，最勝是仙源。峻阪依岩壁，清泉泄洞門。',48,'御定全唐詩/json/510.json','["碧峰南一寺，最勝是仙源。峻阪依岩壁，清泉泄洞門。", "金函崇寶藏，玉樹閟靈根。寄謝香花叟，高蹤不可援。"]'),
('yuding-138','題南陵隱靜寺','張祜','唐','御定全唐诗','yuding','','[]','松徑上登攀，深行煙靄間。合流廚下水，對聳殿前山。',48,'御定全唐詩/json/510.json','["松徑上登攀，深行煙靄間。合流廚下水，對聳殿前山。", "潤壁鳥音迥，泉源僧步閑。更憐飛一錫，天外與雲還。"]'),
('yuding-139','題丘山寺','張祜','唐','御定全唐诗','yuding','','[]','幾代儒家業，何年佛寺碑。地平邊海處，江出上山時。',48,'御定全唐詩/json/510.json','["幾代儒家業，何年佛寺碑。地平邊海處，江出上山時。", "故國人長往，空門事可知。淒涼問禪客，身外即無為。"]'),
('yuding-140','題道光上人山院','張祜','唐','御定全唐诗','yuding','','[]','真僧上方界，山路正岩岩。地僻泉長冷，亭香草不凡。',48,'御定全唐詩/json/510.json','["真僧上方界，山路正岩岩。地僻泉長冷，亭香草不凡。", "火田生白菌，煙岫老青杉。盡日唯山水，當知律行嚴。"]'),
('yuding-141','贈廬山僧','張祜','唐','御定全唐诗','yuding','','[]','一室爐峰下，荒榛手自開。粉牌新薤葉，竹援小蔥台。',48,'御定全唐詩/json/510.json','["一室爐峰下，荒榛手自開。粉牌新薤葉，竹援小蔥台。", "樹黑雲歸去，山明日上來。便知心是佛，堅坐對寒灰。"]'),
('yuding-142','題惠山寺','張祜','唐','御定全唐诗','yuding','','[]','舊宅人何在，空門客自過。泉聲到池盡，山色上樓多。',48,'御定全唐詩/json/510.json','["舊宅人何在，空門客自過。泉聲到池盡，山色上樓多。", "小洞生斜竹，重階夾細莎。殷勤望城市，雲水暮鐘和。"]'),
('yuding-143','題虎丘寺','張祜','唐','御定全唐诗','yuding','','[]','輕棹駐回流，門登西虎丘。霧青山月曉，雲白海天秋。',48,'御定全唐詩/json/510.json','["輕棹駐回流，門登西虎丘。霧青山月曉，雲白海天秋。", "倚殿松株澀，欹庭石片幽。青蛾幾時墓，空色尚悠悠。"]'),
('yuding-144','題普賢寺','張祜','唐','御定全唐诗','yuding','','[]','何人知寺路，松竹暗春山。潭黑龍應在，巢空鶴未還。',48,'御定全唐詩/json/510.json','["何人知寺路，松竹暗春山。潭黑龍應在，巢空鶴未還。", "經年來客倦，半日與僧閑。更共嘗新茗，聞鐘笑語間。"]'),
('yuding-145','題虎丘東寺','張祜','唐','御定全唐诗','yuding','','[]','雲樹擁崔嵬，深行異俗埃。寺門山外入，石壁地中開。',48,'御定全唐詩/json/510.json','["雲樹擁崔嵬，深行異俗埃。寺門山外入，石壁地中開。", "仰砌池光動，登樓海氣來。傷心萬古意，金玉葬寒灰。"]'),
('yuding-146','題虎丘西寺','張祜','唐','御定全唐诗','yuding','','[]','囂塵楚城外，一寺枕通波。松色入門遠，岡形連院多。',48,'御定全唐詩/json/510.json','["囂塵楚城外，一寺枕通波。松色入門遠，岡形連院多。", "花時長到處，別路半經過。惆悵舊禪客，空房深薜蘿。"]'),
('yuding-147','題招隱寺','張祜','唐','御定全唐诗','yuding','','[]','千年戴顒宅，佛廟此崇修。古井人名在，清泉鹿跡幽。',48,'御定全唐詩/json/510.json','["千年戴顒宅，佛廟此崇修。古井人名在，清泉鹿跡幽。", "竹光寒閉院，山影夜藏樓。未得高僧旨，煙霞空暫遊。"]'),
('yuding-148','塞下曲','張祜','唐','御定全唐诗','yuding','','[]','二十逐嫖姚，分兵遠戍遼。雪迷經塞夜，冰壯渡河朝。',48,'御定全唐詩/json/510.json','["二十逐嫖姚，分兵遠戍遼。雪迷經塞夜，冰壯渡河朝。", "促放雕難下，生騎馬未調。小儒何足問，看取劍橫腰。"]'),
('yuding-149','宿淮陰水館','張祜','唐','御定全唐诗','yuding','','[]','積水自成陰，昏昏月映林。五更離浦棹，一夜隔淮砧。',48,'御定全唐詩/json/510.json','["積水自成陰，昏昏月映林。五更離浦棹，一夜隔淮砧。", "漂母鄉非遠，王孫道豈沉。不當無健嫗，誰肯效前心。"]'),
('yuding-150','題小松','張祜','唐','御定全唐诗','yuding','','[]','何處劚雲煙，新移此館前。碧姿塵不染，清影露長鮮。',48,'御定全唐詩/json/510.json','["何處劚雲煙，新移此館前。碧姿塵不染，清影露長鮮。", "聳地心才直，淩雲操未全。可悲人自老，何日是千年。"]'),
('yuding-151','夏日梅溪館寄龐舍人','張祜','唐','御定全唐诗','yuding','','[]','東陽賓禮重，高館望行期。埽簟因松葉，篸瓜使竹枝。',48,'御定全唐詩/json/510.json','["東陽賓禮重，高館望行期。埽簟因松葉，篸瓜使竹枝。", "捲簾聞鳥近，翻枕夢人遲。坐聽津橋說，今營太守碑。"]'),
('yuding-152','感河上兵','張祜','唐','御定全唐诗','yuding','','[]','一聞河塞上，非是欲權兵。首尾誠須畏，膏肓慎勿輕。',48,'御定全唐詩/json/510.json','["一聞河塞上，非是欲權兵。首尾誠須畏，膏肓慎勿輕。", "多門徒可入，盡室且思行。莫為無媒者，滄浪不濯纓。"]'),
('yuding-153','贈淮南將','張祜','唐','御定全唐诗','yuding','','[]','年少好風情，垂鞭眥睚行。帶金獅子小，裘錦麒麟獰。',48,'御定全唐詩/json/510.json','["年少好風情，垂鞭眥睚行。帶金獅子小，裘錦麒麟獰。", "揀匠裝銀鐙，堆錢買鈿箏。李陵雖效死，時論亦輕生。"]'),
('yuding-154','題惠昌上人','張祜','唐','御定全唐诗','yuding','','[]','半岩開一室，香穟細氛氳。石上漱秋水，月中行夏雲。',48,'御定全唐詩/json/510.json','["半岩開一室，香穟細氛氳。石上漱秋水，月中行夏雲。", "律持僧講疏，經誦梵書文。好是風廊下，遙遙掛褐裙。"]'),
('yuding-155','塞上曲','張祜','唐','御定全唐诗','yuding','','[]','邊風卷地時，日暮帳初移。磧迥三通角，山寒一點旗。',48,'御定全唐詩/json/510.json','["邊風卷地時，日暮帳初移。磧迥三通角，山寒一點旗。", "連收榻索馬，引滿射雕兒。莫道功勳細，將軍昔戍師。"]'),
('yuding-156','折楊柳','張祜','唐','御定全唐诗','yuding','','[]','紅粉青樓曙，垂楊仲月春。懷君重攀折，非妾妒腰身。',48,'御定全唐詩/json/510.json','["紅粉青樓曙，垂楊仲月春。懷君重攀折，非妾妒腰身。", "舞帶縈絲斷，嬌娥向葉嚬。橫吹凡幾曲，獨自最愁人。"]'),
('yuding-157','采桑','張祜','唐','御定全唐诗','yuding','','[]','自古多征戰，由來尚甲兵。長驅千里去，一舉兩番平。',48,'御定全唐詩/json/510.json','["自古多征戰，由來尚甲兵。長驅千里去，一舉兩番平。", "按劍從沙漠，歌謠滿帝京。寄言天下將，須立武功名。"]'),
('yuding-158','禪智寺','張祜','唐','御定全唐诗','yuding','','[]','寶殿依山嶮，臨虛勢若吞。畫簷齊木末，香砌壓雲根。',48,'御定全唐詩/json/510.json','["寶殿依山嶮，臨虛勢若吞。畫簷齊木末，香砌壓雲根。", "遠景窗中岫，孤煙竹裏村。憑高聊一望，鄉思隔吳門。"]'),
('yuding-159','寄題商洛王隱居','張祜','唐','御定全唐诗','yuding','','[]','近逢商洛口，知爾坐南塘。草閣平春水，柴門掩夕陽。',48,'御定全唐詩/json/510.json','["近逢商洛口，知爾坐南塘。草閣平春水，柴門掩夕陽。", "隨蜂收野蜜，尋麝采生香。更憶前年醉，松花滿石床。"]'),
('yuding-160','送客歸湘楚','張祜','唐','御定全唐诗','yuding','','[]','無辭一杯酒，昔日與君深。秋色換歸鬢，曙光生別心。',48,'御定全唐詩/json/510.json','["無辭一杯酒，昔日與君深。秋色換歸鬢，曙光生別心。", "桂花山廟冷，楓樹水樓陰。此路千餘裏，應勞楚客吟。"]'),
('yuding-161','登金山寺','張祜','唐','御定全唐诗','yuding','','[]','古今斯島絕，南北大江分。水闊吞滄海，亭高宿斷雲。',48,'御定全唐詩/json/510.json','["古今斯島絕，南北大江分。水闊吞滄海，亭高宿斷雲。", "返潮千澗落，啼鳥半空聞。皆是登臨處，歸航酒半醺。"]'),
('yuding-0','洛陽感寓','張祜','唐','御定全唐诗','yuding','','[]','擾擾都城曉四開，不關名利也塵埃。千門甲第身遙入，',40,'御定全唐詩/json/511.json','["擾擾都城曉四開，不關名利也塵埃。千門甲第身遙入，", "須知此事堪為鏡，莫遣黃金漫作堆。"]'),
('yuding-1','從軍行','張祜','唐','御定全唐诗','yuding','','[]','少年金紫就光輝，直指邊城虎翼飛。一卷旌收千騎虜，',40,'御定全唐詩/json/511.json','["少年金紫就光輝，直指邊城虎翼飛。一卷旌收千騎虜，", "白首漢廷刀筆吏，丈夫功業本相依。"]'),
('yuding-2','愛妾換馬','張祜','唐','御定全唐诗','yuding','','[]','一面妖桃千里蹄，嬌姿駿骨價應齊。乍牽玉勒辭金棧，',80,'御定全唐詩/json/511.json','["一面妖桃千里蹄，嬌姿駿骨價應齊。乍牽玉勒辭金棧，", "嬋娟躞蹀春風裏，揮手搖鞭楊柳堤。", "綺閣香銷華廄空，忍將行雨換追風。休憐柳葉雙眉翠，", "恩勞未盡情先盡，暗泣嘶風兩意同。"]'),
('yuding-3','病宮人','張祜','唐','御定全唐诗','yuding','','[]','佳人臥病動經秋，簾幕襤縿不掛鉤。四體強扶藤夾膝，',40,'御定全唐詩/json/511.json','["佳人臥病動經秋，簾幕襤縿不掛鉤。四體強扶藤夾膝，", "惆悵近來消瘦盡，淚珠時傍枕函流。"]'),
('yuding-4','觀杭州柘枝','張祜','唐','御定全唐诗','yuding','','[]','舞停歌罷鼓連催，軟骨仙蛾暫起來。紅罨畫衫纏腕出，',40,'御定全唐詩/json/511.json','["舞停歌罷鼓連催，軟骨仙蛾暫起來。紅罨畫衫纏腕出，", "看著遍頭香袖褶，粉屏香帕又重隈。"]'),
('yuding-5','周員外席上觀柘枝','張祜','唐','御定全唐诗','yuding','','[]','畫鼓拖環錦臂攘，小娥雙換舞衣裳。金絲蹙霧紅衫薄，',40,'御定全唐詩/json/511.json','["畫鼓拖環錦臂攘，小娥雙換舞衣裳。金絲蹙霧紅衫薄，", "一時欻腕招殘拍，斜斂輕身拜玉郎。"]'),
('yuding-6','觀楊瑗柘枝','張祜','唐','御定全唐诗','yuding','','[]','促疊蠻鼉引柘枝，捲簾虛帽帶交垂。紫羅衫宛蹲身處，',40,'御定全唐詩/json/511.json','["促疊蠻鼉引柘枝，捲簾虛帽帶交垂。紫羅衫宛蹲身處，", "看看舞罷輕雲起，卻赴襄王夢裏期。"]'),
('yuding-7','感王將軍柘枝妓歿','張祜','唐','御定全唐诗','yuding','','[]','寂寞春風舊柘枝，舞人休唱曲休吹。鴛鴦鈿帶拋何處，',40,'御定全唐詩/json/511.json','["寂寞春風舊柘枝，舞人休唱曲休吹。鴛鴦鈿帶拋何處，", "今來座上偏惆悵，曾是堂前教徹時。"]'),
('yuding-8','揚州法雲寺雙檜','張祜','唐','御定全唐诗','yuding','','[]','謝家雙植本圖榮，樹老人因地變更。朱頂鶴知深蓋偃，',40,'御定全唐詩/json/511.json','["謝家雙植本圖榮，樹老人因地變更。朱頂鶴知深蓋偃，", "縱使百年為上壽，綠陰終借暫時行。"]'),
('yuding-9','憶遊天臺寄道流','張祜','唐','御定全唐诗','yuding','','[]','憶昨天台到赤城，幾朝仙籟耳中生。雲龍出水風聲過，',40,'御定全唐詩/json/511.json','["憶昨天台到赤城，幾朝仙籟耳中生。雲龍出水風聲過，", "今來儘是人間夢，劉阮茫茫何處行。"]'),
('yuding-10','寄王尊師','張祜','唐','御定全唐诗','yuding','','[]','天臺南洞一靈仙，骨聳冰棱貌瑩然。曾對浦雲長昧齒，',40,'御定全唐詩/json/511.json','["天臺南洞一靈仙，骨聳冰棱貌瑩然。曾對浦雲長昧齒，", "猶憶夜深華蓋上，更無人處話丹田。"]'),
('yuding-11','公子行','張祜','唐','御定全唐诗','yuding','','[]','錦堂晝永繡簾垂，立卻花驄待出時。紅粉美人擎酒勸，',40,'御定全唐詩/json/511.json','["錦堂晝永繡簾垂，立卻花驄待出時。紅粉美人擎酒勸，", "近地獨遊三五騎，等閒行傍曲江池。"]'),
('yuding-12','寓懷寄蘇州劉郎中','張祜','唐','御定全唐诗','yuding','','[]','一聞周召佐明時，西望都門強策羸。天子好文才自薄，',40,'御定全唐詩/json/511.json','["一聞周召佐明時，西望都門強策羸。天子好文才自薄，", "唯是勝遊行未遍，欲離京國尚遲遲。"]'),
('yuding-13','和杜牧之齊山登高','張祜','唐','御定全唐诗','yuding','','[]','秋溪南岸菊霏霏，急管煩弦對落暉。紅葉樹深山徑斷，',40,'御定全唐詩/json/511.json','["秋溪南岸菊霏霏，急管煩弦對落暉。紅葉樹深山徑斷，", "流落正憐芳意在，砧聲徒促授寒衣。"]'),
('yuding-14','題於越亭','張祜','唐','御定全唐诗','yuding','','[]','扁舟亭下駐煙波，十五年遊重此過。洲觜露沙人渡淺，',40,'御定全唐詩/json/511.json','["扁舟亭下駐煙波，十五年遊重此過。洲觜露沙人渡淺，", "腸斷中秋正圓月，夜來誰唱異鄉歌。"]'),
('yuding-15','秋夜登潤州慈和寺上方','張祜','唐','御定全唐诗','yuding','','[]','清夜浮埃暫歇鄽，塔輪金照露華鮮。人行中路月生海，',40,'御定全唐詩/json/511.json','["清夜浮埃暫歇鄽，塔輪金照露華鮮。人行中路月生海，", "僧房閉盡下樓去，一半夢魂離世緣。"]'),
('yuding-16','寄獻蕭相公','張祜','唐','御定全唐诗','yuding','','[]','東去江幹是勝遊，鼎湖興望不堪愁。謝安近日違朝旨，',40,'御定全唐詩/json/511.json','["東去江幹是勝遊，鼎湖興望不堪愁。謝安近日違朝旨，", "分明此事無人見，白首相看未肯休。"]'),
('yuding-17','哭京兆龐尹','張祜','唐','御定全唐诗','yuding','','[]','揚子江頭昔共迷，一為京兆隔雲泥。故人昨日同時吊，',40,'御定全唐詩/json/511.json','["揚子江頭昔共迷，一為京兆隔雲泥。故人昨日同時吊，", "也知世路名堪貴，誰信莊周論物齊。"]'),
('yuding-18','送周尚書赴滑台','張祜','唐','御定全唐诗','yuding','','[]','楚謠襦袴整三年，喉舌新恩下九天。鼓角雄都分節鉞，',40,'御定全唐詩/json/511.json','["楚謠襦袴整三年，喉舌新恩下九天。鼓角雄都分節鉞，", "多病無由酬一顧，鄢陵千騎去翩翩。"]'),
('yuding-19','和杜使君九華樓見寄','張祜','唐','御定全唐诗','yuding','','[]','孤城高柳曉鳴鴉，風簾半鉤清露華。九峰聚翠宿危檻，',40,'御定全唐詩/json/511.json','["孤城高柳曉鳴鴉，風簾半鉤清露華。九峰聚翠宿危檻，", "杜陵歸去春應早，莫厭青山謝脁家。"]'),
('yuding-20','送人歸蜀','張祜','唐','御定全唐诗','yuding','','[]','錦城春色溯江源，三峽經過幾夜猿。紅樹兩厓開霽色，',40,'御定全唐詩/json/511.json','["錦城春色溯江源，三峽經過幾夜猿。紅樹兩厓開霽色，", "長怨相如留滯處，富家還憶卓王孫。"]'),
('yuding-21','酬答柳宗言秀才見贈','張祜','唐','御定全唐诗','yuding','','[]','南下天臺厭絕冥，五湖波上泛如萍。江鷗自戲為蹤跡，',40,'御定全唐詩/json/511.json','["南下天臺厭絕冥，五湖波上泛如萍。江鷗自戲為蹤跡，", "金門後俊徒相唁，且為人間寄茯苓。"]'),
('yuding-22','題杭州天竺寺','張祜','唐','御定全唐诗','yuding','','[]','西南山最勝，一界是諸天。上路穿岩竹，分流入寺泉。',72,'御定全唐詩/json/511.json','["西南山最勝，一界是諸天。上路穿岩竹，分流入寺泉。", "躡雲丹井畔，望月石橋邊。洞壑江聲遠，樓臺海氣連。", "塔明春嶺雪，鐘散暮松煙。何處去猶恨，更看峰頂蓮。"]'),
('yuding-23','題杭州靈隱寺','張祜','唐','御定全唐诗','yuding','','[]','峰巒開一掌，朱檻幾環延。佛地花分界，僧房竹引泉。',72,'御定全唐詩/json/511.json','["峰巒開一掌，朱檻幾環延。佛地花分界，僧房竹引泉。", "五更樓下月，十裏郭中煙。後塔聳亭後，前山橫閣前。", "溪沙涵水靜，澗石點苔鮮。好是呼猿久，西岩深響連。"]'),
('yuding-24','中秋夜杭州玩月','張祜','唐','御定全唐诗','yuding','','[]','萬古太陰精，中秋海上生。鬼愁緣辟照，人愛為高明。',96,'御定全唐詩/json/511.json','["萬古太陰精，中秋海上生。鬼愁緣辟照，人愛為高明。", "歷歷華星遠，霏霏薄暈縈。影流江不盡，輪曳穀無聲。", "似鏡當樓曉，如珠出浦盈。岸沙全借白，山木半含清。", "小檻迴圈看，長堤蹋陣行。殷勤未歸客，煙水夜來情。"]'),
('yuding-25','高閑上人','張祜','唐','御定全唐诗','yuding','','[]','座上辭安國，禪房戀沃州。道心黃葉老，詩思碧雲秋。',96,'御定全唐詩/json/511.json','["座上辭安國，禪房戀沃州。道心黃葉老，詩思碧雲秋。", "卷軸朝廷餞，書函內庫收。陶欣入社叟，生怯論經儔。", "日色屏初揭，風聲筆未休。長波溢海岸，大點出嵩丘。", "不絕羲之法，難窮智永流。殷勤一箋在，留著看銀鉤。"]'),
('yuding-26','題靈隱寺師一上人十韻','張祜','唐','御定全唐诗','yuding','','[]','八十空門子，深山土木骸。片衣閑自衲，單食老長齋。',120,'御定全唐詩/json/511.json','["八十空門子，深山土木骸。片衣閑自衲，單食老長齋。", "道性終能遣，人情少不乖。樔枸居上院，薜荔俯層階。", "洗缽前臨水，窺門外有柴。朗吟揮竹拂，高楫曳芒鞋。", "迸筍斜穿塢，飛泉下噴崖。種花忻土潤，撥石慮沙埋。", "舊往師招隱，初臨我詠懷。何當緣興玩，更為表新牌。"]'),
('yuding-27','投常州從兄中丞','張祜','唐','御定全唐诗','yuding','','[]','扁舟何所往，言入善人邦。舊愛鵬摶海，今聞虎渡江。',120,'御定全唐詩/json/511.json','["扁舟何所往，言入善人邦。舊愛鵬摶海，今聞虎渡江。", "士因為政樂，儒為說詩降。素履冰容靜，新詞玉潤樅。", "金魚聊解帶，畫鷁稍移樁。邀妓思逃席，留賓命倒缸。", "史材誰是伍，經術世無雙。廣廈當宏構，洪鐘並待撞。", "成龍須講邴，展驥莫先龐。應念宗中末，秋螢照一窗。"]'),
('yuding-28','送王昌涉侍禦','張祜','唐','御定全唐诗','yuding','','[]','十裏指東平，軍前首出征。諸侯青服舊，禦史紫衣榮。',96,'御定全唐詩/json/511.json','["十裏指東平，軍前首出征。諸侯青服舊，禦史紫衣榮。", "入陳梟心死，分圍虎力生。畫時安楚塞，刻日下齊城。", "號令朝移幕，偷蹤夜斫營。雲梯曾險上，地道慣深行。", "舉旆招降將，投戈趁敗兵。自慚居虜者，當此立功名。"]'),
('yuding-29','少年樂','張祜','唐','御定全唐诗','yuding','','[]','二十便封侯，名居第一流。綠鬟深小院，清管下高樓。',72,'御定全唐詩/json/511.json','["二十便封侯，名居第一流。綠鬟深小院，清管下高樓。", "醉把金船擲，閑敲玉鐙遊。帶盤紅鼴鼠，袍砑紫犀牛。", "錦袋歸調箭，羅鞋起撥球。眼前長貴盛，那信世間愁。"]'),
('yuding-30','華清宮和杜舍人','張祜','唐','御定全唐诗','yuding','','[]','五十年天子，離宮舊粉牆。登封時正泰，禦宇日初長。',360,'御定全唐詩/json/511.json','["五十年天子，離宮舊粉牆。登封時正泰，禦宇日初長。", "上位先名實，中興事憲章。舉戎輕甲胄，餘地取河湟。", "道帝玄元祖，儒封孔子王。因緣百司署，叢會一人湯。", "渭水波搖綠，秦山草半黃。馬頭開夜照，鷹眼利星芒。", "下箭朱弓滿，鳴鞭皓腕攘。畋思獲呂望，諫祇避周昌。", "兔跡貪前逐，梟心不早防。幾添鸚鵡勸，頻賜荔支嘗。", "月鎖千門靜，天高一笛涼。細音搖翠佩，輕步宛霓裳。", "禍亂根潛結，升平意遽忘。衣冠逃犬虜，鼙鼓動漁陽。", "外戚心殊迫，中途事可量。雪埋妃子貌，刃斷祿兒腸。", "近侍煙塵隔，前蹤輦路荒。益知迷寵佞，惟恨喪忠良。", "北闕尊明主，南宮遜上皇。禁清餘鳳吹，池冷映龍光。", "祝壽山猶在，流年水共傷。杜鵑魂厭蜀，蝴蝶夢悲莊。", "雀卵遺雕栱，蟲絲罥畫梁。紫苔侵壁潤，紅樹閉門芳。", "守吏齊鴛瓦，耕民得翠璫。歡康昔時樂，講武舊兵場。", "暮草深岩靄，幽花墜徑香。不堪垂白叟，行折禦溝楊。"]'),
('yuding-31','穆護砂','張祜','唐','御定全唐诗','yuding','','[]','玉管朝朝弄，清歌日日新。折花當驛路，寄與隴頭人。',24,'御定全唐詩/json/511.json','["玉管朝朝弄，清歌日日新。折花當驛路，寄與隴頭人。"]'),
('yuding-32','思歸樂二首','張祜','唐','御定全唐诗','yuding','','[]','晚日催弦管，春風入綺羅。杏花如有意，偏落舞衫多。',48,'御定全唐詩/json/511.json','["晚日催弦管，春風入綺羅。杏花如有意，偏落舞衫多。", "萬里春應盡，三江雁亦稀。連天漢水廣，孤客未言歸。"]'),
('yuding-33','金殿樂','張祜','唐','御定全唐诗','yuding','','[]','入夜秋砧動，千聲起四鄰。不緣樓上月，應為隴頭人。',24,'御定全唐詩/json/511.json','["入夜秋砧動，千聲起四鄰。不緣樓上月，應為隴頭人。"]'),
('yuding-34','牆頭花二首','張祜','唐','御定全唐诗','yuding','','[]','蟋蟀鳴洞房，梧桐落金井。為君裁舞衣，天寒剪刀冷。',48,'御定全唐詩/json/511.json','["蟋蟀鳴洞房，梧桐落金井。為君裁舞衣，天寒剪刀冷。", "妾有羅衣裳，秦王在時作。為舞春風多，秋來不堪著。"]'),
('yuding-35','胡渭州','張祜','唐','御定全唐诗','yuding','','[]','楊柳千尋色，桃花一苑芳。風吹入簾裏，唯有惹衣香。',24,'御定全唐詩/json/511.json','["楊柳千尋色，桃花一苑芳。風吹入簾裏，唯有惹衣香。"]'),
('yuding-36','白鼻騧','張祜','唐','御定全唐诗','yuding','','[]','為底胡姬酒，長來白鼻騧。摘蓮拋水上，郎意在浮花。',24,'御定全唐詩/json/511.json','["為底胡姬酒，長來白鼻騧。摘蓮拋水上，郎意在浮花。"]'),
('yuding-37','戎渾','張祜','唐','御定全唐诗','yuding','','[]','風勁角弓鳴，將軍獵渭城。草枯鷹眼疾，雪盡馬蹄輕。',24,'御定全唐詩/json/511.json','["風勁角弓鳴，將軍獵渭城。草枯鷹眼疾，雪盡馬蹄輕。"]'),
('yuding-38','楊下采桑','張祜','唐','御定全唐诗','yuding','','[]','飛絲惹綠塵，軟葉對孤輪。今朝入園去，物色強著人。',24,'御定全唐詩/json/511.json','["飛絲惹綠塵，軟葉對孤輪。今朝入園去，物色強著人。"]'),
('yuding-39','宮詞二首','張祜','唐','御定全唐诗','yuding','','[]','故國三千里，深宮二十年。一聲河滿子，雙淚落君前。',48,'御定全唐詩/json/511.json','["故國三千里，深宮二十年。一聲河滿子，雙淚落君前。", "自倚能歌日，先皇掌上憐。新聲何處唱，腸斷李延年。"]'),
('yuding-40','昭君怨二首','張祜','唐','御定全唐诗','yuding','','[]','萬里邊城遠，千山行路難。舉頭唯見日，何處是長安。',48,'御定全唐詩/json/511.json','["萬里邊城遠，千山行路難。舉頭唯見日，何處是長安。", "漢庭無大議，戎虜幾先和。莫羨傾城色，昭君恨最多。"]'),
('yuding-41','夕次竟陵','張祜','唐','御定全唐诗','yuding','','[]','南風吹五兩，日暮竟陵城。腸斷巴江月，夜蟬何處聲。',24,'御定全唐詩/json/511.json','["南風吹五兩，日暮竟陵城。腸斷巴江月，夜蟬何處聲。"]'),
('yuding-42','信州水亭','張祜','唐','御定全唐诗','yuding','','[]','南簷架短廊，沙路白茫茫。盡日不歸處，一庭梔子香。',24,'御定全唐詩/json/511.json','["南簷架短廊，沙路白茫茫。盡日不歸處，一庭梔子香。"]'),
('yuding-43','蘇小小歌三首','張祜','唐','御定全唐诗','yuding','','[]','車輪不可遮，馬足不可絆。長怨十字街，使郎心四散。',72,'御定全唐詩/json/511.json','["車輪不可遮，馬足不可絆。長怨十字街，使郎心四散。", "新人千里去，故人千里來。剪刀橫眼底，方覺淚難裁。", "登山不愁峻，涉海不愁深。中擘庭前棗，教郎見赤心。"]'),
('yuding-44','樹中草','張祜','唐','御定全唐诗','yuding','','[]','青青樹中草，托根非不危。草生樹卻死，榮枯君可知。',24,'御定全唐詩/json/511.json','["青青樹中草，托根非不危。草生樹卻死，榮枯君可知。"]'),
('yuding-45','七裏瀨漁家','張祜','唐','御定全唐诗','yuding','','[]','七裏垂釣叟，還傍釣台居。莫恨無名姓，嚴陵不賣魚。',24,'御定全唐詩/json/511.json','["七裏垂釣叟，還傍釣台居。莫恨無名姓，嚴陵不賣魚。"]'),
('yuding-46','讀曲歌五首','張祜','唐','御定全唐诗','yuding','','[]','窗中獨自起，簾外獨自行。愁見蜘蛛織，尋思直到明。',120,'御定全唐詩/json/511.json','["窗中獨自起，簾外獨自行。愁見蜘蛛織，尋思直到明。", "碓上米不舂，窗中絲罷絡。看渠駕去車，定是無四角。", "不見心相許，徒雲腳漫勤。摘荷空摘葉，是底採蓮人。", "窗外山魈立，知渠腳不多。三更機底下，摸著是誰梭。", "郎去摘黃瓜，郎來收赤棗。郎耕種麻地，今作西舍道。"]'),
('yuding-47','玉樹後庭花','張祜','唐','御定全唐诗','yuding','','[]','輕車何草草，獨唱後庭花。玉座誰為主，徒悲張麗華。',24,'御定全唐詩/json/511.json','["輕車何草草，獨唱後庭花。玉座誰為主，徒悲張麗華。"]'),
('yuding-48','莫愁樂','張祜','唐','御定全唐诗','yuding','','[]','儂居石城下，郎到石城遊。自郎石城出，長在石城頭。',24,'御定全唐詩/json/511.json','["儂居石城下，郎到石城遊。自郎石城出，長在石城頭。"]'),
('yuding-49','襄陽樂','張祜','唐','御定全唐诗','yuding','','[]','大堤花月夜，長江春水流。東風正上信，春夜特來遊。',24,'御定全唐詩/json/511.json','["大堤花月夜，長江春水流。東風正上信，春夜特來遊。"]'),
('yuding-50','自君之出矣','張祜','唐','御定全唐诗','yuding','','[]','自君之出矣，萬物看成古。千尋葶藶枝，急奈長長苦。',24,'御定全唐詩/json/511.json','["自君之出矣，萬物看成古。千尋葶藶枝，急奈長長苦。"]'),
('yuding-51','夢江南','張祜','唐','御定全唐诗','yuding','','[]','行吟洞庭句，不見洞庭人。盡日碧江夢，江南紅樹春。',24,'御定全唐詩/json/511.json','["行吟洞庭句，不見洞庭人。盡日碧江夢，江南紅樹春。"]'),
('yuding-52','將離嶽州留獻徐員外','張祜','唐','御定全唐诗','yuding','','[]','高齋長對酒，下客亦沾魚。不為江南去，還來郡北居。',24,'御定全唐詩/json/511.json','["高齋長對酒，下客亦沾魚。不為江南去，還來郡北居。"]'),
('yuding-53','題彭澤盧明府新樓','張祜','唐','御定全唐诗','yuding','','[]','碧落新樓迥，清池古樹閑。先賢盡為宰，空看縣南山。',24,'御定全唐詩/json/511.json','["碧落新樓迥，清池古樹閑。先賢盡為宰，空看縣南山。"]'),
('yuding-54','贈禪師','張祜','唐','御定全唐诗','yuding','','[]','坐見三生事，宗傳一衲來。已知無法說，心向定中灰。',24,'御定全唐詩/json/511.json','["坐見三生事，宗傳一衲來。已知無法說，心向定中灰。"]'),
('yuding-55','江南逢故人','張祜','唐','御定全唐诗','yuding','','[]','河洛多塵事，江山半舊遊。春風故人夜，又醉白蘋洲。',24,'御定全唐詩/json/511.json','["河洛多塵事，江山半舊遊。春風故人夜，又醉白蘋洲。"]'),
('yuding-56','松江懷古','張祜','唐','御定全唐诗','yuding','','[]','碧樹吳洲遠，青山震澤深。無人蹤范蠡，煙水暮沉沉。',24,'御定全唐詩/json/511.json','["碧樹吳洲遠，青山震澤深。無人蹤范蠡，煙水暮沉沉。"]'),
('yuding-57','書憤','張祜','唐','御定全唐诗','yuding','','[]','三十未封侯，顛狂遍九州。平生鏌鋣劍，不報小人讎。',24,'御定全唐詩/json/511.json','["三十未封侯，顛狂遍九州。平生鏌鋣劍，不報小人讎。"]'),
('yuding-58','題孟處士宅','張祜','唐','御定全唐诗','yuding','','[]','高才何必貴，下位不妨賢。孟簡雖持節，襄陽屬浩然。',24,'御定全唐詩/json/511.json','["高才何必貴，下位不妨賢。孟簡雖持節，襄陽屬浩然。"]'),
('yuding-59','首陽竹','張祜','唐','御定全唐诗','yuding','','[]','首陽山下路，孤竹節長存。為問無心草，如何庇本根。',24,'御定全唐詩/json/511.json','["首陽山下路，孤竹節長存。為問無心草，如何庇本根。"]'),
('yuding-60','題僧影堂','張祜','唐','御定全唐诗','yuding','','[]','寒葉墜清霜，空簾著燼香。生前既無事，何事更悲傷。',24,'御定全唐詩/json/511.json','["寒葉墜清霜，空簾著燼香。生前既無事，何事更悲傷。"]'),
('yuding-61','邊思','張祜','唐','御定全唐诗','yuding','','[]','蘇武節旌盡，李陵音信稀。花當隴上發，人向隴頭歸。',24,'御定全唐詩/json/511.json','["蘇武節旌盡，李陵音信稀。花當隴上發，人向隴頭歸。"]'),
('yuding-62','題弋陽館','張祜','唐','御定全唐诗','yuding','','[]','一葉飄然下弋陽，殘霞昏日樹蒼蒼。',32,'御定全唐詩/json/511.json','["一葉飄然下弋陽，殘霞昏日樹蒼蒼。", "吳溪漫淬幹將劍，卻是猿聲斷客腸。"]'),
('yuding-63','題秀師影堂','張祜','唐','御定全唐诗','yuding','','[]','陰陰古寺杉松下，記得長明一焰燈。',32,'御定全唐詩/json/511.json','["陰陰古寺杉松下，記得長明一焰燈。", "盡日看山人不會，影堂中是別來僧。"]'),
('yuding-64','贈李修源','張祜','唐','御定全唐诗','yuding','','[]','岳陽新尉曉衙參，卻是傍人意未甘。',32,'御定全唐詩/json/511.json','["岳陽新尉曉衙參，卻是傍人意未甘。", "昨夜與君思賈誼，長沙猶在洞庭南。"]'),
('yuding-65','瓜洲聞曉角','張祜','唐','御定全唐诗','yuding','','[]','寒耿稀星照碧霄，月樓吹角夜江遙。',32,'御定全唐詩/json/511.json','["寒耿稀星照碧霄，月樓吹角夜江遙。", "五更人起煙霜靜，一曲殘聲遍落潮。"]'),
('yuding-66','元日仗','張祜','唐','御定全唐诗','yuding','','[]','文武千官歲仗兵，萬方同軌奏升平。',32,'御定全唐詩/json/511.json','["文武千官歲仗兵，萬方同軌奏升平。", "上皇一禦含元殿，丹鳳門開白日明。"]'),
('yuding-67','連昌宮','張祜','唐','御定全唐诗','yuding','','[]','龍虎旌旗雨露飄，玉樓歌斷碧山遙。',32,'御定全唐詩/json/511.json','["龍虎旌旗雨露飄，玉樓歌斷碧山遙。", "玄宗上馬太真去，紅樹滿園香自銷。"]'),
('yuding-68','正月十五夜燈','張祜','唐','御定全唐诗','yuding','','[]','千門開鎖萬燈明，正月中旬動帝京。',32,'御定全唐詩/json/511.json','["千門開鎖萬燈明，正月中旬動帝京。", "三百內人連袖舞，一時天上著詞聲。"]'),
('yuding-69','上巳樂','張祜','唐','御定全唐诗','yuding','','[]','猩猩血彩系頭標，天上齊聲舉畫橈。',32,'御定全唐詩/json/511.json','["猩猩血彩系頭標，天上齊聲舉畫橈。", "卻是內人爭意切，六宮紅袖一時招。"]'),
('yuding-70','千秋樂','張祜','唐','御定全唐诗','yuding','','[]','八月平時花萼樓，萬方同樂奏千秋。',32,'御定全唐詩/json/511.json','["八月平時花萼樓，萬方同樂奏千秋。", "傾城人看長竿出，一伎初成趙解愁。"]'),
('yuding-71','春鶯囀','張祜','唐','御定全唐诗','yuding','','[]','興慶池南柳未開，太真先把一枝梅。',32,'御定全唐詩/json/511.json','["興慶池南柳未開，太真先把一枝梅。", "內人已唱春鶯囀，花下傞傞軟舞來。"]'),
('yuding-72','大酺樂二首','張祜','唐','御定全唐诗','yuding','','[]','車駕東來值太平，大酺三日洛陽城。',64,'御定全唐詩/json/511.json','["車駕東來值太平，大酺三日洛陽城。", "小兒一伎竿頭絕，天下傳呼萬歲聲。", "紫陌酺歸日欲斜，紅塵開路薛王家。", "雙鬟笑說樓前鼓，兩仗爭輪好落花。"]'),
('yuding-73','邠王小管','張祜','唐','御定全唐诗','yuding','','[]','虢國潛行韓國隨，宜春深院映花枝。',32,'御定全唐詩/json/511.json','["虢國潛行韓國隨，宜春深院映花枝。", "金輿遠幸無人見，偷把邠王小管吹。"]'),
('yuding-74','李謨笛','張祜','唐','御定全唐诗','yuding','','[]','平時東幸洛陽城，天樂宮中夜徹明。',32,'御定全唐詩/json/511.json','["平時東幸洛陽城，天樂宮中夜徹明。", "無奈李謨偷曲譜，酒樓吹笛是新聲。"]'),
('yuding-75','甯哥來','張祜','唐','御定全唐诗','yuding','','[]','日映宮城霧半開，太真簾下畏人猜。',32,'御定全唐詩/json/511.json','["日映宮城霧半開，太真簾下畏人猜。", "黃翻綽指向西樹，不信甯哥回馬來。"]'),
('yuding-76','丁巳年仲冬月江上作','張祜','唐','御定全唐诗','yuding','','[]','南來驅馬渡江濆，消息前年此月聞。',32,'御定全唐詩/json/511.json','["南來驅馬渡江濆，消息前年此月聞。", "唯是賈生先慟哭，不堪天意重陰雲。"]'),
('yuding-77','鄴中懷古','張祜','唐','御定全唐诗','yuding','','[]','鄴中城下漳河水，日夜東流莫記春。',32,'御定全唐詩/json/511.json','["鄴中城下漳河水，日夜東流莫記春。", "腸斷宮中望陵處，不堪臺上也無人。"]'),
('yuding-78','讀池州杜員外杜秋娘詩','張祜','唐','御定全唐诗','yuding','','[]','年少多情杜牧之，風流仍作杜秋詩。',32,'御定全唐詩/json/511.json','["年少多情杜牧之，風流仍作杜秋詩。", "可知不是長門閉，也得相如第一詞。"]'),
('yuding-79','杭州開元寺牡丹','張祜','唐','御定全唐诗','yuding','','[]','濃豔初開小藥欄，人人惆悵出長安。',32,'御定全唐詩/json/511.json','["濃豔初開小藥欄，人人惆悵出長安。", "風流卻是錢塘寺，不踏紅塵見牡丹。"]'),
('yuding-80','招徐宗偃畫松石','張祜','唐','御定全唐诗','yuding','','[]','咫尺雲山便出塵，我生長日自因循。',32,'御定全唐詩/json/511.json','["咫尺雲山便出塵，我生長日自因循。", "憑君畫取江南勝，留向東齋伴老身。"]'),
('yuding-81','平陰夏日作','張祜','唐','御定全唐诗','yuding','','[]','西來漸覺細塵紅，擾擾舟車路向東。',32,'御定全唐詩/json/511.json','["西來漸覺細塵紅，擾擾舟車路向東。", "可惜夏天明月夜，土山前面障南風。"]'),
('yuding-82','贈處士','張祜','唐','御定全唐诗','yuding','','[]','小徑上山山甚小，每憐僧院笑僧禪。',32,'御定全唐詩/json/511.json','["小徑上山山甚小，每憐僧院笑僧禪。", "人間莫道無難事，二十年來已是玄。"]'),
('yuding-83','邠娘羯鼓','張祜','唐','御定全唐诗','yuding','','[]','新教邠娘羯鼓成，大酺初日最先呈。',32,'御定全唐詩/json/511.json','["新教邠娘羯鼓成，大酺初日最先呈。", "冬兒指向貞貞說，一曲幹鳴兩杖輕。"]');
